// Load preferred UI language (RiceMap24 UI only). Kitchen content is not translated.
try{
  const savedLang = localStorage.getItem('ricemap24_lang');
  if(savedLang && copy[savedLang]) state.lang = savedLang;
}catch(_e){}


function t(key){
  const dict = copy[state.lang];
  const val = key.split('.').reduce((acc,k)=>acc?.[k], dict);
  if(val !== undefined && val !== null) return val;
  // Fallback to English if the selected language is missing a key.
  const en = copy.en;
  const valEn = key.split('.').reduce((acc,k)=>acc?.[k], en);
  return valEn ?? key;
}


