function authT(key){
  const lang = authCopy[state.lang] ? state.lang : 'en';
  return (authCopy[lang] && authCopy[lang][key]) || authCopy.en[key] || key;
}

function assetUrl(p){
  if (!p) return '';
  // Normalize to a single leading slash: "assets/x.jpg" -> "/assets/x.jpg", "/assets/x.jpg" -> "/assets/x.jpg"
  return p.startsWith('/') ? p : '/' + p;
}

// Some early demo seeds referenced an asset that no longer exists (assets/hero_maria.jpg).
// To avoid "missing image" in Explore + dashboard previews, normalize to a real default.
function isDemoListing(listing){
  if(!listing || typeof listing !== 'object') return false;
  if(!!listing.is_demo || String(listing.listing_type || '').trim().toLowerCase() === 'demo') return true;
  const slug = String(listing.slug || '').trim().toLowerCase();
  return ['marias-filipino-kusina','linh-viet-kitchen','noks-thai-corner'].includes(slug);
}

function safeHeroPath(p, listing=null){
  const s = (p || '').trim();
  // Empty means the kitchen has not uploaded a photo yet. Do not show demo/test images.
  if(!s) return '';
  // Real kitchens must never display bundled demo/test assets.
  if(!isDemoListing(listing) && isDemoAssetPath(s)) return '';
  // Only old demo rows that explicitly reference the removed Maria asset get mapped to a real demo image.
  if(isDemoListing(listing) && s.includes('hero_maria.jpg')) return 'assets/hero_fusion.jpg';
  return s;
}

function noPhotoLabel(){
  return state.lang === 'no' ? 'Ingen bilde lagt til ennå' : 'No photo added yet';
}

function imagePlaceholder(className){
  return el('div', { class: `${className || ''} noPhotoPlaceholder`.trim() }, [
    el('span', {}, [noPhotoLabel()])
  ]);
}

function signatureImagePath(listing){
  const direct = (listing?.signature_image || '').trim();
  if(direct && (isDemoListing(listing) || !isDemoAssetPath(direct))) return direct;
  const menu = Array.isArray(listing?.menu) ? listing.menu : [];
  for(const item of menu){
    if(!item || typeof item !== 'object') continue;
    const tags = Array.isArray(item.tags) ? item.tags : (item.tags ? [item.tags] : []);
    const isSignature = tags.some(t => String(t || '').trim().toLowerCase() === 'signature');
    const image = String(item.image || '').trim();
    if(isSignature && image && (isDemoListing(listing) || !isDemoAssetPath(image))) return image;
  }
  for(const item of menu){
    if(!item || typeof item !== 'object') continue;
    const image = String(item.image || '').trim();
    if(image && (isDemoListing(listing) || !isDemoAssetPath(image))) return image;
  }
  return '';
}

function isDemoAssetPath(p){
  const s = String(p || '').trim().replace(/^\//, '').toLowerCase();
  if (!s.startsWith('assets/')) return false;
  return /(^|\/)hero_|(^|\/)dish_|hero_fusion|dish_adobo|filipino|thai|viet|barkada|lumpia/.test(s);
}

function stripDemoImagesFromListingPayload(obj){
  if (!obj || typeof obj !== 'object') return obj;
  ['hero_image','signature_image','signature_photo','image','photo'].forEach((key)=>{
    if (isDemoAssetPath(obj[key])) obj[key] = '';
  });
  const menu = Array.isArray(obj.menu) ? obj.menu : [];
  menu.forEach((item)=>{
    if (!item || typeof item !== 'object') return;
    ['image','photo','img','hero_image'].forEach((key)=>{ if (isDemoAssetPath(item[key])) item[key] = ''; });
  });
  return obj;
}

function fetchWithTimeout(path, options={}, timeoutMs=8000){
  const controller = new AbortController();
  const t = setTimeout(()=>controller.abort(), timeoutMs);
  return fetch(path, { ...options, signal: controller.signal }).finally(()=>clearTimeout(t));
}

async function apiGet(path, opts={}){
  const timeoutMs = opts.timeoutMs || 8000;
  const res = await fetchWithTimeout(path, { headers: { 'Accept':'application/json' }, credentials:'include' }, timeoutMs);
  if(!res.ok) throw new Error(await res.text());
  return await res.json();
}


function adminKeyParam(){
  const key = String(state.admin.key || '').trim();
  return key ? ('?key=' + encodeURIComponent(key)) : '';
}
function adminAmpParam(){
  const key = String(state.admin.key || '').trim();
  return key ? ('&key=' + encodeURIComponent(key)) : '';
}
function adminUrl(path){
  const key = String(state.admin.key || '').trim();
  if(!key) return path;
  return path + (path.includes('?') ? '&' : '?') + 'key=' + encodeURIComponent(key);
}
async function adminCheckAuth(){
  try{
    const data = await apiGet('/api/auth/me');
    state.admin.authenticated = !!data.authenticated;
    state.admin.authUser = data.user || null;
    state.admin.loginError = '';
  }catch(e){
    state.admin.authenticated = false;
    state.admin.authUser = null;
  }
  try{
    const bs = await apiGet(adminUrl('/api/auth/bootstrap-status'));
    state.admin.bootstrapStatus = bs || null;
    state.admin.bootstrapChecked = true;
  }catch(e){
    state.admin.bootstrapStatus = null;
    state.admin.bootstrapChecked = true;
  }
  state.admin.authChecked = true;
  render();
}
function adminCanCreateLocalAdmin(){
  const bs = state.admin.bootstrapStatus || {};
  if (bs.production) return false;
  if (bs.can_create_first_admin) return true;
  if (bs.can_create_with_legacy) return true;
  return false;
}
function adminCanResetLocalAdmin(){
  const bs = state.admin.bootstrapStatus || {};
  return !!bs && !bs.production;
}
function adminBootstrapHint(){
  const bs = state.admin.bootstrapStatus || {};
  const no = state.lang === 'no';
  if (!state.admin.bootstrapChecked) return no ? 'Sjekker admin-oppsett…' : 'Checking admin setup…';
  if (bs.production) return no ? 'Produksjon: admin-brukere må opprettes kontrollert på server, ikke fra offentlig login-skjerm.' : 'Production: admin users must be created through a controlled server-side process, not from the public login screen.';
  if (bs.can_create_first_admin) return no ? 'Ingen lokal admin-bruker finnes i denne databasen. Opprett første lokale admin her.' : 'No local admin user exists in this database. Create the first local admin here.';
  if (bs.has_admin) return no ? 'Lokal admin-bruker finnes allerede. Bruk Logg inn. Hvis gammel admin ikke virker i staging, kan du nullstille lokal admin under.' : 'A local admin user already exists. Use Log in. If the old staging admin no longer works, reset the local admin below.';
  return no ? 'Logg inn med admin-bruker.' : 'Log in with an admin user.';
}
async function adminLogin(){
  const email = String(state.admin.loginEmail || '').trim();
  const password = String(state.admin.loginPassword || '');
  if(!email || !password){ state.admin.loginError = state.lang==='no'?'Skriv e-post og passord.':'Enter email and password.'; render(); return; }
  state.admin.loginBusy = true; state.admin.loginError=''; render();
  try{
    const data = await apiJson('POST', '/api/auth/login', { email, password });
    state.admin.authenticated = true;
    state.admin.authUser = data.user || null;
    state.admin.loginPassword = '';
    state.admin.authChecked = true;
    await adminRefreshFromLogin();
  }catch(e){
    state.admin.authenticated = false;
    state.admin.authUser = null;
    state.admin.loginError = e?.message || String(e);
  }finally{
    state.admin.loginBusy = false; render();
  }
}
async function adminLogout(){
  await logoutCurrentSession('/admin');
}
async function adminCreateLocalAdmin(){
  const email = String(state.admin.loginEmail || '').trim();
  const password = String(state.admin.loginPassword || '');
  if(!email || !password){ state.admin.loginError = state.lang==='no'?'Skriv e-post og passord først.':'Enter email and password first.'; render(); return; }
  state.admin.createAdminBusy = true; state.admin.loginError=''; render();
  try{
    await apiJson('POST', '/api/auth/dev-create-admin' + adminKeyParam(), { email, password, display_name:'Admin' });
    await adminLogin();
  }catch(e){
    state.admin.loginError = e?.message || String(e);
  }finally{
    state.admin.createAdminBusy = false; render();
  }
}

async function adminResetLocalAdmin(){
  const email = String(state.admin.loginEmail || '').trim();
  const password = String(state.admin.loginPassword || '');
  if(!email || !password){ state.admin.loginError = state.lang==='no'?'Skriv ny admin-e-post og passord først.':'Enter the new admin email and password first.'; render(); return; }
  const c = prompt(state.lang==='no' ? 'Skriv RESET for å nullstille lokal/staging admin. Dette sletter ikke kjøkken.' : 'Type RESET to reset local/staging admin. This does not delete kitchens.');
  if(String(c || '').trim().toUpperCase() !== 'RESET') return;
  state.admin.createAdminBusy = true; state.admin.loginError=''; render();
  try{
    await apiJson('POST', '/api/auth/dev-reset-admin', { email, password, display_name:'Admin', confirm:'RESET' });
    state.admin.loginError = state.lang==='no' ? 'Admin er nullstilt. Logger inn…' : 'Admin has been reset. Logging in…';
    await adminLogin();
  }catch(e){
    state.admin.loginError = e?.message || String(e);
  }finally{
    state.admin.createAdminBusy = false; render();
  }
}

async function adminRefreshFromLogin(){
  if (typeof window.__rm24AdminRefresh === 'function') return await window.__rm24AdminRefresh();
}

async function apiJson(method, url, body, opts={}){
  const timeoutMs = opts.timeoutMs || 15000;
  const res = await fetchWithTimeout(url, {
    method,
    headers: { 'Content-Type':'application/json' },
    credentials:'include',
    body: method==='GET' ? undefined : JSON.stringify(body || {})
  }, timeoutMs);
  if (!res.ok){
    // Prefer JSON error bodies, but fall back to plain text. Include status so
    // staging errors are actionable instead of only showing "Request failed".
    let msg = `Request failed (${res.status})`;
    try{
      const j = await res.json();
      msg = j.detail || JSON.stringify(j) || msg;
    }catch(e){
      try{ msg = (await res.text()) || msg; }catch(e2){}
    }
    throw new Error(msg);
  }
  try{ return await res.json(); }catch(e){ return {}; }
}




function applyMasterclassPlanMatrix(items, plan){
  const normalized = normalizePlan(plan || 'basic');
  if (normalized === 'growth' || normalized === 'pro') return items || [];
  const basicOpen = new Set(['01-A','01-D']);
  const businessOpen = new Set(['01-A','01-B','01-C','01-D','01-E','01-F']);
  const allowed = normalized === 'business' ? businessOpen : basicOpen;
  return (items || []).map((it)=>{
    const code = String(it?.code || '').toUpperCase().trim();
    const canOpen = allowed.has(code);
    return { ...it, locked: !canOpen, teaser: canOpen ? (it.teaser || '') : '' };
  });
}

// --- Owner: Masterclass -----------------------------------------------------

async function loadOwnerMasterclass(ownerToken, force=false){
  if (!ownerToken) return;
  if (state.masterclass.loaded && !force) return;
  state.masterclass.loading = true;
  state.masterclass.error = '';
  render();
  try{
    const tok = encodeURIComponent(String(ownerToken));
    const res = await apiJson('GET', `/api/owner/${tok}/masterclass`);
    state.masterclass.plan = res.plan || 'basic';
    state.masterclass.items = applyMasterclassPlanMatrix(res.items || [], state.masterclass.plan);
    state.masterclass.counts = res.counts || null;
    state.masterclass.current = res.current_masterclass || null;
    state.masterclass.subscriptionMonth = res.subscription_month || null;
    state.masterclass.loaded = true;
    state.masterclass.loading = false;
    const current = state.masterclass.selectedId;
    const items = state.masterclass.items || [];
    const firstOpen = items.find(x=>!x.locked);
    const firstAny = items[0] || null;
    state.masterclass.selectedId = (current && items.find(x=>x.id===current)) ? current : ((firstOpen || firstAny || {}).id || null);
    if (state.masterclass.selectedId){
      loadOwnerMasterclassDetail(ownerToken, state.masterclass.selectedId);
    } else {
      state.masterclass.selected = null;
      render();
    }
  }catch(err){
    state.masterclass.loading = false;
    state.masterclass.error = err?.message || String(err);
    render();
  }
}

async function loadOwnerMasterclassDetail(ownerToken, itemId){
  if (!ownerToken || !itemId) return;
  const item = (state.masterclass.items || []).find(x=>x.id===itemId);
  state.masterclass.selectedId = itemId;
  state.masterclass.detailError = '';
  if (item && item.locked){
    state.masterclass.selected = { locked:true, ...item };
    render();
    return;
  }
  state.masterclass.loadingDetail = true;
  render();
  try{
    const tok = encodeURIComponent(String(ownerToken));
    const res = await apiJson('GET', `/api/owner/${tok}/masterclass/${encodeURIComponent(itemId)}`);
    state.masterclass.selected = { locked:false, ...(item||{}), ...(res||{}) };
    state.masterclass.loadingDetail = false;
    render();
  }catch(err){
    state.masterclass.loadingDetail = false;
    state.masterclass.detailError = err?.message || String(err);
    state.masterclass.selected = { locked:true, ...(item||{}) };
    render();
  }
}

function _fmtUnlockDate(s){
  if (!s) return '';
  const d = new Date(String(s).replace(' ', 'T'));
  if (isNaN(d.getTime())) return '';
  try{
    return new Intl.DateTimeFormat(state.lang==='no' ? 'nb-NO' : 'en-GB', { day:'numeric', month:'long', year:'numeric' }).format(d);
  }catch(_e){ return d.toISOString().slice(0,10); }
}

