function _filterRecipes(items, q){
  const s = String(q||'').trim().toLowerCase();
  if (!s) return items || [];
  return (items||[]).filter(it=>{
    const hay = `${it.title||''} ${it.teaser||''} ${(it.tags && JSON.stringify(it.tags))||''}`.toLowerCase();
    return hay.includes(s);
  });
}

function _recipeCategory(it){
  const t = String(((it && it.tags && (it.tags.type || it.tags.role)) || '')).toLowerCase();
  const id = String(it && it.id || '').toLowerCase();
  const title = String(it && (it.title||it.id) || '').toLowerCase();

  // Trust backend classification first.
  if (t.includes('dessert')) return 'desserts';
  if (t.includes('drink')) return 'drinks';
  if (t.includes('baguette') || t.includes('wrap') || t.includes('handheld')) return 'handhelds';
  if (t === 'side' || t.includes('side')) return 'sides';
  if (t.includes('main')) return 'mains';

  // Fallback heuristics (very conservative to avoid wrong menu placement)
  if (id.includes('hor-mok') || title.includes('hor mok')) return 'mains';
  if (/(^|\b)(baguette|sandwich|banh\s*-\s*mi|sub|wrap|panini)(\b|$)/.test(title) || id.includes('baguette')) return 'handhelds';
  if (/(^|\b)(iced\s+tea|thai\s+tea|coffee|latte|juice|lemonade|smoothie|shake|boba|soda)(\b|$)/.test(title)) return 'drinks';
  if (/(^|\b)(mochi|pudding|ice\s*cream|gelato|cake|brownie|cookie|custard|tiramisu|dessert)(\b|$)/.test(title)) return 'desserts';
  if (id.includes('sideorder') || /(^|\b)(side\s*order|sideorder|spring\s*roll|lumpia|dumpling|wonton|bao|fries|salad|pickles|slaw|dip)(\b|$)/.test(title)) return 'sides';
  return 'mains';
}

function _filterRecipesByCat(items, cat){
  const c = String(cat||'all').toLowerCase();
  if (!c || c === 'all') return items || [];
  return (items || []).filter(it => _recipeCategory(it) === c);
}


function openRecipeModal(ownerToken, recipeId){
  const isNO = state.lang==='no';
  const overlay = el('div', { class:'overlay', onclick:(e)=>{ if(e.target===overlay) overlay.remove(); } }, [
    el('div', { class:'modal modal-wide' }, [
      el('div', { class:'modal-head' }, [
        el('div', { class:'modal-title' }, [isNO ? 'RiceMap24 Oppskriftskort' : 'RiceMap24 Recipe Card']),
        el('button', { class:'x', onclick: ()=>overlay.remove() }, ['✕'])
      ]),
      el('div', { class:'modal-body' }, [
        el('div', { class:'muted small' }, [isNO ? 'Laster …' : 'Loading …'])
      ])
    ])
  ]);
  document.body.appendChild(overlay);

  (async()=>{
    try{
      const res = await apiJson('GET', `/api/owner/${encodeURIComponent(String(ownerToken))}/recipes/${encodeURIComponent(recipeId)}`);
      const modal = overlay.querySelector('.modal-body');
      if (!modal) return;
      modal.innerHTML = '';

      const title = el('h2', { class:'h2', style:'margin-top:0' }, [res.title || recipeId]);

      let tab = 'recipe';
      const body = el('div', { class:'md' }, []);
      const tabs = el('div', { class:'tabRow recipeDetailTabs', style:'margin:10px 0' }, []);
      const canUseStrategy = !!res.show_strategy;

      function tabBtn(key, label, opts={}){
        const disabled = !!opts.disabled;
        return el('button', {
          class:'tabBtn'+(tab===key?' active':'')+(disabled?' disabled locked':''),
          disabled,
          title: disabled ? (isNO?'Tilgjengelig i Growth og Pro':'Available in Growth and Pro') : '',
          onclick:(e)=>{
            e.preventDefault();
            if (disabled) return;
            tab=key;
            paint();
          }
        }, [label]);
      }

      const relatedCard = (it)=> el('div',{class:'recipeMini'+(it.locked?' locked':''), onclick:()=>{ if(!it.locked) openRecipeModal(ownerToken, it.id); }},[
        el('div',{class:'recipeMiniT'},[it.title||it.id]),
        it.teaser ? el('div',{class:'muted small'},[String(it.teaser).slice(0,110)]) : null,
        it.locked ? el('div',{class:'pill smallPill'},[isNO?'Låst':'Locked']) : null
      ].filter(Boolean));

      function paint(){
        tabs.innerHTML='';
        tabs.appendChild(tabBtn('recipe', isNO?'Oppskrift':'Recipe'));
        tabs.appendChild(tabBtn('strategy', canUseStrategy ? (isNO?'Strategi':'Strategy') : (isNO?'Strategi låst':'Strategy locked'), { disabled: !canUseStrategy }));
        tabs.appendChild(tabBtn('related', isNO?'Kombinasjoner':'Combos'));

        body.innerHTML = '';
        if (tab==='recipe'){
          // Recipe content (HTML from server)
          const recipeWrap = el('div', { class:'md' }, []);
          recipeWrap.innerHTML = res.html?.recipe || '';
          body.appendChild(recipeWrap);

          // --- Supplies & packaging shortcut (shown inside the recipe card) ---
          const country = String(state.currentListing?.country || 'NO').toUpperCase();
          const dlToken = (state.currentListing && state.currentListing.preview_token) ? state.currentListing.preview_token : ownerToken;

          function inferDishParam(){
            const tags = res.tags || {};
            const raw = String(tags.dish_type || tags.dish || tags.category || '').toLowerCase();
            const titleLow = String(res.title || '').toLowerCase();
            const s = raw || titleLow;
            if (/(baguette|sandwich|wrap)/.test(s)) return 'baguettes';
            if (/(soup|pho|ramen)/.test(s)) return 'soups';
            if (/(curry|rice\s*bowl|rice bowl|bowl)/.test(s)) return 'rice';
            if (/(dessert|pastry|cake|cookie|brownie)/.test(s)) return 'desserts';
            if (/(drink|coffee|tea|smoothie|lemonade)/.test(s)) return 'drinks';
            return '';
          }

          const dishParam = inferDishParam();
          const amazonUrl = `/r/amazon?country=${encodeURIComponent(country)}&t=${encodeURIComponent(dlToken)}&page=recipe${dishParam?`&dish=${encodeURIComponent(dishParam)}`:''}`;

          const packCard = el('div', { class:'card', style:'margin-top:14px' }, [
            el('div', { class:'h3', style:'margin:0 0 6px' }, ['Supplies & packaging']),
            el('div', { class:'muted small', style:'margin-bottom:10px' }, ['Quick shortcut for packaging items (Amazon small orders).']),
            el('div', { class:'row', style:'gap:10px; flex-wrap:wrap' }, [
              button('Open Amazon shortcuts', { variant:'primary', onclick: ()=>{ window.open(amazonUrl, '_blank'); } }),
              button('Open Supplies tab', { variant:'outline', onclick: ()=>{
                // Switch the owner dashboard tab behind the modal
                if (!state.preview) state.preview = { tabs:{} };
                if (!state.preview.tabs) state.preview.tabs = {};
                state.preview.tabs[dlToken] = 'tools';
                state.preview.toolsTabs[dlToken] = 'supplies';
                overlay.remove();
                render();
              } })
            ])
          ]);
          body.appendChild(packCard);
        }else if (tab==='strategy'){
          if (!canUseStrategy){
            body.appendChild(el('div',{class:'lockNote'},[isNO
              ? 'Strategidelen er låst på Business. Oppgrader til Growth eller Pro for strategi, add-ons og kampanjeforslag.'
              : 'Strategy is locked on Business. Upgrade to Growth or Pro for strategy, add-ons and campaign ideas.'
            ]));
            return;
          }
          const box = el('div',{class:'md'},[]);
          box.innerHTML = res.html?.strategy || '';
          body.appendChild(box);
        }else{
          const rel = res.related || {};
          const addons = (rel.addons||[]).slice(0,4);
          const generic = (rel.generic_addons||[]).slice(0,6);
          const similar = (rel.similar||[]).slice(0,6);
          const allItemsById = new Map((state.recipes.items||[]).map(x=>[x.id,x]));
          const aCards = addons.map(x=> relatedCard({...(allItemsById.get(x.id)||{}), ...x }));
          const sCards = similar.map(x=> relatedCard({...(allItemsById.get(x.id)||{}), ...x }));
          body.appendChild(el('h3',{},[isNO?'Anbefalte add-ons':'Recommended add-ons']));
          if (aCards.length){
            body.appendChild(el('div',{class:'recipeGrid'}, aCards));
          }else if (!generic.length){
            body.appendChild(el('div',{class:'muted'},[isNO?'Ingen forslag ennå.':'No suggestions yet.']));
          }

          if (generic.length){
            body.appendChild(el('div',{class:'teaser', style:'margin-top:10px'},[
              el('div',{class:'muted small', style:'margin-bottom:8px'},[isNO?'Ekstra forslag (ikke koblet til oppskrifter):':'Suggested extras (not linked to recipes):']),
              el('ul',{}, generic.map(t=>el('li',{},[t])))
            ]));
          }
          body.appendChild(el('h3',{style:'margin-top:14px'},[isNO?'Lignende retter':'Similar recipes']));
          body.appendChild(el('div',{class:'recipeGrid'}, sCards.length? sCards : [el('div',{class:'muted'},[isNO?'Ingen forslag ennå.':'No suggestions yet.'])]));
        }
      }

      modal.appendChild(title);
      modal.appendChild(tabs);
      modal.appendChild(body);
      paint();

    }catch(err){
      const modal = overlay.querySelector('.modal-body');
      if (!modal) return;
      modal.innerHTML = '';
      modal.appendChild(el('div',{class:'lockNote'},[isNO?'Låst. Oppgrader for å åpne denne oppskriften.':'Locked. Upgrade to open this recipe.']));
    }
  })();
}



function doSearch(){
  // If empty, still load (shows all), but keep the UX consistent
  loadListings({ scroll:true, indicate:true });
}

function el(tag, attrs={}, children=[]){
  const n = document.createElement(tag);
  for (const [k,v] of Object.entries(attrs)){
    if (k === 'class') n.className = v;
    else if (k === 'html') n.innerHTML = v;
    else if (k === 'value') {
      // Keep form controls visually in sync after re-render.
      // setAttribute('value', ...) is not enough for <select>; the property must be set.
      try { n.value = String(v); } catch(_) {}
      n.setAttribute('value', String(v));
    }
    else if (k.startsWith('on') && typeof v === 'function') n.addEventListener(k.slice(2).toLowerCase(), v);
    else if (v === null || v === undefined) {
      // skip
    } else if (typeof v === 'boolean') {
      // Boolean attributes must be set as properties (not "false"/"true" strings).
      // If false, ensure attribute is removed.
      try { n[k] = !!v; } catch(_){}
      if (v) n.setAttribute(k, '');
      else n.removeAttribute(k);
    } else {
      n.setAttribute(k, v);
    }
  }
  for (const c of (children||[])){
    if (c === null || c === undefined) continue;
    if (typeof c === 'string') n.appendChild(document.createTextNode(c));
    else n.appendChild(c);
  }
  if (Object.prototype.hasOwnProperty.call(attrs, 'value')) {
    try { n.value = String(attrs.value); } catch(_) {}
  }
  return n;
}

function escapeHtml(s){
  return String(s==null?'':s)
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;')
    .replace(/'/g,'&#039;');
}

function link(href, text){
  return el('a', { href, class:'link', onclick: (e)=>{ e.preventDefault(); navigate(href); }}, [text]);
}

function button(text, opts={}){
  const clsBase = opts.variant === 'ghost' ? 'btn btn-ghost'
    : opts.variant === 'outline' ? 'btn btn-outline'
    : 'btn';
  const extra = (opts.className || '').trim();
  const cls = extra ? `${clsBase} ${extra}` : clsBase;
  const attrs = { class: cls, type:'button', onclick: opts.onclick };
  if (opts.disabled) attrs.disabled = true;
  return el('button', attrs, [text]);
}

function chip(text, active=false, onclick=null){
  const cls = active ? 'chip chip-active' : 'chip';
  return el('button', { class: cls, type:'button', onclick }, [text]);
}

function badge(text){
  const label = String(text || '');
  const normalized = label.toLowerCase().trim();
  let cls = 'badge';
  if (normalized === 'premium') cls += ' premium';
  if (normalized === 'growth' || normalized === 'pro' || normalized === 'plus') cls += ' plan-plus';
  return el('span', { class: cls }, [label]);
}

// --- Plans (Basic / Business / Growth / Pro) ---
// Legacy mapping: old Business = Business, old Growth = Growth.
function normalizePlan(plan){
  const p = String(plan || 'basic').toLowerCase().trim();
  if (p === 'premium' || p === 'standard') return 'business';
  if (p === 'plus') return 'growth';
  if (p === 'basic' || p === 'business' || p === 'growth' || p === 'pro') return p;
  return 'basic';
}


function todayISO(){
  return new Date().toISOString().slice(0,10);
}

function normalizeFeatureOverrides(raw){
  if (!raw) return {};
  if (Array.isArray(raw)){
    return raw.reduce((acc,key)=>{
      const k = String(key||'').trim();
      if (k) acc[k] = { enabled:true, start:'', end:'', reason:'' };
      return acc;
    }, {});
  }
  if (typeof raw === 'object') return raw;
  return {};
}

function featureOverrideConfig(listing, key){
  const overrides = normalizeFeatureOverrides(listing?.feature_overrides);
  const cfg = overrides[String(key||'')] || null;
  return (cfg && typeof cfg === 'object') ? cfg : (cfg ? { enabled:true, start:'', end:'', reason:'' } : null);
}

function hasFeatureOverride(listing, key){
  const cfg = featureOverrideConfig(listing, key);
  if (!cfg || cfg.enabled === false) return false;
  const t = todayISO();
  const start = String(cfg.start || cfg.start_date || '').slice(0,10);
  const end = String(cfg.end || cfg.end_date || '').slice(0,10);
  if (start && t < start) return false;
  if (end && t > end) return false;
  return true;
}

function featureOverrideSummary(raw){
  const overrides = normalizeFeatureOverrides(raw);
  return Object.entries(overrides).filter(([_,cfg])=>cfg && cfg.enabled !== false).map(([key,cfg])=>{
    const end = cfg.end || cfg.end_date || '';
    return end ? `${key} until ${end}` : key;
  });
}


