const RM24_MARKET_ORDER = ['NO','SE','DK','CH','GB','DE','FI','NL','FR','ES','IT','IE','BE','AT','PT','US'];
function normalizeMarketCountry(country){ const c = String(country || 'NO').trim().toUpperCase(); return RM24_MARKETS[c] ? c : 'NO'; }
function marketForCountry(country){ return RM24_MARKETS[normalizeMarketCountry(country)]; }

const RM24_ACCOUNTING_CURRENCIES = ['NOK','SEK','DKK','EUR','GBP','USD','CHF'];
function accountingCurrencyOptions(){ return RM24_ACCOUNTING_CURRENCIES.map(c => [c, c]); }
function accountingCurrencyForCountry(country){ return marketForCountry(country || 'NO').currency || 'NOK'; }
function normalizeAccountingCurrency(currency, country){
  const cur = String(currency || '').trim().toUpperCase();
  return RM24_ACCOUNTING_CURRENCIES.includes(cur) ? cur : accountingCurrencyForCountry(country || 'NO');
}

function moneyAmount(value, currency){ const decimal = currency === 'EUR' || currency === 'USD' || currency === 'CHF' || currency === 'GBP'; return decimal ? Number(value).toFixed(2) : String(Math.round(Number(value))); }
function formatPlanPrice(plan, billing='monthly', country='NO'){
  const p = normalizePlan(plan); const market = marketForCountry(country); const monthly = market.prices[p] || market.prices.basic; const value = billing === 'yearly' ? monthly * 10 : monthly; const suffix = billing === 'yearly' ? '/yr' : '/mo'; return moneyAmount(value, market.currency) + ' ' + market.currency + suffix;
}
function marketTaxCopy(country){ const market = marketForCountry(country); return market.currency === 'USD' ? 'Sales tax may be added at checkout depending on your state.' : 'Price includes VAT where applicable.'; }

function maxDishesForPlan(plan){
  const p = normalizePlan(plan);
  if (p === 'pro') return 48;
  if (p === 'growth') return 24;
  if (p === 'business') return 12;
  return 5;
}

function planDisplayName(plan){
  const p = normalizePlan(plan);
  if (p === 'pro') return 'Pro';
  if (p === 'growth') return 'Growth';
  if (p === 'business') return 'Business';
  return 'Basic';
}


function planLevel(plan){
  const p = normalizePlan(plan);
  if (p === 'pro') return 3;
  if (p === 'growth') return 2;
  if (p === 'business') return 1;
  return 0;
}

function hasCustomerListAccess(listing){
  return planLevel(listing?.plan || 'basic') >= 1
    || hasFeatureOverride(listing, 'crm')
    || hasFeatureOverride(listing, 'customer_list')
    || hasFeatureOverride(listing, 'customers');
}

function hasAccountingAccess(listing){
  return planLevel(listing?.plan || 'basic') >= 1
    || hasFeatureOverride(listing, 'accounting')
    || hasFeatureOverride(listing, 'accounting_insights');
}

