// Form field wrapper (label + control)
// Used throughout the /list wizard.
function field(label, control){
  return el('div', { class:'field' }, [
    el('div', { class:'label' }, [label]),
    control
  ]);
}

// Small helper for <select> dropdowns.
// options: Array<[value, label]>
function select(value, options, onchange){
  const sel = el('select', {
    class: 'input',
    onchange: (e)=>onchange(e.target.value)
  }, (options||[]).map(([v,label])=>
      el('option', { value: String(v), selected: String(v)===String(value) }, [String(label)])
  ));
  try{ sel.value = String(value); }catch(_e){}
  return sel;
}


