function openPortalMap(){
  // Make Map easy to reach from anywhere.
  state.ui.portalView = 'map';
  // Navigate home if needed.
  if (location.pathname !== '/' && location.pathname !== '' && !location.pathname.endsWith('/index.html')){
    navigate('/');
  } else {
    render();
  }
  // Move user to the top so the map toggle/area is immediately reachable.
  setTimeout(()=>{ scrollToTop(); }, 30);
}



function scrollToTop(){
  try{ window.scrollTo({ top:0, left:0, behavior:'smooth' }); }
  catch(e){ try{ window.scrollTo(0,0); }catch(_){} }
}

function setPortalView(view){
  state.ui.portalView = view;
  // Make view switching robust: always clean up Leaflet when leaving map.
  if (view !== 'map'){
    try{ destroyLeaflet(); }catch(e){}
  }
}

function portalViewToggle(extraClass=''){
  return el('div', { class:'seg viewToggle' + (extraClass ? ' ' + extraClass : ''), role:'tablist', 'aria-label':'View toggle' }, [
    el('button', { class: 'segbtn listbtn' + (state.ui.portalView==='list' ? ' active' : ''), type:'button', onclick: ()=>{
      setPortalView('list');
      render();
      // Make it obvious that List is selected by bringing the user to the results.
      setTimeout(()=>{
        const r = document.getElementById('results');
        if (r && r.scrollIntoView){
          try{ r.scrollIntoView({ behavior:'smooth', block:'start' }); }
          catch(e){ try{ r.scrollIntoView(true); }catch(_){} }
        } else {
          scrollToTop();
        }
      }, 30);
    } }, [t('ui.list')]),
    el('button', { class: 'segbtn mapbtn' + (state.ui.portalView==='map' ? ' active' : ''), type:'button', onclick: ()=>{
      setPortalView('map');
      render();
      // Bring the user to the map area (not the bottom of the page).
      setTimeout(()=>{
        const box = document.getElementById('leafletPortalMap');
        if (box && box.scrollIntoView){
          try{ box.scrollIntoView({ behavior:'smooth', block:'start' }); }
          catch(e){ try{ box.scrollIntoView(true); }catch(_){} }
        } else {
          scrollToTop();
        }
      }, 30);
    } }, [t('ui.map')]),
  ]);
}


