function quickCuisineChips(){
  const picks = ['all_asian','thai','filipino','vietnamese','chinese','korean','japanese','indonesian','indian','pan_asian'];
  return picks.map(k => {
    const active = (k === 'all_asian') ? !state.filters.cuisine : state.filters.cuisine === k;
    return chip(cuisineName(k), active, ()=>{
      state.filters.cuisine = (k === 'all_asian') ? '' : k;
      loadListings();
    });
  });
}

function cuisineName(key){
  if (key === 'all_asian') {
    return t('ui.allAsian');
  }
  const c = state.cuisines.find(x=>x.key===key);
  if (!c) return key;
  return c.label[state.lang] || c.label.en || key;
}

function ownerCuisineChoices(){
  const order = ['thai','filipino','vietnamese','chinese','korean','japanese','indonesian','indian','pan_asian'];
  const byKey = new Map((state.cuisines || []).map(c => [c.key, c]));
  return order.map(key => byKey.get(key)).filter(Boolean);
}

