function contactButtons(listing){
  const c = listing.contact || {};
  const buttons = [];
  if (c.whatsapp) buttons.push({ label: 'WhatsApp', href: `https://wa.me/${c.whatsapp.replace(/\D/g,'')}` });
  if (c.phone) buttons.push({ label: t('ui.call'), href: `tel:${c.phone}` });
  if (c.instagram) buttons.push({ label: 'Instagram', href: `https://instagram.com/${c.instagram.replace('@','')}` });
  if (c.email) buttons.push({ label: t('ui.email'), href: `mailto:${c.email}` });

  const primary = buttons.slice(0,3);
  const rest = buttons.slice(3);

  const row = el('div', { class:'contact-row' }, primary.map(b =>
    el('a', { class:'btn', href: b.href, target:'_blank', rel:'noreferrer' }, [b.label])
  ));

  const secondary = el('div', { class:'row', style:'gap:10px; margin-top:10px; flex-wrap:wrap' }, [
    button(t('ui.copyOrder'), { variant:'outline', onclick: ()=>copyOrderMessage(listing) }),
    button(t('ui.share'), { variant:'ghost', onclick: ()=>sharePage() }),
  ]);

  let more = null;
  if (rest.length){
    more = el('div', { class:'muted small', style:'margin-top:8px' }, [
      t('ui.more'),
      ...rest.map((b, idx) => {
        const a = el('a', { href: b.href, target:'_blank', rel:'noreferrer', class:'link' }, [b.label]);
        return idx < rest.length-1 ? el('span', {}, [a, ' · ']) : a;
      })
    ]);
  }

  return el('div', { class:'section' }, [row, secondary, more].filter(Boolean));
}

