function ingredientsBlock(m){
  const ing = m.ingredients;
  if (!ing) return null;
  const label = state.lang==='no' ? 'Ingredienser' : 'Ingredients';
  let arr = [];
  if (Array.isArray(ing)) arr = ing;
  else if (typeof ing === 'string') arr = ing.split(',').map(s=>s.trim()).filter(Boolean);
  else arr = (ing?.[state.lang] || ing?.en || []);
  if (!arr || !arr.length) return null;

  return el('details', { class:'ing' }, [
    el('summary', { class:'ing-sum' }, [label]),
    el('ul', { class:'ing-list' }, arr.map(x => el('li', {}, [x])))
  ]);
}

function dishDescriptionText(m){
  // Supports both old demo data (desc.en/no) and newer owner-entered data
  // (description or desc as string/object). This is the short sales text shown
  // under the dish name on the public menu and inside the dish modal.
  const lang = state.lang || 'en';
  const desc = m?.desc;
  if (typeof desc === 'string' && desc.trim()) return desc.trim();
  if (desc && typeof desc === 'object'){
    const v = desc[lang] || desc.en || desc.no || Object.values(desc).find(x=>String(x||'').trim());
    if (v && String(v).trim()) return String(v).trim();
  }
  const description = m?.description;
  if (typeof description === 'string' && description.trim()) return description.trim();
  if (description && typeof description === 'object'){
    const v = description[lang] || description.en || description.no || Object.values(description).find(x=>String(x||'').trim());
    if (v && String(v).trim()) return String(v).trim();
  }
  return '';
}

function setDishDescriptionText(m, value){
  const v = String(value || '').trimStart();
  m.description = v;
  const old = (m.desc && typeof m.desc === 'object') ? m.desc : {};
  // One visible field for MVP: keep en/no in sync so switching language does not
  // make the owner's own description disappear.
  m.desc = { ...old, en: v, no: v };
}


function normalizeDishKey(m){
  if (m.dish_key) return String(m.dish_key);
  const nm = (m.name?.en || m.name?.no || m.title || '').toLowerCase().trim();
  // keep sets separate
  return nm || ('dish_' + Math.random().toString(16).slice(2));
}

function buildDishGroupByKey(listing, dishKey){
  // Build the same group shape used by menuSection/openDishOptions so we can
  // open the dish modal from other parts of the kitchen page (signature cards, etc.).
  const key = String(dishKey || '').trim();
  const matches = (listing?.menu||[]).map((m, idx)=>({m, idx})).filter(x=>normalizeDishKey(x.m)===key);
  if (!matches.length) return null;

  const order = { single: 1, family: 2, group: 3 };
  const repEntry = matches.find(x=>x.m.serves==='single') || matches[0];
  const rep = repEntry.m;

  const title = rep.name?.[state.lang] || rep.name?.en || rep.title || '';
  const desc = dishDescriptionText(rep);
  const image = dishImageEffective(listing, rep);
  const fromPrice = Math.min(...matches.map(x=>Number(x.m.price)||999999));
  const options = matches
    .map(x=>x.m)
    .slice()
    .sort((a,b)=>(order[a.serves]||9)-(order[b.serves]||9))
    .map(x=>({ serves:x.serves, price:x.price, note:x.note?.[state.lang] || x.note?.en || '' }));

  const ingredientsSource = (matches.map(x=>x.m).find(x=>x.ingredients) || null);
  const ix = (rep.image_focal_x==null || isNaN(Number(rep.image_focal_x))) ? 50 : Number(rep.image_focal_x);
  const iy = (rep.image_focal_y==null || isNaN(Number(rep.image_focal_y))) ? 50 : Number(rep.image_focal_y);
  const iz = (rep.image_zoom==null || isNaN(Number(rep.image_zoom))) ? 120 : Number(rep.image_zoom);

  return {
    key,
    title,
    desc,
    image,
    fromPrice,
    options,
    ingredientsSource,
    repIndex: repEntry.idx,
    image_focal_x: ix,
    image_focal_y: iy,
    image_zoom: iz,
    sectionLabel: menuSectionLabelForItem(rep),
    sectionKey: String(rep?.menu_section_key || '').trim(),
    sectionCustom: String(rep?.menu_section_custom || '').trim(),
  };
}

function servesLabel(serves){
  if (serves==='single') return (state.lang==='no' ? 'Single (1)' : 'Single (1)');
  if (serves==='family') return (state.lang==='no' ? 'Familie (3–4)' : 'Family (3–4)');
  if (serves==='group') return (state.lang==='no' ? 'Gruppe (6–8)' : 'Group (6–8)');
  return serves || '';
}


function dishImageEffective(listing, dish){
  const title = ((dish?.name?.en || dish?.name?.no || dish?.title || '') + '').toLowerCase();
  const img = String(dish?.image || '').trim();
  if (img && (isDemoListing(listing) || !isDemoAssetPath(img))) return img;
  // Demo rows may still use bundled demo images. Real kitchens must stay blank until
  // the owner uploads their own food photo.
  if (listing && listing.slug === 'marias-filipino-kusina'){
    if (title.includes('adobo')) return 'assets/dish_adobo_custom.png';
    if (title.includes('lumpia') || title.includes('vårr') || title.includes('värr')) return 'assets/dish_lumpia_custom.png';
    if (title.includes('barkada')) return 'assets/dish_barkada_custom.png';
    if (img.includes('dish_lumpia')) return 'assets/dish_lumpia_custom.png';
    if (img.includes('dish_family3') || img.includes('dish_barkada')) return 'assets/dish_barkada_custom.png';
  }
  return '';
}

function dishCropEffective(dish){
  // Dish image crop (applies to both thumbnails + large modal image)
  // Defaults are slightly zoomed-in to reduce "air" for food photos.
  const clamp = (v)=>Math.max(0, Math.min(100, Number(v)));
  const clampZoom = (v)=>Math.max(100, Math.min(200, Number(v)));
  const x = clamp(dish?.image_focal_x==null ? 50 : dish.image_focal_x);
  const y = clamp(dish?.image_focal_y==null ? 50 : dish.image_focal_y);
  const z = clampZoom(dish?.image_zoom==null ? 120 : dish.image_zoom);
  return { x, y, z };
}

function dishBgStyle(img, dish){
  const clean = String(img || '').trim();
  if (!clean) return '';
  const { x, y, z } = dishCropEffective(dish);
  return `background-image:url(${assetUrl(clean)}); background-position: ${x}% ${y}%; background-size: ${z}% auto`;
}

function dishImageBox(className, img, dish, children=[]){
  const clean = String(img || '').trim();
  if (!clean) return imagePlaceholder(className);
  return el('div', { class: `${className || ''} editableImg`.trim(), style:dishBgStyle(clean, dish) }, children.filter(Boolean));
}


function ensureOrderForCook(listing){
  if (!state.orderDraft || state.orderDraft.cookSlug !== listing.slug){
    state.orderDraft = { cookSlug: listing.slug, items: [], method: 'pickup', timeKey: 'ASAP', time: '', note: '', name: '' };
  }
}

function orderCount(){
  const od = state.orderDraft;
  if (!od || !od.items) return 0;
  return od.items.reduce((s,x)=>s+Number(x.qty||0),0);
}

function addToOrder(listing, group, opt){
  ensureOrderForCook(listing);
  const key = (group.key || group.title || 'dish');
  const safe = String(key).toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'');
  const id = `${listing.slug}::${safe}::${opt.serves}`;
  const existing = state.orderDraft.items.find(x=>x.id===id);
  if (existing){
    existing.qty += 1;
  } else {
    state.orderDraft.items.push({
      id,
      dish: group.title,
      serves: opt.serves,
      servesLabel: servesLabel(opt.serves),
      price: opt.price,
      currency: listing.currency,
      qty: 1
    });
  }
  render();
}

function buildOrderMessage(listing){
  ensureOrderForCook(listing);
  const od = state.orderDraft;

  const greet = state.lang==='no'
    ? `Hei ${listing.name}! Jeg ønsker å bestille:`
    : `Hi ${listing.name}! I'd like to order:`;

  const lines = od.items.map(it => `- ${it.dish} — ${it.servesLabel} x${it.qty}`);

  const methodLabel = state.lang==='no' ? 'Ønsker' : 'Request';
  const timeLabel = state.lang==='no' ? 'Ønsket tidspunkt' : 'Preferred time';
  const noteLabel = state.lang==='no' ? 'Notat' : 'Note';
  const nameLabel = state.lang==='no' ? 'Navn' : 'Name';

  let msg = [greet, ...lines].join('\n');

  const methodText = (()=>{
    if (od.method === 'delivery') return (state.lang==='no' ? 'Levering' : 'Delivery');
    return (state.lang==='no' ? 'Henting' : 'Pickup');
  })();

  // Only add method if seller supports delivery OR user chose delivery
  if ((listing.badges||[]).includes('delivery') || od.method === 'delivery'){
    msg += `\n${methodLabel}: ${methodText}`;
  }

  if (od.timeKey === 'ASAP'){
    msg += `\n${timeLabel}: ${state.lang==='no' ? 'Så fort som mulig' : 'ASAP'}`;
  } else if (od.time && String(od.time).trim()){
    msg += `\n${timeLabel}: ${String(od.time).trim()}`;
  }

  if (od.note && od.note.trim()){
    msg += `\n${noteLabel}: ${od.note.trim()}`;
  }
  if (od.name && od.name.trim()){
    msg += `\n${nameLabel}: ${od.name.trim()}`;
  }
  return msg;
}

function whatsappHref(listing, message){
  const wa = listing.contact?.whatsapp;
  if (!wa) return null;
  const digits = String(wa).replace(/\D/g,'');
  if (!digits) return null;
  return `https://wa.me/${digits}?text=${encodeURIComponent(message)}`;
}

function copyToClipboard(text, okMessage){
  const ok = okMessage || (state.lang==='no' ? 'Kopiert!' : 'Copied!');
  if (navigator.clipboard && navigator.clipboard.writeText){
    navigator.clipboard.writeText(text)
      .then(()=>alert(ok))
      .catch(()=>prompt(state.lang==='no' ? 'Kopier:' : 'Copy:', text));
  } else {
    prompt(state.lang==='no' ? 'Kopier:' : 'Copy:', text);
  }
}

function openOrderDrawer(listing){
  ensureOrderForCook(listing);
  state.ui.orderOpen = true;
  render();
}

function closeOrderDrawer(){
  state.ui.orderOpen = false;
  render();
}

function clearOrder(listing){
  ensureOrderForCook(listing);
  state.orderDraft.items = [];
  state.ui.orderOpen = false;
  render();
}

function orderBar(listing){
  const od = state.orderDraft;
  if (!od || od.cookSlug !== listing.slug || !od.items.length) return null;

  const count = orderCount();
  return el('div', { class:'order-bar' }, [
    el('div', { class:'order-bar-inner container' }, [
      el('div', {}, [
        el('div', { class:'order-count' }, [String(count) + ' ' + (state.lang==='no' ? 'vare(r)' : 'item(s)')]),
        el('div', { class:'muted small' }, [state.lang==='no' ? 'Bestillingsutkast' : 'Order draft'])
      ]),
      el('div', { class:'row', style:'gap:10px' }, [
        button(state.lang==='no' ? 'Vis' : 'View', { variant:'primary', className:'btn-emph', onclick: ()=>openOrderDrawer(listing) }),
        button(state.lang==='no' ? 'Tøm' : 'Clear', { variant:'outline', onclick: ()=>clearOrder(listing) })
      ])
    ])
  ]);
}

function orderDrawer(listing){
  if (!state.ui.orderOpen) return null;
  ensureOrderForCook(listing);
  const od = state.orderDraft;

  // Ensure a valid method
  const supportsDelivery = (listing.badges||[]).includes('delivery');
  const supportsPickup = (listing.badges||[]).includes('pickup') || true;
  if (!od.method){
    od.method = supportsDelivery ? 'pickup' : 'pickup';
  }
  if (od.method === 'delivery' && !supportsDelivery){
    od.method = 'pickup';
  }

  const message = buildOrderMessage(listing);

  const timeOptions = [
    { key:'ASAP', no:'Så fort som mulig', en:'ASAP' },
    { key:'Today', no:'I dag', en:'Today' },
    { key:'Tomorrow', no:'I morgen', en:'Tomorrow' },
    { key:'Custom', no:'Eget tidspunkt', en:'Custom' },
  ];

  const currentTimeKey = (()=>{
    const k = od.timeKey || 'ASAP';
    if (timeOptions.some(x=>x.key===k)) return k;
    return 'Custom';
  })();

  const itemRows = od.items.map(it => el('div', { class:'order-item' }, [
    el('div', { class:'order-item-main' }, [
      el('div', { class:'menu-title', style:'margin:0' }, [it.dish]),
      el('div', { class:'muted small' }, [it.servesLabel]),
    ]),
    el('div', { class:'order-item-qty' }, [
      el('button', { class:'qty', onclick: ()=>{ 
        if (it.qty > 1){ it.qty -= 1; } else { od.items = od.items.filter(x=>x.id!==it.id); }
        render();
      } }, ['−']),
      el('div', { class:'qty-num' }, [String(it.qty)]),
      el('button', { class:'qty', onclick: ()=>{ it.qty += 1; render(); } }, ['+']),
    ]),
  ]));

  const wa = whatsappHref(listing, message);

  const disclaimer = state.lang==='no'
    ? 'Bestillingen sendes direkte til kjøkkenet. RiceMap24 håndterer ikke betaling og tar ikke ansvar for levering/oppfyllelse.'
    : 'Your order is sent directly to the kitchen. RiceMap24 does not process payments and is not responsible for fulfillment.';

  const methodLabel = state.lang==='no' ? 'Ønsker du henting eller levering?' : 'Pickup or delivery?';
  const timeLabel = state.lang==='no' ? 'Ønsket tidspunkt' : 'Preferred time';

  const methodSeg = el('div', { class:'seg' }, [
    el('button', { class: 'segbtn' + (od.method==='pickup' ? ' active' : ''), onclick: ()=>{ od.method='pickup'; render(); } }, [state.lang==='no' ? 'Henting' : 'Pickup']),
    supportsDelivery ? el('button', { class: 'segbtn' + (od.method==='delivery' ? ' active' : ''), onclick: ()=>{ od.method='delivery'; render(); } }, [state.lang==='no' ? 'Levering' : 'Delivery']) : null
  ].filter(Boolean));

  return el('div', { class:'overlay', onclick:(e)=>{ if (e.target.classList.contains('overlay')) closeOrderDrawer(); } }, [
    el('div', { class:'modal modal-wide' }, [
      el('div', { class:'modal-head' }, [
        el('div', { class:'modal-title' }, [state.lang==='no' ? 'Bestillingsutkast' : 'Order draft']),
        el('button', { class:'x', onclick: closeOrderDrawer }, ['✕'])
      ]),
      el('div', { class:'modal-body' }, [
        el('div', { class:'muted', style:'margin-bottom:10px' }, [disclaimer]),

        el('div', { class:'order-list' }, itemRows),
        el('hr', { class:'sep' }),

        el('label', { class:'lbl' }, [methodLabel]),
        methodSeg,

        el('label', { class:'lbl', style:'margin-top:12px' }, [timeLabel]),
        el('select', { class:'select', onchange:(e)=>{ 
          const key = e.target.value;
          od.timeKey = key;
          if (key === 'ASAP'){
            od.time = '';
          } else if (key === 'Custom'){
            od.time = od.time || '';
          } else {
            const opt = timeOptions.find(x=>x.key===key);
            od.time = (state.lang==='no' ? opt.no : opt.en);
          }
          render();
        }}, timeOptions.map(p => el('option', { value:p.key, selected: p.key === currentTimeKey }, [state.lang==='no' ? p.no : p.en]))),

        (currentTimeKey === 'Custom'
          ? el('input', { class:'input', placeholder: state.lang==='no' ? 'F.eks. lørdag kl. 16:00' : 'e.g. Saturday 4:00 PM', value: od.time||'', oninput:(e)=>{ od.time = e.target.value; } })
          : null),

        el('label', { class:'lbl', style:'margin-top:12px' }, [state.lang==='no' ? 'Notat (allergier osv.)' : 'Note (allergies etc.)']),
        el('textarea', { class:'textarea', rows:3, placeholder: state.lang==='no' ? 'F.eks. ingen nøtter' : 'e.g. no peanuts', oninput:(e)=>{ od.note = e.target.value; } }, [od.note||'']),
        el('label', { class:'lbl', style:'margin-top:12px' }, [state.lang==='no' ? 'Navn (valgfritt)' : 'Name (optional)']),
        el('input', { class:'input', placeholder: state.lang==='no' ? 'Ditt navn' : 'Your name', value: od.name||'', oninput:(e)=>{ od.name = e.target.value; } }),
      ].filter(Boolean)),
      el('div', { class:'modal-actions' }, [
        button(t('ui.copyOrder'), { variant:'outline', onclick: ()=>copyToClipboard(message, state.lang==='no' ? 'Kopiert! Lim inn i WhatsApp eller Instagram.' : 'Copied! Paste into WhatsApp or Instagram.') }),
        wa
          ? el('a', { class:'btn primary', href: wa, target:'_blank', rel:'noreferrer' }, [state.lang==='no' ? 'Send på WhatsApp' : 'Send via WhatsApp'])
          : button(state.lang==='no' ? 'Send (kopier)' : 'Send (copy)', { variant:'primary', onclick: ()=>copyToClipboard(message) }),
      ])
    ])
  ]);
}


function openDishOptions(listing, group){
  const title = group.title || '';
  const desc = group.desc || '';
  const img = group.image || '';

  const clamp = (v)=>Math.max(0, Math.min(100, Number(v)));
  const clampZoom = (v)=>Math.max(100, Math.min(200, Number(v)));
  const isOwnerPreview = !!(state.preview && state.preview.active && state.preview.token);
  let dishFocalX = clamp(group.image_focal_x==null?50:group.image_focal_x);
  let dishFocalY = clamp(group.image_focal_y==null?50:group.image_focal_y);
  let dishZoom = clampZoom(group.image_zoom==null?120:group.image_zoom);

  const overlay = el('div', { class:'overlay', onclick: (e)=>{ if (e.target===overlay) overlay.remove(); } }, [
    el('div', { class:'modal modal-wide' }, [
      el('div', { class:'modal-head' }, [
        el('div', { class:'modal-title' }, [title]),
        el('button', { class:'x', onclick: ()=>overlay.remove() }, ['✕'])
      ]),
      el('div', { class:'modal-body' }, [
        img ? (()=>{
          const n = el('div', { class:'dish-modal-img', style:`background-image:url(${assetUrl(img)}); background-position: ${dishFocalX}% ${dishFocalY}%; background-size: ${dishZoom}% auto` });
          return n;
        })() : null,
        desc ? el('div', { class:'muted', style:'margin-top:10px' }, [desc]) : null,

        (isOwnerPreview && img && !state.ui.editMode ? el('div', { class:'muted small', style:'margin-top:10px' }, [state.lang==='no'
          ? 'Slå på «Edit Photos» i toppbanneret mens du står i Menu & Photos for å zoome og flytte snittet på dette bildet.'
          : 'Turn on “Edit Photos” in the top banner while you are in Menu & Photos to zoom and adjust the crop for this image.'
        ]) : null),

        // Owner-only: image crop editor for dish photos (affects thumbnails + modal)
        (isOwnerPreview && state.ui.editMode && img ? (()=>{
          const focalXVal = el('span', { class:'muted small' }, [String(dishFocalX) + '%']);
          const focalVal = el('span', { class:'muted small' }, [String(dishFocalY) + '%']);
          const zoomVal = el('span', { class:'muted small' }, [String(dishZoom) + '%']);

          const focalXRange = el('input', {
            type:'range', min:0, max:100,
            value: String(dishFocalX),
            class:'focalRange',
            oninput:(e)=>{
              const v = clamp(e.target.value||50);
              dishFocalX = v;
              const imgEl = overlay.querySelector('.dish-modal-img');
              if (imgEl) imgEl.style.backgroundPosition = `${dishFocalX}% ${dishFocalY}%`;
              focalXVal.textContent = String(v) + '%';
            }
          });

          const focalRange = el('input', {
            type:'range', min:0, max:100,
            value: String(dishFocalY),
            class:'focalRange',
            oninput:(e)=>{
              const v = clamp(e.target.value||50);
              dishFocalY = v;
              const imgEl = overlay.querySelector('.dish-modal-img');
              if (imgEl) imgEl.style.backgroundPosition = `${dishFocalX}% ${dishFocalY}%`;
              focalVal.textContent = String(v) + '%';
            }
          });

          const zoomRange = el('input', {
            type:'range', min:100, max:200,
            value: String(dishZoom),
            class:'focalRange',
            oninput:(e)=>{
              const v = clampZoom(e.target.value||120);
              dishZoom = v;
              const imgEl = overlay.querySelector('.dish-modal-img');
              if (imgEl) imgEl.style.backgroundSize = `${v}% auto`;
              zoomVal.textContent = String(v) + '%';
            }
          });

          const saveBtn = button(state.lang==='no' ? 'Lagre bilde-snitt' : 'Save crop', {
            variant:'primary',
            onclick: async()=>{
              await ownerSaveDishCrop(state.preview.token, group.key, dishFocalX, dishFocalY, dishZoom);
              group.image_focal_x = dishFocalX;
              group.image_focal_y = dishFocalY;
              group.image_zoom = dishZoom;
              overlay.remove();
            }
          });

          const resetBtn = button(state.lang==='no' ? 'Nullstill' : 'Reset', {
            variant:'outline',
            onclick: ()=>{
              dishFocalX = 50;
              dishFocalY = 50;
              dishZoom = 120;
              const imgEl = overlay.querySelector('.dish-modal-img');
              if (imgEl){
                imgEl.style.backgroundPosition = `${dishFocalX}% ${dishFocalY}%`;
                imgEl.style.backgroundSize = `${dishZoom}% auto`;
              }
              focalXRange.value = String(dishFocalX);
              focalRange.value = String(dishFocalY);
              zoomRange.value = String(dishZoom);
              focalXVal.textContent = String(dishFocalX) + '%';
              focalVal.textContent = String(dishFocalY) + '%';
              zoomVal.textContent = String(dishZoom) + '%';
            }
          });

          return el('div', { class:'card', style:'margin-top:12px; padding:12px' }, [
            el('div', { class:'row', style:'justify-content:space-between; align-items:center; gap:10px; flex-wrap:wrap' }, [
              el('div', { class:'muted small' }, [state.lang==='no' ? 'Rediger bilde (kun du ser dette)' : 'Edit image (only visible to you)']),
              el('div', { class:'muted small' }, [state.lang==='no' ? 'Gjelder både små og store visninger' : 'Applies to thumbnails and the large image'])
            ]),
            el('div', { class:'muted small', style:'margin-top:6px' }, [state.lang==='no'
              ? 'Tips: Zoom inn til retten fyller rammen, og flytt litt opp/ned.'
              : 'Tip: Zoom in so the dish fills the frame, then adjust up/down.'
            ]),
            el('div', { class:'muted small', style:'margin-top:10px' }, [state.lang==='no' ? 'Venstre/Høyre' : 'Left/Right']),
            focalXRange,
            el('div', { class:'row', style:'justify-content:space-between; margin-top:4px' }, [
              el('span', { class:'muted small' }, [state.lang==='no' ? 'Vannrett posisjon' : 'Horizontal position']),
              focalXVal,
            ]),
            el('div', { class:'muted small', style:'margin-top:10px' }, [state.lang==='no' ? 'Opp/Ned' : 'Up/Down']),
            focalRange,
            el('div', { class:'row', style:'justify-content:space-between; margin-top:4px' }, [
              el('span', { class:'muted small' }, [kitchenEditText('position')]),
              focalVal,
            ]),
            el('div', { class:'muted small', style:'margin-top:10px' }, [state.lang==='no' ? 'Zoom' : 'Zoom']),
            zoomRange,
            el('div', { class:'row', style:'justify-content:space-between; margin-top:4px' }, [
              el('span', { class:'muted small' }, ['100%']),
              zoomVal,
            ]),
            el('div', { class:'row', style:'gap:10px; margin-top:10px; flex-wrap:wrap' }, [
              saveBtn,
              resetBtn
            ])
          ]);
        })() : null),

        el('div', { class:'dish-options' }, group.options.map(opt => 
          el('div', { class:'dish-opt' }, [
            el('div', {}, [
              el('div', { class:'menu-title', style:'margin:0' }, [servesLabel(opt.serves)]),
              opt.note ? el('div', { class:'muted small' }, [opt.note]) : null
            ].filter(Boolean)),
            el('div', { class:'row', style:'gap:10px; align-items:center' }, [
              el('div', { class:'price' }, [`${opt.price} ${listing.currency}`]),
              button(state.lang==='no' ? 'Legg til' : 'Add', { variant:'primary', onclick:(e)=>{ e.stopPropagation(); addToOrder(listing, group, opt); } })
            ])
          ])
        )),

        // Ingredients (from the first option that has it)
        (group.ingredientsSource ? ingredientsBlock(group.ingredientsSource) : null),

        el('div', { class:'muted small', style:'margin-top:10px' }, [
          state.lang==='no'
            ? 'Bestilling og betaling avtales direkte med kjøkkenet.'
            : 'Ordering and payment happen directly with the kitchen.'
        ])
      ].filter(Boolean))
    ])
  ]);
  document.body.appendChild(overlay);
}

function triggerBrowserDownload(url, filename=''){
  const a = document.createElement('a');
  a.href = url;
  if (filename) a.download = filename;
  a.rel = 'noopener';
  a.style.display = 'none';
  document.body.appendChild(a);
  a.click();
  a.remove();
}

function downloadPrintAsset(url, filename=''){
  try {
    triggerBrowserDownload(url, filename);
  } catch (_) {
    window.location.href = url;
  }
}

function openPrintPreview(ownerToken, cfg={}){
  const isNO = state.lang==='no';
  const overlay = el('div', { class:'overlay', onclick:(e)=>{ if(e.target===overlay) overlay.remove(); } }, [
    el('div', { class:'modal modal-wide print-preview-modal' }, [
      el('div', { class:'modal-head' }, [
        el('div', {}, [
          el('div', { class:'modal-title' }, [cfg.title || (isNO ? 'Forhåndsvisning' : 'Preview')]),
          cfg.subtitle ? el('div', { class:'muted small', style:'margin-top:4px' }, [cfg.subtitle]) : null
        ].filter(Boolean)),
        el('button', { class:'x', onclick: ()=>overlay.remove() }, ['✕'])
      ]),
      el('div', { class:'modal-body print-preview-body' }, [
        el('div', { class:'muted small' }, [isNO ? 'Laster forhåndsvisning …' : 'Loading preview …'])
      ]),
      el('div', { class:'modal-actions' }, [
        button(isNO ? 'Download' : 'Download', { variant:'primary', onclick: ()=>downloadPrintAsset(cfg.downloadUrl, cfg.filename || '') }),
        button(isNO ? 'Lukk' : 'Close', { variant:'outline', onclick: ()=>overlay.remove() })
      ])
    ])
  ]);
  document.body.appendChild(overlay);

  const body = overlay.querySelector('.print-preview-body');
  if (!body) return;
  body.innerHTML = '';

  if (cfg.kind === 'image'){
    body.appendChild(el('img', {
      class:'print-preview-image',
      src: cfg.previewUrl || cfg.downloadUrl,
      alt: cfg.title || 'Preview'
    }));
    return;
  }

  body.appendChild(el('iframe', {
    class:'print-preview-frame',
    src: (cfg.previewUrl || cfg.downloadUrl) + '#toolbar=0&navpanes=0&scrollbar=1',
    title: cfg.title || 'Preview'
  }));
}

function openPrintPreviewNode(cfg={}, nodeFactory){
  const isNO = state.lang==='no';
  const overlay = el('div', { class:'overlay', onclick:(e)=>{ if(e.target===overlay) overlay.remove(); } }, [
    el('div', { class:'modal modal-wide print-preview-modal' }, [
      el('div', { class:'modal-head' }, [
        el('div', {}, [
          el('div', { class:'modal-title' }, [cfg.title || (isNO ? 'Forhåndsvisning' : 'Preview')]),
          cfg.subtitle ? el('div', { class:'muted small', style:'margin-top:4px' }, [cfg.subtitle]) : null
        ].filter(Boolean)),
        el('button', { class:'x', onclick: ()=>overlay.remove() }, ['✕'])
      ]),
      el('div', { class:'modal-body print-preview-body', style:'display:flex; justify-content:center; align-items:flex-start; background:#f5efe8;' }),
      el('div', { class:'modal-actions' }, [
        button(isNO ? 'Download' : 'Download', { variant:'primary', onclick: ()=>downloadPrintAsset(cfg.downloadUrl, cfg.filename || '') }),
        button(isNO ? 'Lukk' : 'Close', { variant:'outline', onclick: ()=>overlay.remove() })
      ])
    ])
  ]);
  document.body.appendChild(overlay);
  const body = overlay.querySelector('.print-preview-body');
  if (!body) return;
  body.innerHTML = '';
  const node = typeof nodeFactory === 'function' ? nodeFactory() : null;
  if (node) body.appendChild(node);
}

function printAssetButtons(ownerToken, cfg={}){
  const isNO = state.lang==='no';
  return el('div', { class:'row', style:'gap:8px; margin-top:10px; flex-wrap:wrap' }, [
    button(isNO ? 'Preview' : 'Preview', { variant:'outline', onclick: ()=>openPrintPreview(ownerToken, cfg) }),
    button(isNO ? 'Download' : 'Download', { variant:'primary', onclick: ()=>downloadPrintAsset(cfg.downloadUrl, cfg.filename || '') })
  ]);
}

function rangeField(label, value, min, max, step, oninput){
  return el('label', {}, [
    el('div', { class:'muted small' }, [`${label}: ${value}`]),
    el('input', { type:'range', min:String(min), max:String(max), step:String(step), value:String(value), oninput:(e)=>oninput(Number(e.target.value)) })
  ]);
}

function colorField(label, value, oninput){
  return el('label', {}, [
    el('div', { class:'muted small' }, [label]),
    el('div', { class:'row', style:'gap:8px; align-items:center' }, [
      el('input', { type:'color', value: value || '#000000', oninput:(e)=>oninput(e.target.value) }),
      el('input', { type:'text', value: value || '', style:'width:110px', oninput:(e)=>oninput(e.target.value) })
    ])
  ]);
}


const MENU_SECTION_PRESETS = [
  { key:'mains', label:{ en:'Mains', no:'Hovedretter' } },
  { key:'sides', label:{ en:'Sides', no:'Tilbehør' } },
  { key:'desserts', label:{ en:'Desserts', no:'Dessert' } },
  { key:'drinks', label:{ en:'Drinks', no:'Drikke' } },
  { key:'combos', label:{ en:'Combos', no:'Kombinasjoner' } },
  { key:'specials', label:{ en:'Specials', no:'Spesialiteter' } },
];

function menuSectionPresetLabel(key){
  const found = MENU_SECTION_PRESETS.find(x=>x.key===String(key||'').trim());
  if (!found) return '';
  return found.label?.[state.lang] || found.label?.en || found.key;
}

function menuSectionLabelForItem(item, opts={}){
  const fallback = opts.fallback || '';
  const custom = String(item?.menu_section_custom || '').trim();
  if (custom) return custom;
  const key = String(item?.menu_section_key || '').trim();
  if (key) return menuSectionPresetLabel(key) || fallback;
  return fallback;
}

function menuSectionMetaForItem(item, opts={}){
  const fallbackLabel = opts.fallbackLabel || '';
  const custom = String(item?.menu_section_custom || '').trim();
  if (custom) return { id:`custom:${custom.toLowerCase()}`, label:custom, isFallback:false };
  const key = String(item?.menu_section_key || '').trim();
  if (key){
    return { id:`preset:${key}`, label:(menuSectionPresetLabel(key) || fallbackLabel || key), isFallback:false };
  }
  return { id:'uncategorized', label:fallbackLabel, isFallback:true };
}

function menuSection(listing){
  const items = listing.menu || [];

  // Group by dish_key or name, to support size options without cluttering the menu.
  const groupsMap = new Map();
  for (let i=0; i<items.length; i++){
    const m = items[i];
    const key = normalizeDishKey(m);
    if (!groupsMap.has(key)){
      groupsMap.set(key, { key, entries: [], firstIndex: i });
    }
    groupsMap.get(key).entries.push({ item:m, idx:i });
  }

  const fallbackSectionLabel = state.lang==='no' ? 'Andre retter' : 'Other dishes';
  const groups = Array.from(groupsMap.values()).map(g=>{
    const repEntry = g.entries.find(x=>x.item.serves==='single') || g.entries[0];
    const rep = repEntry?.item || {};

    const title = rep.name?.[state.lang] || rep.name?.en || rep.title || '';
    const desc = dishDescriptionText(rep);
    const image = dishImageEffective(listing, rep);
    const fromPrice = Math.min(...g.entries.map(x=>Number(x.item.price)||999999));

    const order = { single: 1, family: 2, group: 3 };
    const options = g.entries.map(x=>x.item).slice().sort((a,b)=>(order[a.serves]||9)-(order[b.serves]||9)).map(x=>({
      serves: x.serves,
      price: x.price,
      note: x.note?.[state.lang] || x.note?.en || ''
    }));

    const ingredientsSource = (g.entries.map(x=>x.item).find(x=>x.ingredients) || null);
    const ix = (rep.image_focal_x==null || isNaN(Number(rep.image_focal_x))) ? 50 : Number(rep.image_focal_x);
    const iy = (rep.image_focal_y==null || isNaN(Number(rep.image_focal_y))) ? 50 : Number(rep.image_focal_y);
    const iz = (rep.image_zoom==null || isNaN(Number(rep.image_zoom))) ? 120 : Number(rep.image_zoom);
    const sectionMeta = menuSectionMetaForItem(rep, { fallbackLabel: fallbackSectionLabel });

    return {
      key: g.key,
      title,
      desc,
      image,
      fromPrice,
      options,
      ingredientsSource,
      repIndex: repEntry?.idx ?? null,
      image_focal_x: ix,
      image_focal_y: iy,
      image_zoom: iz,
      firstIndex: g.firstIndex,
      sectionId: sectionMeta.id,
      sectionLabel: sectionMeta.label,
      sectionFallback: !!sectionMeta.isFallback,
    };
  }).sort((a,b)=>a.firstIndex-b.firstIndex);

  const explicitSectionCount = new Set(groups.filter(g=>!g.sectionFallback).map(g=>g.sectionId)).size;
  const shouldShowSections = explicitSectionCount > 0 || new Set(groups.map(g=>g.sectionId)).size > 1;
  const sections = [];
  const sectionsMap = new Map();
  for (const g of groups){
    const secId = shouldShowSections ? g.sectionId : '__all';
    if (!sectionsMap.has(secId)){
      sectionsMap.set(secId, {
        id: secId,
        label: shouldShowSections ? (g.sectionLabel || fallbackSectionLabel) : '',
        items: []
      });
      sections.push(sectionsMap.get(secId));
    }
    sectionsMap.get(secId).items.push(g);
  }

  const makeCard = (g) => {
    const clamp = (v)=>Math.max(0, Math.min(100, Number(v)));
    const clampZoom = (v)=>Math.max(100, Math.min(200, Number(v)));
    const x = clamp(g.image_focal_x==null?50:g.image_focal_x);
    const y = clamp(g.image_focal_y==null?50:g.image_focal_y);
    const z = clampZoom(g.image_zoom==null?120:g.image_zoom);
    const isOwner = !!(state.preview && state.preview.active && state.preview.token);
    const showEdit = isOwner && state.ui.editMode;
    return el('button', { class:'menu-card', onclick: ()=>openDishOptions(listing, g) }, [
      el('div', { class:'menu-img editableImg', style:`background-image:url(${assetUrl(g.image)}); background-position: ${x}% ${y}%; background-size: ${z}% auto` }, [
        showEdit ? el('div', { class:'editBadge', title: (state.lang==='no' ? 'Rediger bilde' : 'Edit image') }, ['✏️']) : null
      ].filter(Boolean)),
    el('div', { class:'menu-body' }, [
      el('div', { class:'menu-title' }, [g.title]),
      g.desc ? el('div', { class:'menu-desc muted' }, [g.desc]) : null,
      el('div', { class:'muted small', style:'margin-top:8px' }, [state.lang==='no' ? 'Trykk for å se valg og priser' : 'Tap to see options and prices'])
    ].filter(Boolean))
    ]);
  };

  return el('div', { class:'section' }, [
    el('h2', {}, [t('ui.menu')]),
    ...sections.map(sec=>el('div', { class:'menu-section' }, [
      shouldShowSections && sec.label ? el('div', { class:'menu-section-head' }, [
        el('h3', {}, [sec.label])
      ]) : null,
      el('div', { class:'menu-list' }, sec.items.map(makeCard))
    ].filter(Boolean))),
    el('p', { class:'muted small', style:'margin-top:10px' }, [
      state.lang==='no'
        ? 'Pris og tilgjengelighet kan variere. Avtal direkte med kjøkkenet.'
        : 'Price and availability may vary. Agree directly with the kitchen.'
    ])
  ]);
}

