function structuredInfoSection(listing){
  const a = listing.availability?.[state.lang] || listing.availability?.en || null;

  const howTitle = t('ui.howOrderingWorks');
  const howSteps = [
    t('ui.howStep1'),
    t('ui.howStep2'),
    t('ui.howStep3')
  ];

  const how = panelCard(howTitle, [
    el('ol', { class:'steps' }, howSteps.map(s => el('li', {}, [s]))),
    el('div', { class:'muted small', style:'margin-top:10px' }, [
      t('ui.directoryKitchenNote')
    ])
  ]);

  const pickupTitle = t('ui.pickupTiming');
  const pickupRows = [
    rowKV(t('ui.locationLabel'), `${listing.area} · ${listing.city}`),
    rowKV(t('ui.pickupLabel'), (listing.pickup_note?.[state.lang] || listing.pickup_note?.en || '—')),
  ];
  if ((listing.badges||[]).includes('delivery')){
    pickupRows.push(rowKV(t('ui.deliveryLabel'), (listing.delivery_note?.[state.lang] || listing.delivery_note?.en || '—')));
  }
  if (a){
    if (a.deadline) pickupRows.push(rowKV(t('ui.orderDeadlineLabel'), a.deadline));
    if (a.window) pickupRows.push(rowKV(t('ui.timeWindowLabel'), a.window));
  }
  const pickupCard = panelCard(pickupTitle, pickupRows);

  const payTitle = t('ui.paymentTitle');
  const payCard = panelCard(payTitle, [
    el('div', { class:'muted' }, [listing.payment_note?.[state.lang] || listing.payment_note?.en || '—']),
    el('div', { class:'muted small', style:'margin-top:10px' }, [
      t('ui.footer')
    ])
  ]);

  const contactTitle = t('ui.contactTitle');
  const c = listing.contact || {};
  const buttons = [];
  if (c.whatsapp) buttons.push({ label: 'WhatsApp', href: `https://wa.me/${String(c.whatsapp).replace(/\D/g,'')}` });
  if (c.phone) buttons.push({ label: t('ui.call'), href: `tel:${c.phone}` });
  if (c.instagram) buttons.push({ label: 'Instagram', href: `https://instagram.com/${String(c.instagram).replace('@','')}` });
  if (c.email) buttons.push({ label: t('ui.email'), href: `mailto:${c.email}` });

  const primary = buttons.slice(0,3);
  const rest = buttons.slice(3);

  const contactCard = panelCard(contactTitle, [
    el('div', { class:'contact-row' }, primary.map(b =>
      el('a', { class:'btn', href: b.href, target:'_blank', rel:'noreferrer' }, [b.label])
    )),
    el('div', { class:'row', style:'gap:10px; margin-top:10px; flex-wrap:wrap' }, [
      button(t('ui.copyOrder'), { variant:'outline', onclick: ()=>copyOrderMessage(listing) }),
      button(t('ui.share'), { variant:'ghost', onclick: ()=>sharePage() }),
    ]),
    rest.length ? el('div', { class:'muted small', style:'margin-top:8px' }, [
      t('ui.more'),
      ...rest.map((b, idx) => {
        const a = el('a', { href: b.href, target:'_blank', rel:'noreferrer', class:'link' }, [b.label]);
        return idx < rest.length-1 ? el('span', {}, [a, ' · ']) : a;
      })
    ]) : null,
    el('div', { class:'muted small', style:'margin-top:10px' }, [
      t('ui.tipOrderDraft')
    ])
  ].filter(Boolean));

  return el('div', { class:'section' }, [
    el('div', { class:'info-grid' }, [how, pickupCard, payCard, contactCard])
  ]);
}

