    function referralDashboardCard(){
      const country = normalizeMarketCountry(listing?.country || d?.country || 'NO');
      const market = marketForCountry(country);
      const plan = normalizePlan(listing?.plan || d?.plan || 'basic');
      const monthly = market.prices[plan] || market.prices.basic;
      const availableCredit = Number(listing?.referral_credit_balance || listing?.referralCreditBalance || 0);
      const totalEarned = Number(listing?.referral_credit_total_earned || listing?.referralCreditTotalEarned || 0);
      const successful = Number(listing?.successful_referrals || listing?.successfulReferrals || 0);
      const pending = Number(listing?.pending_referrals || listing?.pendingReferrals || 0);
      const savedNextMonth = Math.min(monthly, availableCredit);
      const code = referralCodeForListing();
      const inviteLink = `${location.origin}/list?ref=${encodeURIComponent(code)}`;
      const copyInviteLink = async ()=>{ try{ await navigator.clipboard?.writeText(inviteLink); alert(dashText('inviteLinkCopied')); } catch(_e){ alert(inviteLink); } };
      const shareText = `${dashText('shareInvite')} ${inviteLink}`;
      const events = Array.isArray(listing?.referral_events) ? listing.referral_events : [];
      return el('div', { class:'infocard referralDashboardCard' }, [
        el('div', { class:'referralTop' }, [
          el('div', { class:'referralIcon' }, ['↗']),
          el('div', { class:'referralIntro' }, [
            el('div', { class:'referralEyebrow' }, [dashText('referralProgram')]),
            el('div', { class:'referralTitle' }, [dashText('inviteKitchens')]),
            el('p', { class:'referralHeroText' }, [dashText('referralIntro')])
          ]),
          el('div', { class:'referralValuePill' }, [
            el('span', {}, [dashText('credit')]),
            el('strong', {}, ['50%']),
            el('em', {}, [dashText('ofFirstMonth')])
          ])
        ]),
        el('div', { class:'referralRule' }, [
          el('strong', {}, [dashText('rule')]),
          dashText('referralRule')
        ]),
        el('div', { class:'referralLinkBox' }, [
          el('div', { class:'referralLinkLabel' }, [dashText('yourInviteLink')]),
          el('div', { class:'referralLinkLine' }, [
            el('code', { class:'referralLinkText' }, [inviteLink]),
            button(dashText('copy'), { className:'referralCopyBtn', onclick: copyInviteLink })
          ])
        ]),
        el('div', { class:'referralShareRow' }, [
          el('a', { class:'btn btn-outline referralShareBtn', href:`https://wa.me/?text=${encodeURIComponent(shareText)}`, target:'_blank', rel:'noreferrer' }, ['WhatsApp']),
          el('a', { class:'btn btn-outline referralShareBtn', href:`https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(inviteLink)}`, target:'_blank', rel:'noreferrer' }, ['Facebook']),
          el('a', { class:'btn btn-outline referralShareBtn', href:`mailto:?subject=${encodeURIComponent(dashText('inviteEmailSubject'))}&body=${encodeURIComponent(shareText)}` }, [dashText('email')])
        ]),
        el('div', { class:'referralStatsGrid' }, [
          el('div', { class:'referralStat referralStatMain' }, [el('span',{},[dashText('availableCredit')]), el('strong',{},[`${moneyAmount(availableCredit, market.currency)} ${market.currency}`])]),
          el('div', { class:'referralStat' }, [el('span',{},[dashText('successful')]), el('strong',{},[String(successful)])]),
          el('div', { class:'referralStat' }, [el('span',{},[dashText('pending')]), el('strong',{},[String(pending)])]),
          el('div', { class:'referralStat' }, [el('span',{},[dashText('savedNextMonth')]), el('strong',{},[`${moneyAmount(savedNextMonth, market.currency)} ${market.currency}`])])
        ]),
        el('div', { class:'referralHistoryHead' }, [dashText('referralHistory')]),
        el('div', { class:'referralTableWrap' }, [el('table', { class:'referralTable' }, [
          el('thead', {}, [el('tr', {}, [el('th', {}, [dashText('kitchen')]), el('th', {}, [dashText('country')]), el('th', {}, [dashText('plan')]), el('th', {}, [dashText('status')]), el('th', {}, [dashText('credit')])])]),
          el('tbody', {}, events.length ? events.map(ev => el('tr', {}, [el('td', {}, [ev.kitchen || '—']), el('td', {}, [ev.country || market.label]), el('td', {}, [ev.plan || planDisplayName(plan)]), el('td', {}, [el('span', { class:'referralStatusBadge' }, [ev.status || '—'])]), el('td', {}, [ev.credit || '—'])])) : [el('tr', {}, [el('td', { colspan:'5', class:'referralEmptyState' }, [dashText('noReferrals')])])])
        ])])
      ]);
    }


    function referralPageCard(){
      const code = referralCodeForListing();
      const inviteLink = `${location.origin}/list?ref=${encodeURIComponent(code)}`;
      const shareText = `${dashText('shareInvite')} ${inviteLink}`;
      async function copyInvite(){
        try{ await navigator.clipboard?.writeText(inviteLink); alert(dashText('inviteLinkCopied')); }catch(_e){ alert(inviteLink); }
      }
      function emailInvite(){
        const subject = encodeURIComponent(dashText('inviteEmailSubject'));
        const body = encodeURIComponent(shareText);
        window.location.href = `mailto:?subject=${subject}&body=${body}`;
      }
      return el('div', { class:'container section narrow ownerReferralPage' }, [
        el('div', { class:'ownerReferralHeroPanel' }, [
          el('div', { class:'ownerReferralHeroCopy' }, [
            el('div', { class:'ownerDashKicker' }, [dashText('referralProgram')]),
            el('h2', {}, [dashText('referralHeadline')]),
            el('p', { class:'muted' }, [dashText('referralIntro')]),
            el('p', { class:'muted small referralExampleLine' }, [dashText('referralExample')])
          ]),
          el('div', { class:'ownerReferralHeroActions' }, [
            button(dashText('copyReferralLink'), { variant:'primary', onclick:copyInvite }),
            button(dashText('email'), { variant:'outline', onclick:emailInvite }),
            button(state.lang==='no' ? 'Tilbake til dashboard' : 'Back to dashboard', { variant:'outline', onclick:()=>selectOwnerTab('dashboard') })
          ])
        ]),
        referralDashboardCard()
      ]);
    }

    function cuisineChips(){
      const all = ownerCuisineChoices();
      const chosen = new Set(d.cuisines||[]);
      return el('div', { class:'row', style:'gap:8px; flex-wrap:wrap' }, all.map(c=>{
        const active = chosen.has(c.key);
        const label = c.label?.[state.lang] || c.label?.en || c.key;
        return el('button', {
          type:'button',
          class:'chip' + (active?' active':''),
          onclick: ()=>{
            if (active) chosen.delete(c.key); else chosen.add(c.key);
            d.cuisines = Array.from(chosen);
            render();
          }
        }, [label]);
      }));
    }

    function dishEditor(idx){
      const item = d.menu[idx] || (d.menu[idx] = {});
      if (!item.serves) item.serves = 'single';
      if (!item.title && (item.name?.en || item.name?.no)) item.title = (item.name?.[state.lang] || item.name?.en || item.name?.no || '');
      const img = (item.image || '').trim();

      const servesSelect = el('select',{class:'input', value:item.serves, onchange:(e)=>{ item.serves=e.target.value; render(); }},[
        el('option',{value:'single', selected:item.serves==='single'},[kitchenEditText('servesSingle')]),
        el('option',{value:'family', selected:item.serves==='family'},[kitchenEditText('servesFamily')]),
        el('option',{value:'group', selected:item.serves==='group'},[kitchenEditText('servesGroup')])
      ]);
      const sectionKey = String(item.menu_section_key || '').trim();
      const sectionSelect = el('select', { class:'input', value: sectionKey || '', onchange:(e)=>{
        item.menu_section_key = e.target.value;
        if (item.menu_section_key !== 'custom') item.menu_section_custom = '';
        render();
      } }, [
        el('option', { value:'', selected: !sectionKey }, [kitchenEditText('noHeading')]),
        ...MENU_SECTION_PRESETS.map(opt => el('option', { value:opt.key, selected:sectionKey===opt.key }, [opt.label?.[state.lang] || opt.label?.en || opt.key])),
        el('option', { value:'custom', selected:sectionKey==='custom' }, [kitchenEditText('customHeading')])
      ]);

      const clampPct = (v)=>Math.max(0, Math.min(100, Number(v)));
      const clampDishZoom = (v)=>Math.max(100, Math.min(200, Number(v)));
      if (item.image_focal_x==null || isNaN(Number(item.image_focal_x))) item.image_focal_x = 50;
      if (item.image_focal_y==null || isNaN(Number(item.image_focal_y))) item.image_focal_y = 50;
      if (item.image_zoom==null || isNaN(Number(item.image_zoom))) item.image_zoom = 120;
      const applyDishCropToGroup = (patch)=>{
        const groupKey = normalizeDishKey(item);
        (d.menu||[]).forEach((m)=>{
          if (normalizeDishKey(m) === groupKey){
            if (patch.image_focal_x !== undefined) m.image_focal_x = patch.image_focal_x;
            if (patch.image_focal_y !== undefined) m.image_focal_y = patch.image_focal_y;
            if (patch.image_zoom !== undefined) m.image_zoom = patch.image_zoom;
          }
        });
      };

      return el('div',{class:'card', style:'margin-bottom:12px'},[
        el('div',{class:'row', style:'gap:10px; align-items:flex-start; flex-wrap:wrap'},[
          el('div',{style:'flex:1; min-width:260px'},[
            field(kitchenEditText('dishName'), el('input',{class:'input', value:item.title||'', oninput:(e)=>{ item.title=e.target.value; }})),
            field(kitchenEditText('dishDescription'), el('div', {}, [
              el('textarea',{class:'input', rows:2, placeholder: state.lang==='no' ? 'F.eks. kremet grøt med kardemomme, kanel og topping.' : 'e.g. Creamy porridge with cardamom, cinnamon and toppings.', value:dishDescriptionText(item), oninput:(e)=>{ setDishDescriptionText(item, e.target.value); }}),
              el('div', { class:'muted small', style:'margin-top:6px' }, [kitchenEditText('dishDescriptionHint')])
            ])),
            el('div',{class:'row', style:'gap:10px; flex-wrap:wrap'},[
              el('div',{style:'width:160px'},[ field(kitchenEditText('serves'), servesSelect) ]),
              el('div',{style:'width:160px'},[ field(kitchenEditText('price'), el('input',{class:'input', value:String(item.price||''), oninput:(e)=>{ item.price = parseInt(e.target.value||'0',10) || 0; }})) ]),
            ]),
            field(kitchenEditText('menuSection'), el('div', {}, [
              sectionSelect,
              el('div', { class:'muted small', style:'margin-top:6px' }, [kitchenEditText('menuSectionHint')]),
              (item.menu_section_key==='custom'
                ? el('input', { class:'input', style:'margin-top:8px', placeholder: kitchenEditText('customHeadingPlaceholder'), value:item.menu_section_custom||'', oninput:(e)=>{ item.menu_section_custom = e.target.value; } })
                : null)
            ].filter(Boolean))),
            field(kitchenEditText('ingredients'), el('textarea',{class:'input', rows:3, value:item.ingredients||'', oninput:(e)=>{ item.ingredients=e.target.value; }})),
            (()=>{
              const currentImg = (item.image || '').trim();
              const thumb = currentImg
                ? el('div',{
                    class:'imgThumb',
                    style:`background-image:url(${assetUrl(currentImg)}); background-position:${clampPct(item.image_focal_x)}% ${clampPct(item.image_focal_y)}%; background-size:${clampDishZoom(item.image_zoom)}% auto; background-repeat:no-repeat; background-color:#f5f1ec;`
                  })
                : imagePlaceholder('imgThumb');
              const updateThumb = ()=>{
                if (!currentImg || !thumb || !thumb.style) return;
                thumb.style.backgroundPosition = `${clampPct(item.image_focal_x)}% ${clampPct(item.image_focal_y)}%`;
                thumb.style.backgroundSize = `${clampDishZoom(item.image_zoom)}% auto`;
              };
              const cropControls = (state.ui.editMode && currentImg) ? el('div', { class:'card', style:'margin-top:10px; padding:10px; background:#fffaf4' }, [
                el('div', { class:'muted small', style:'font-weight:700; margin-bottom:6px' }, [state.lang==='no' ? 'Bildeutsnitt' : 'Image crop']),
                el('div', { class:'muted small' }, [state.lang==='no' ? 'Venstre/høyre' : 'Left/right']),
                el('input', { type:'range', min:0, max:100, value:String(clampPct(item.image_focal_x)), class:'focalRange', oninput:(e)=>{
                  const v = clampPct(e.target.value||50);
                  applyDishCropToGroup({image_focal_x:v});
                  item.image_focal_x = v;
                  updateThumb();
                }}),
                el('div', { class:'muted small', style:'margin-top:8px' }, [state.lang==='no' ? 'Opp/ned' : 'Up/down']),
                el('input', { type:'range', min:0, max:100, value:String(clampPct(item.image_focal_y)), class:'focalRange', oninput:(e)=>{
                  const v = clampPct(e.target.value||50);
                  applyDishCropToGroup({image_focal_y:v});
                  item.image_focal_y = v;
                  updateThumb();
                }}),
                el('div', { class:'muted small', style:'margin-top:8px' }, ['Zoom']),
                el('input', { type:'range', min:100, max:200, value:String(clampDishZoom(item.image_zoom)), class:'focalRange', oninput:(e)=>{
                  const v = clampDishZoom(e.target.value||120);
                  applyDishCropToGroup({image_zoom:v});
                  item.image_zoom = v;
                  updateThumb();
                }}),
                el('div', { class:'row', style:'gap:8px; margin-top:8px; flex-wrap:wrap' }, [
                  button(state.lang==='no' ? 'Lagre bildeutsnitt' : 'Save crop', { variant:'primary', onclick: async ()=>{
                    applyDishCropToGroup({ image_focal_x: clampPct(item.image_focal_x), image_focal_y: clampPct(item.image_focal_y), image_zoom: clampDishZoom(item.image_zoom) });
                    await autoSaveAfterImageChange();
                  }}),
                  button(state.lang==='no' ? 'Nullstill' : 'Reset', { variant:'outline', onclick: async ()=>{
                    applyDishCropToGroup({ image_focal_x:50, image_focal_y:50, image_zoom:120 });
                    item.image_focal_x = 50;
                    item.image_focal_y = 50;
                    item.image_zoom = 120;
                    updateThumb();
                    await autoSaveAfterImageChange();
                    render();
                  }})
                ])
              ]) : null;
              return el('div',{class:'row', style:'gap:10px; margin-top:10px; align-items:flex-start; flex-wrap:wrap'},[
                thumb,
                el('div',{style:'flex:1; min-width:220px'},[
                  el('div',{class:'muted small'},[kitchenEditText('dishImage')]),
                  customImageFileInput(async (e)=>{
                    const f = e.target.files && e.target.files[0];
                    if (!f) return;
                    try{
                      const url = await uploadFor('dish', idx, f);
                      const groupKey = normalizeDishKey(item);
                      (d.menu||[]).forEach((m)=>{
                        if (normalizeDishKey(m) === groupKey){
                          m.image = url;
                          if (m.image_focal_x==null) m.image_focal_x = 50;
                          if (m.image_focal_y==null) m.image_focal_y = 50;
                          if (m.image_zoom==null) m.image_zoom = 120;
                        }
                      });
                      item.image = url;
                      render();
                      await autoSaveAfterImageChange();
                    }catch(err){ alert(kitchenEditText('uploadFailed') + ': ' + (err.message||err)); }
                  }),
                  currentImg ? button(state.lang==='no' ? 'Fjern bilde' : 'Remove image', { variant:'outline', onclick: async ()=>{
                    const groupKey = normalizeDishKey(item);
                    (d.menu||[]).forEach((m)=>{ if (normalizeDishKey(m) === groupKey) m.image = ''; });
                    item.image = '';
                    render();
                    await autoSaveAfterImageChange();
                  }}) : null,
                  cropControls,
                  el('div',{class:'muted small', style:'margin-top:6px'},[state.ui.editMode && currentImg
                    ? (state.lang==='no' ? 'Bruk sliderne når Edit Photos er på. Utsnittet brukes på kundesiden, kort og printverktøy.' : 'Use the sliders when Edit Photos is on. The crop is used on the public page, cards and print tools.')
                    : kitchenEditText('squareTip')
                  ])
                ].filter(Boolean))
              ]);
            })(),
            el('label', { class:'row', style:'gap:10px; align-items:center; margin-top:10px' }, [
              el('input', { type:'checkbox', checked: !!item.sold_out, onchange:(e)=>{ item.sold_out = !!e.target.checked; render(); } }),
              el('span', { class:'muted' }, [kitchenEditText('soldOut')])
            ])
          ]),
          el('div',{style:'min-width:140px'},[
            button(kitchenEditText('remove'),{variant:'outline', onclick:()=>{ d.menu.splice(idx,1); render(); }})
          ])
        ])
      ]);
    }

    function _scrollToSec(id){
      try{
        const n = document.getElementById(id);
        if (n) n.scrollIntoView({behavior:'smooth', block:'start'});
      }catch(_e){}
    }

    function onboardingCard(){
      const DEFAULT_HERO = 'assets/hero_fusion.jpg';
      const heroOk = !!(d.hero_image && String(d.hero_image).trim() && String(d.hero_image).trim() !== DEFAULT_HERO);
      const menuOk = ((d.menu||[]).filter(Boolean).length >= 3);
      const contactOk = !!(((d.contact||{}).whatsapp||'').trim() || ((d.contact||{}).phone||'').trim() || ((d.contact||{}).instagram||'').trim() || ((d.contact||{}).email||'').trim());
      const avail = d.availability || {};
      const availabilityOk = !!(
        ((avail.no||{}).deadline||'').trim() || ((avail.no||{}).window||'').trim() ||
        ((avail.en||{}).deadline||'').trim() || ((avail.en||{}).window||'').trim()
      );
      const slugOk = !!(String(d.slug||'').trim());

      const steps = [
        {
          key:'hero',
          done: heroOk,
          title: dashText('uploadHero'),
          hint: dashText('uploadHeroHint'),
          action: ()=>_scrollToSec('sec-images'),
          actionLabel: dashText('openImages')
        },
        {
          key:'menu',
          done: menuOk,
          title: dashText('addDishes'),
          hint: dashText('addDishesHint'),
          action: ()=>_scrollToSec('sec-menu'),
          actionLabel: dashText('openMenu')
        },
        {
          key:'contact',
          done: contactOk,
          title: dashText('addContact'),
          hint: dashText('addContactHint'),
          action: ()=>_scrollToSec('sec-listing'),
          actionLabel: dashText('openListing')
        },
        {
          key:'availability',
          done: availabilityOk,
          title: dashText('setAvailability'),
          hint: dashText('setAvailabilityHint'),
          action: ()=>_scrollToSec('sec-listing'),
          actionLabel: dashText('openListing')
        },
        {
          key:'slug',
          done: slugOk,
          title: dashText('saveShareLink'),
          hint: dashText('saveShareHint'),
          action: ()=>_scrollToSec('sec-public'),
          actionLabel: dashText('openLink')
        },
      ];

      const doneCount = steps.filter(s=>s.done).length;
      const total = steps.length;
      const pct = Math.round((doneCount/Math.max(1,total))*100);

      const row = (s)=>{
        return el('div',{class:'onboardRow'},[
          el('div',{class:'onboardLeft'},[
            el('div',{class:'onboardIcon ' + (s.done ? 'done' : 'todo')},[s.done ? '✓' : '•']),
            el('div',{},[
              el('div',{class:'onboardTitle'},[s.title]),
              el('div',{class:'muted small', style:'margin-top:2px'},[s.hint])
            ])
          ]),
          button(s.actionLabel,{variant: s.done ? 'ghost' : 'outline', onclick: s.action})
        ]);
      };

      return infoCard(dashText('quickStart'), [
        el('div',{class:'row', style:'justify-content:space-between; align-items:center; gap:10px; flex-wrap:wrap'},[
          el('div',{class:'muted'},[`${dashText('progress')}: ${doneCount}/${total}`]),
          el('div',{class:'muted small'},[pct + '%'])
        ]),
        el('div',{class:'onboardProg'},[
          el('div',{class:'onboardProgBar', style:`width:${pct}%`})
        ]),
        el('div',{class:'onboardList'}, steps.map(row))
      ]);
    }
    const currentPlanLevel = planLevel(listing?.plan || 'basic');
    const upgradeCard = (()=>{
      if (currentPlanLevel >= 3) return null;
      const upgradeRows = currentPlanLevel === 0
        ? [
            { name: 'Business', text: dashText('businessUpgrade') },
            { name: 'Growth', text: dashText('growthUpgrade') },
            { name: 'Pro', text: dashText('proUpgrade') }
          ]
        : currentPlanLevel === 1
          ? [
              { name: 'Growth', text: dashText('growthUpgrade2') },
              { name: 'Pro', text: dashText('proUpgrade2') }
            ]
          : [
              { name: 'Pro', text: dashText('proUpgrade3') }
            ];
      const title = currentPlanLevel === 0
        ? dashText('nextGrow')
        : currentPlanLevel === 1
          ? dashText('nextLevels')
          : dashText('nextPro');
      const intro = currentPlanLevel === 0
        ? dashText('basicIntro')
        : currentPlanLevel === 1
          ? dashText('businessIntro')
          : dashText('growthIntro');
      return infoCard(title, [
        el('div', { class:'muted' }, [intro]),
        el('div', { class:'upgradePathList' }, upgradeRows.map(r =>
          el('div', { class:'upgradePathItem' }, [
            el('div', { class:'upgradePathName' }, [r.name]),
            el('div', { class:'muted small' }, [r.text])
          ])
        )),
        el('div', { class:'row', style:'gap:10px; margin-top:12px; flex-wrap:wrap' }, [
          currentPlanLevel === 0 ? button(dashText('seeResults'), { variant:'outline', onclick: ()=>selectOwnerTab('results', { resultsTab:'accounting' }) }) : null,
          button(dashText('seePlans'), { variant:'primary', onclick: ()=>navigate('/pricing') }),
        ].filter(Boolean))
      ]);
    })();

