  function academyQuickLinks(current){
    const isNO = state.lang==='no';
    const prefix = current==='businesscoach' ? 'business-coach' : (current==='marketingcoach' ? 'marketing-coach' : 'masterclass');
    function jump(id){
      setTimeout(()=>{
        const node = document.getElementById(id);
        if (node && node.scrollIntoView) node.scrollIntoView({ behavior:'smooth', block:'start' });
      }, 10);
    }
    return el('div', { class:'academyQuickLinks', 'aria-label': ownerUi('academyShortcuts') }, [
      el('span', { class:'academyQuickLabel' }, [ownerUi('shortcutsLabel')]),
      el('button', { type:'button', class:'academyQuickBtn', onclick:()=>jump(prefix + '-coming-next') }, [ownerUi('comingNext')]),
      el('button', { type:'button', class:'academyQuickBtn', onclick:()=>jump(prefix + '-archive') }, [ownerUi('archive')])
    ]);
  }

