function pagePricing(){
  const yearly = state.billing === 'yearly';
  if (!state.marketCountry) state.marketCountry = 'NO';
  const selectedCountry = normalizeMarketCountry(state.marketCountry);
  const selectedMarket = marketForCountry(selectedCountry);
  const P = pricingText(state.lang);
  const planData = planTextData(state.lang);
  const prices = {
    basic: formatPlanPrice('basic', yearly ? 'yearly' : 'monthly', selectedCountry),
    business: formatPlanPrice('business', yearly ? 'yearly' : 'monthly', selectedCountry),
    growth: formatPlanPrice('growth', yearly ? 'yearly' : 'monthly', selectedCountry),
    pro: formatPlanPrice('pro', yearly ? 'yearly' : 'monthly', selectedCountry)
  };

  function setPricingCountry(country){ state.marketCountry = normalizeMarketCountry(country); render(); }

  function startPlanFromPricing(planKey){
    navigate('/list?plan=' + encodeURIComponent(normalizePlan(planKey)) + '&country=' + encodeURIComponent(selectedCountry));
    setTimeout(()=>document.getElementById('account-start')?.scrollIntoView({behavior:'smooth', block:'start'}), 80);
  }

  const planCard = (plan, cls='') => {
    const [key, name, intro, items, fit] = plan;
    return el('div', { class:'plan '+cls }, [
      key === 'growth' ? el('div', { class:'ribbon ribbon-plus pricingRibbon' }, [P.recommended]) : null,
      el('h2', {}, [name]),
      el('div', { class:'price' }, [prices[key]]),
      el('div', { class:'muted small', style:'margin-top:6px' }, [intro]),
      el('ul', { class:'bul' }, items.map(t => el('li', {}, [t]))),
      el('div', { class:'planFit' }, [fit]),
      button(P.choose + name, { onclick: ()=>startPlanFromPricing(key) })
    ]);
  };

  return el('div', { class:'container narrow section pricingPage' }, [
    el('section', { class:'pricingHero' }, [
      el('div', { class:'pricingEyebrow' }, [P.eyebrow]),
      el('h1', {}, [P.title]),
      el('p', { class:'lead' }, [P.lead]),
      el('p', { class:'pricingHeroText' }, [P.hero]),
      el('div', { class:'pricingHeroNote' }, [P.noPay]),
      el('div', { class:'pricingCountryCard' }, [
        el('div', { class:'pricingCountryHeader' }, [
          el('div', { class:'kicker' }, [P.countryBilling]),
          el('div', { class:'pricingCountryTitle' }, [P.based])
        ]),
        el('select', { class:'input pricingCountrySelect', value:selectedCountry, onchange:e=>setPricingCountry(e.target.value) }, RM24_MARKET_ORDER.map(code=>el('option', { value:code, selected: code === selectedCountry }, [marketNameLocalized(code, state.lang) + ' · ' + RM24_MARKETS[code].currency]))),
        el('p', { class:'muted small pricingCountryHelp' }, [P.countryHelp + ' ' + marketTaxCopy(selectedCountry)])
      ]),
      el('div', { class:'seg pricingSeg' }, [
        el('button', { class: 'segbtn' + (state.billing==='monthly'?' active':''), onclick: ()=>{ state.billing='monthly'; render(); } }, [P.monthly]),
        el('button', { class: 'segbtn' + (state.billing==='yearly'?' active':''), onclick: ()=>{ state.billing='yearly'; render(); } }, [P.yearly]),
        el('div', { class:'muted pricingSaveTxt' }, [P.yearlyPrice]),
      ])
    ]),
    el('div', { class:'pricing pricing-four' }, [
      planCard(planData[0]),
      planCard(planData[1], 'plan-premium'),
      planCard(planData[2], 'plan-plus'),
      planCard(planData[3], 'plan-plus')
    ]),
    el('div', { class:'teaser', style:'margin-top:18px' }, [
      el('h2', {}, [P.taxTitle]),
      el('p', { class:'muted' }, [P.selectedMarket + selectedMarket.label + ' · ' + selectedMarket.currency + ' · ' + selectedMarket.taxLabel + '. ' + marketTaxCopy(selectedCountry)]),
      el('p', { class:'muted small' }, [P.checkoutNote])
    ]),
    el('div', { class:'teaser', style:'margin-top:18px' }, [
      el('h2', {}, [P.note]),
      el('p', { class:'muted' }, [P.samePages]),
    ])
  ]);
}

function pageHow(){
  return el('div', { class:'container section' }, [
    el('h1', {}, [state.lang==='no' ? 'Slik fungerer det' : 'How it works']),
    el('p', { class:'lead' }, [state.lang==='no' ? 'Fra meny til kunder — på få minutter.' : 'From menu to customers — in minutes.' ]),
    el('div', { class:'steps' }, [
      el('div', { class:'step' }, [
        el('div', { class:'step-title' }, [state.lang==='no' ? 'For kunder' : 'For customers']),
        el('div', { class:'muted' }, [state.lang==='no' ? 'Søk → filtrer → kontakt kjøkkenet direkte.' : 'Search → filter → contact the kitchen directly.' ])
      ]),
      el('div', { class:'step' }, [
        el('div', { class:'step-title' }, [state.lang==='no' ? 'For lokale kjøkken' : 'For local kitchens']),
        el('div', { class:'muted' }, [state.lang==='no' ? 'Fyll skjema → legg inn retter → publiser → få forespørsler.' : 'Fill form → add dishes → publish → get requests.' ])
      ]),
      el('div', { class:'step' }, [
        el('div', { class:'step-title' }, [state.lang==='no' ? 'Hva vi ikke gjør' : 'What we don’t do']),
        el('div', { class:'muted' }, [state.lang==='no' ? 'Ingen betaling på nettsiden. Vi er ikke part i avtalen.' : 'No payments on the site. We are not part of the agreement.' ])
      ]),
    ]),
    el('div', { class:'row', style:'margin-top:14px' }, [
      button(state.lang==='no' ? 'Registrer kjøkken' : 'Create your page', { onclick: ()=>navigate('/list') })
    ])
  ]);
}


