function marketTaxLabelLocalized(country, lang){
  const market = marketForCountry(country);
  const incl = {
    en:'incl. VAT', no:'inkl. mva', sv:'inkl. moms', da:'inkl. moms', fi:'sis. ALV', pt:'IVA incluído', fr:'TVA incluse', es:'IVA incluido', nl:'incl. btw', de:'inkl. MwSt.'
  };
  const sales = {
    en:'+ sales tax where applicable', no:'+ sales tax der det gjelder', sv:'+ sales tax där det gäller', da:'+ sales tax hvor relevant', fi:'+ sales tax tarvittaessa', pt:'+ sales tax quando aplicável', fr:'+ sales tax le cas échéant', es:'+ sales tax cuando corresponda', nl:'+ sales tax waar van toepassing', de:'+ Sales Tax falls zutreffend'
  };
  return market.currency === 'USD' ? (sales[lang] || sales.en) : (incl[lang] || incl.en);
}

