async function loadCuisines(){
  const data = await apiGet('/api/cuisines');
  state.cuisines = data.cuisines;
}

async function loadMapListings(){
  // Airbnb-style map: show ALL live kitchens (optionally filtered by cuisine).
  // NOTE: We intentionally do NOT include the free-text q filter here.
  const params = new URLSearchParams();
  if (state.filters.cuisine) params.set('cuisine', state.filters.cuisine);
  if (state.filters.has_group) params.set('has_group', 'true');
  if (state.filters.has_family) params.set('has_family', 'true');

  try{
    const data = await apiGet(`/api/map/listings?${params.toString()}`);
    state.mapListings = (data && data.items) ? data.items : [];
  }catch(e){
    // Don't break the UI; map can fall back to list-based pins.
    console.error('loadMapListings failed', e);
  }
}



function isLocationSearchActive(){
  return !!((state.ui && state.ui.gps && state.ui.gps.active) || (state.ui && state.ui.near && state.ui.near.active));
}

async function showAllKitchens(opts={}){
  state.filters.q = '';
  state.ui.gps = { active:false, lat:null, lng:null };
  state.ui.near = { active:false, label:'', lat:null, lng:null };
  state.ui.emptyNote = '';
  await loadListings({ indicate: opts.indicate !== false, scroll: opts.scroll !== false, source:'all' });
}

async function useMyLocation(){
  if (!navigator.geolocation) {
    state.ui.emptyNote = state.lang==='no'
      ? 'Nettleseren støtter ikke GPS-søk.'
      : 'Your browser does not support location search.';
    render();
    return;
  }
  state.ui.locating = true;
  state.ui.searching = true;
  render();

  navigator.geolocation.getCurrentPosition(async (pos)=>{
    const lat = pos && pos.coords ? pos.coords.latitude : null;
    const lng = pos && pos.coords ? pos.coords.longitude : null;
    if (lat == null || lng == null) {
      state.ui.locating = false;
      state.ui.searching = false;
      state.ui.emptyNote = state.lang==='no' ? 'Fant ikke posisjonen din.' : 'Could not find your location.';
      render();
      return;
    }
    state.filters.q = '';
    state.ui.gps = { active:true, lat, lng };
    await loadListings({ indicate:false, source:'gps' });
    state.ui.locating = false;
    state.ui.searching = false;
    render();
    setTimeout(()=>{
      const r = document.getElementById('results');
      if (r && r.scrollIntoView) {
        try{ r.scrollIntoView({ behavior:'smooth', block:'start' }); } catch(e){ try{ r.scrollIntoView(true); }catch(_){} }
      }
    }, 40);
  }, ()=>{
    state.ui.locating = false;
    state.ui.searching = false;
    state.ui.gps = { active:false, lat:null, lng:null };
    state.ui.near = { active:false, label:'', lat:null, lng:null };
    state.ui.emptyNote = state.lang==='no'
      ? 'GPS-søk ble ikke aktivert. Gi nettleseren tilgang til posisjon og prøv igjen.'
      : 'Location search was not enabled. Allow location access in your browser and try again.';
    render();
  }, { enableHighAccuracy:false, timeout:10000, maximumAge:300000 });
}

async function loadListings(opts={}){
  const params = new URLSearchParams();
  const qRaw = (state.filters.q || '').trim();
  if (qRaw) params.set('q', qRaw);
  if (state.filters.cuisine) params.set('cuisine', state.filters.cuisine);
  if (state.filters.has_group) params.set('has_group', 'true');
  if (state.filters.has_family) params.set('has_family', 'true');

  if (opts.indicate){
    state.ui.searching = true;
    render();
  }

  // tiny delay so the loading state is visible (makes the button feel real)
  if (opts.indicate) await new Promise(r=>setTimeout(r, 350));

  // If the user searched a place (city/postcode), try geocoding it.
  // If the user chooses GPS, use the browser coordinates instead.
  // Important: Norwegian postcodes (4 digits) are ambiguous globally, so we default them to country=no.
  const paramsText = new URLSearchParams(params.toString()); // includes q
  state.ui.near = state.ui.near || { active:false, label:'', lat:null, lng:null };
  state.ui.gps = state.ui.gps || { active:false, lat:null, lng:null };
  state.ui.emptyNote = '';

  let geo = null;
  const gpsActive = !!(state.ui.gps.active && state.ui.gps.lat != null && state.ui.gps.lng != null && !qRaw);
  if (!gpsActive && qRaw) {
    const isNoPostcode = /^[0-9]{4}$/.test(qRaw);
    const geoUrl = isNoPostcode
      ? `/api/geocode?q=${encodeURIComponent(qRaw)}&country=no`
      : `/api/geocode?q=${encodeURIComponent(qRaw)}`;
    try {
      const g = await apiGet(geoUrl);
      if (g && g.ok) geo = g;
    } catch(e) {
      geo = null;
    }
  }

  if (gpsActive) {
    params.delete('q');
    params.set('lat', state.ui.gps.lat);
    params.set('lng', state.ui.gps.lng);
    params.set('radius_km', '20050');
    state.ui.near.active = true;
    state.ui.near.label = state.lang==='no' ? 'din posisjon' : 'your location';
    state.ui.near.lat = state.ui.gps.lat;
    state.ui.near.lng = state.ui.gps.lng;
  } else if (geo) {
    params.delete('q');
    params.set('lat', geo.lat);
    params.set('lng', geo.lng);
    params.set('radius_km', '20050');
    state.ui.near.active = true;
    state.ui.near.label = geo.display_name || qRaw;
    state.ui.near.lat = geo.lat;
    state.ui.near.lng = geo.lng;
  } else {
    state.ui.near.active = false;
    state.ui.near.label = '';
    state.ui.near.lat = null;
    state.ui.near.lng = null;
  }

  // Fetch listings. Location/GPS mode uses a broad radius so users see the nearest kitchens first,
  // but can still scroll farther results without refreshing or clearing the page manually.
  let data = await apiGet(`/api/listings?${params.toString()}`);
  if ((geo || gpsActive) && data && Array.isArray(data.items) && data.items.length === 0) {
    try {
      const wideParams = new URLSearchParams(params.toString());
      wideParams.set('radius_km', '20050');
      const data2 = await apiGet(`/api/listings?${wideParams.toString()}`);
      if (data2 && Array.isArray(data2.items) && data2.items.length > 0) {
        data = data2;
        state.ui.near.active = true;
        state.ui.near.label = gpsActive ? (state.lang==='no' ? 'din posisjon' : 'your location') : (geo.display_name || qRaw);
        state.ui.near.lat = gpsActive ? state.ui.gps.lat : geo.lat;
        state.ui.near.lng = gpsActive ? state.ui.gps.lng : geo.lng;
        state.ui.emptyNote = gpsActive
          ? (state.lang==='no'
              ? 'Ingen kjøkken nær posisjonen din ennå. Viser nærmeste tilgjengelige kjøkken.'
              : 'No kitchens near your location yet. Showing the nearest available kitchens.')
          : (state.lang==='no'
              ? `Ingen kjøkken i "${qRaw}" ennå. Viser nærmeste tilgjengelige kjøkken.`
              : `No kitchens in "${qRaw}" yet. Showing the nearest available kitchens.`
            );
      } else {
        const data3 = await apiGet(`/api/listings?${paramsText.toString()}`);
        data = data3;
        state.ui.near.active = false;
        state.ui.near.label = '';
        state.ui.near.lat = null;
        state.ui.near.lng = null;
        state.ui.emptyNote = gpsActive
          ? (state.lang==='no' ? 'Fant ingen kjøkken nær posisjonen din.' : 'No kitchens found near your location.')
          : (state.lang==='no'
              ? `Fant ingen nær "${qRaw}". Viser derfor teksttreff i stedet.`
              : `No results near "${qRaw}". Showing text matches instead.`
            );
      }
    } catch(e) {
      // keep empty results
    }
  }

  state.listings = (data && data.items) ? data.items : [];

  // Keep map pins up-to-date with filters (Airbnb-style map shows all live kitchens).
  // (Does not include free-text q.)
  loadMapListings();

  // Map pins refresh is fire-and-forget; never block page rendering.

  state.ui.searching = false;
  render();

  if (opts.scroll){
    setTimeout(()=>{
      const elr = document.getElementById('results');
      if (elr) elr.scrollIntoView({ behavior:'smooth', block:'start' });
    }, 80);
  }
}

