async function loadAdminKitchenView(listingId, expectedSlug){
  const id = Number(listingId || 0);
  const slug = String(expectedSlug || '').trim();
  if (!Number.isInteger(id) || id <= 0 || !slug) throw new Error('Invalid kitchen identifier');

  // Bind this asynchronous response to the exact route that started it. A slower
  // request from a previously opened kitchen must never overwrite the newer view.
  const viewKey = `admin:${id}:${slug}`;
  const requestPath = `/admin-view/${encodeURIComponent(String(id))}/${encodeURIComponent(slug)}`;
  state.preview.viewKey = viewKey;
  const data = await apiGet(adminUrl(`/api/admin/listings/${id}/view-as?slug=${encodeURIComponent(slug)}`), { cache: 'no-store' });

  const routeStillMatches = location.pathname === requestPath;
  if (state.preview.viewKey !== viewKey || !routeStillMatches) return;

  const listing = data && data.listing;
  const returnedId = Number(data?.listing_id);
  const listingIdFromPayload = Number(listing?.id);
  const returnedSlug = String(listing?.slug || '').trim();
  if (!data || !listing || returnedId !== id || listingIdFromPayload !== id || returnedSlug !== slug) {
    throw new Error('Could not verify the selected kitchen');
  }
  const token = String(data.preview_token || '').trim();
  if (!token) throw new Error('Could not prepare this kitchen dashboard');

  state.preview.token = token;
  state.preview.active = true;
  state.preview.adminView = true;
  state.preview.adminListingId = id;
  state.preview.adminListingSlug = slug;
  state.preview.viewKey = viewKey;
  state.preview.err = null;
  state.__route_err = null;
  state.currentListing = listing;
  render();
}

function setLang(lang){
  state.lang = lang;
  try{ localStorage.setItem('ricemap24_lang', lang); }catch(_e){}
  render();
}

function sharePage(){
  if (navigator.share){
    navigator.share({ title: document.title, url: location.href }).catch(()=>{});
  } else {
    navigator.clipboard?.writeText(location.href);
    alert(state.lang==='no' ? 'Lenke kopiert' : 'Link copied');
  }
}

function copyOrderMessage(listing){
  // If user has an order draft for this cook, copy a detailed order message.
  // Otherwise copy a simple template.
  try { ensureOrderForCook(listing); } catch(e) {}
  const od = state.orderDraft || {};
  const hasDraft = od && od.cookSlug === listing.slug && Array.isArray(od.items) && od.items.length;

  const msg = hasDraft
    ? makeOrderMessage(listing)
    : (state.lang==='no'
        ? 'Hei! Jeg fant deg på RiceMap24. Jeg ønsker [rett/pakke] for [dato]. Kan jeg hente, eller kan du levere? Hvordan ønsker du betaling?'
        : 'Hi! I found you on RiceMap24. I’d like [dish/set] for [date]. Is pickup possible, or delivery? What payment method do you prefer?');

  copyToClipboard(
    msg,
    state.lang==='no'
      ? 'Kopiert! Lim inn i WhatsApp eller Instagram.'
      : 'Copied! Paste into WhatsApp or Instagram.'
  );
}


function setOwnerDashboardToken(token){
  const t = String(token || '').trim();
  if (!t) return;
  try { localStorage.setItem('rm_owner_dashboard_token', t); } catch(_) {}
  if (!state.ui) state.ui = {};
  state.ui.ownerDashboardToken = t;
}

function getOwnerDashboardToken(){
  if (state.ui && state.ui.ownerDashboardToken) return state.ui.ownerDashboardToken;
  try {
    const t = localStorage.getItem('rm_owner_dashboard_token') || '';
    if (t && state.ui) state.ui.ownerDashboardToken = t;
    return t;
  } catch(_) { return ''; }
}

function setOwnerSessionLocal(active){
  try {
    if (active) localStorage.setItem('rm_owner_session_active', '1');
    else localStorage.removeItem('rm_owner_session_active');
  } catch(_) {}
  if (!state.ui) state.ui = {};
  state.ui.ownerSessionActive = !!active;
}

function hasOwnerSessionLocal(){
  if (state.ui && state.ui.ownerSessionActive) return true;
  try {
    const v = localStorage.getItem('rm_owner_session_active') || '';
    if (v === '1') {
      if (state.ui) state.ui.ownerSessionActive = true;
      return true;
    }
  } catch(_) {}
  return false;
}

function currentOwnerTokenFromRoute(){
  const parts = (location.pathname || '/').split('/').filter(Boolean);
  if (parts[0] === 'p' && parts[1]) return decodeURIComponent(parts[1]);
  return '';
}

function ownerDashboardPath(){
  // Prefer verified owner session, but also treat the active /p/<token> owner
  // dashboard route as owner context. This prevents the header from showing
  // "Log in" while the kitchen owner is already inside the dashboard.
  const od = state.auth && state.auth.authenticated ? state.auth.owner_dashboard : null;
  const sessionToken = od && (od.preview_token || (od.path || '').split('/p/')[1]);
  const routeToken = currentOwnerTokenFromRoute();
  const localToken = hasOwnerSessionLocal() ? getOwnerDashboardToken() : '';
  const token = sessionToken || routeToken || localToken;
  return token ? ('/p/' + encodeURIComponent(token)) : '';
}

function isOwnerContext(){
  if (isOwnerLoggedIn()) return true;
  if (currentOwnerTokenFromRoute()) return true;
  if (hasOwnerSessionLocal() && getOwnerDashboardToken()) return true;
  return false;
}

function isAnyUserLoggedIn(){
  return !!((state.auth && state.auth.authenticated) || (state.admin && state.admin.authenticated));
}

async function logoutCurrentSession(redirectPath='/'){
  try { await apiJson('POST', '/api/auth/logout', {}); } catch(_) {}
  state.auth.checked = true;
  state.auth.authenticated = false;
  state.auth.user = null;
  state.auth.owner_dashboard = null;
  state.auth.loginPassword = '';
  state.auth.error = '';
  state.admin.authenticated = false;
  state.admin.authUser = null;
  state.admin.items._loadedOnce = false;
  try {
    localStorage.removeItem('rm_owner_dashboard_token');
    localStorage.removeItem('rm_owner_token');
    localStorage.removeItem('rm_preview_token');
    localStorage.removeItem('rm_owner_session_active');
  } catch(_) {}
  if (state.ui) {
    state.ui.ownerDashboardToken = '';
    state.ui.ownerSessionActive = false;
  }
  navigate(redirectPath);
}

async function logoutFromTopbar(){
  await logoutCurrentSession('/');
}

function applyAuthData(data){
  state.auth.checked = true;
  state.auth.authenticated = !!(data && data.authenticated);
  state.auth.user = (data && data.user) || null;
  state.auth.owner_dashboard = (data && data.owner_dashboard) || null;
  const od = state.auth.owner_dashboard;
  if (od && od.preview_token) {
    setOwnerDashboardToken(od.preview_token);
    setOwnerSessionLocal(true);
  }
}

async function refreshAuth(){
  try{
    const data = await apiGet('/api/auth/me', { timeoutMs: 6000 });
    applyAuthData(data);
  }catch(e){
    state.auth.checked = true;
    state.auth.authenticated = false;
    state.auth.user = null;
    state.auth.owner_dashboard = null;
  }
}

function isOwnerLoggedIn(){
  return !!(state.auth && state.auth.authenticated && state.auth.owner_dashboard);
}

async function ownerLogout(){
  await logoutCurrentSession('/login');
}

function navigate(path){
  history.pushState({}, '', path);
  onRoute();
  // Always jump to top on navigation (better UX for long lists).
  scrollToTop();
}

function onRoute(){
  const path = location.pathname;
  const parts = path.split('/').filter(Boolean);

  if (parts.length===0) {
    // portal
    render();
    return;
  }

  // Reset preview flag unless we're in preview route
  if (!(parts[0] === 'p' && parts[1])) {
    state.preview.active = false;
    state.preview.token = null;
  }

  if (parts[0] === 'c' && parts[1]){
    // Keep an already-loaded/list-card version visible while the full kitchen payload loads.
    // This reduces the visible blink when moving from Explore to a kitchen page.
    const slug = parts[1];
    const existing = (state.currentListing && state.currentListing.slug === slug)
      ? state.currentListing
      : ((state.listings || []).find(x => x && x.slug === slug) || null);
    state.currentListing = existing;
    render();
    loadListing(slug).catch((e)=>{
      console.error(e);
      // keep pageNotFound view instead of blank
      state.currentListing = null;
      state.preview.err = null;
      state.__route_err = (e && e.message) ? e.message : String(e);
      render();
    });
    return;
  }

  if (parts[0] === 'admin-view' && parts[1] && parts[2]){
    // Admin inspection uses the immutable listing id plus the canonical kitchen slug.
    // The server verifies that both belong to the same row before any dashboard is shown.
    const listingId = Number(decodeURIComponent(parts[1]));
    const expectedSlug = decodeURIComponent(parts[2]);
    state.preview.active = true;
    state.preview.adminView = true;
    state.preview.adminListingId = listingId;
    state.preview.adminListingSlug = expectedSlug;
    state.preview.viewKey = `admin:${listingId}:${expectedSlug}`;
    state.preview.token = null;
    state.preview.err = null;
    state.currentListing = null;
    render();

    loadAdminKitchenView(listingId, expectedSlug).catch((e)=>{
      console.error(e);
      state.preview.err = (e && e.message) ? e.message : String(e);
      render();
    });
    return;
  }

  if (parts[0] === 'admin-view'){
    state.preview.active = true;
    state.preview.adminView = true;
    state.preview.err = 'This admin kitchen link is incomplete.';
    state.currentListing = null;
    render();
    return;
  }

  if (parts[0] === 'p' && parts[1]){
    // Normal owner dashboard route, identified by its dashboard token.
    const token = decodeURIComponent(parts[1]);
    state.preview.adminView = false;
    state.preview.adminListingId = null;
    setOwnerDashboardToken(token);
    setOwnerSessionLocal(true);
    state.preview.active = true;
    state.preview.token = token;
    state.preview.err = null;
    state.currentListing = null;
    render();

    loadPreview(token).catch((e)=>{
      console.error(e);
      state.preview.err = (e && e.message) ? e.message : String(e);
      render();
    });
    return;
  }

  // simple pages
  render();
}


function resetPayState(){
  state.pay = { loading:false, done:false, ok:null, data:null, err:null };
}

function pagePaySuccess(){
  const sid = new URLSearchParams(location.search).get('session_id');
  if (!sid){
    return el('div',{class:'container section'},[
      el('div',{class:'card'},[
        el('h1',{class:'h2'},[state.lang==='no'?'Betaling':'Payment']),
        el('p',{class:'muted'},[state.lang==='no'?'Mangler session_id i URL-en.':'Missing session_id in URL.']),
        el('div',{class:'row'},[
          el('button',{class:'btn', onclick:()=>navigate('/list')},[t('ui.back')])
        ])
      ])
    ]);
  }

  if (!state.pay.loading && !state.pay.done){
    state.pay.loading = true;
    state.pay.err = null;
    apiGet(`/api/billing/confirm?session_id=${encodeURIComponent(sid)}`).then((data)=>{
      state.pay.loading = false;
      state.pay.done = true;
      state.pay.ok = true;
      state.pay.data = data;
      render();
    }).catch((e)=>{
      state.pay.loading = false;
      state.pay.done = true;
      state.pay.ok = false;
      state.pay.err = (e && e.message) ? e.message : String(e);
      render();
    });
  }

  const loading = state.pay.loading;
  const ok = state.pay.ok;
  const slug = state.pay.data ? state.pay.data.slug : null;

  return el('div',{class:'container section'},[
    el('div',{class:'card'},[
      el('h1',{class:'h2'},[state.lang==='no'?'Betaling fullført':'Payment completed']),
      loading ? el('p',{class:'muted'},[state.lang==='no'?'Bekrefter betaling og aktiverer…':'Confirming payment and activating…']) : null,
      (!loading && ok) ? el('p',{class:'muted'},[state.lang==='no'?'Siden din er aktivert.':'Your page is now active.']) : null,
      (!loading && ok && slug) ? el('div',{class:'row'},[
        el('button',{class:'btn primary', onclick:()=>navigate(`/c/${slug}`)},[state.lang==='no'?'Åpne siden':'Open page']),
        el('button',{class:'btn ghost', onclick:()=>navigate('/')},[t('ui.backToPortal')])
      ]) : null,

      (!loading && ok && !slug) ? el('div',{class:'row'},[
        el('button',{class:'btn', onclick:()=>navigate('/list')},[t('ui.back')])
      ]) : null,

      (!loading && ok===false) ? el('div',{},[
        el('p',{class:'muted'},[(state.lang==='no'?'Kunne ikke bekrefte betaling: ':'Could not confirm payment: ') + (state.pay.err||'')]),
        el('div',{class:'row'},[
          el('button',{class:'btn', onclick:()=>{ resetPayState(); render(); }},[state.lang==='no'?'Prøv igjen':'Try again']),
          el('button',{class:'btn ghost', onclick:()=>navigate('/list')},[t('ui.back')])
        ])
      ]) : null,
    ])
  ]);
}

function pagePayCancel(){
  resetPayState();
  return el('div',{class:'container section'},[
    el('div',{class:'card'},[
      el('h1',{class:'h2'},[state.lang==='no'?'Betaling avbrutt':'Payment canceled']),
      el('p',{class:'muted'},[state.lang==='no'?'Du avbrøt betalingen. Du kan prøve igjen når som helst.':'You canceled the checkout. You can try again anytime.']),
      el('div',{class:'row'},[
        el('button',{class:'btn', onclick:()=>navigate('/list')},[t('ui.backToOnboarding')]),
        el('button',{class:'btn ghost', onclick:()=>navigate('/')},[t('ui.backToPortal')])
      ])
    ])
  ]);
}


