function routeView(){
  const path = location.pathname;
  const parts = path.split('/').filter(Boolean);

  if (parts.length===0) return pagePortal();

  if (parts[0] === 'c' && parts[1]){
    if (!state.currentListing) {
      const err = state.__route_err;
      if (err){
        return el('div',{class:'container section'},[
          el('div',{class:'card'},[
            el('h1',{class:'h2'},[state.lang==='no'?'Kunne ikke laste siden':'Could not load page']),
            el('p',{class:'muted'},[String(err)]),
            el('div',{class:'row', style:'gap:10px; flex-wrap:wrap'},[
              button(t('ui.backToPortal'),{onclick:()=>navigate('/')})
            ])
          ])
        ]);
      }
      return el('div', { class:'container section' }, [el('div', { class:'muted' }, [state.lang==='no'?'Laster…':'Loading…'])]);
    }
    return pageCook(state.currentListing);
  }

  if ((parts[0] === 'p' && parts[1]) || (parts[0] === 'admin-view' && parts[1] && parts[2])){
    if (!state.currentListing) {
      const err = state.preview && state.preview.err;
      if (err){
        return el('div',{class:'container section'},[
          el('div',{class:'card'},[
            el('h1',{class:'h2'},[state.lang==='no'?'Forhåndsvisning ble ikke funnet':'Preview not found']),
            el('p',{class:'muted'},[String(err)]),
            el('div',{class:'row', style:'gap:10px; flex-wrap:wrap'},[
              button(state.lang==='no'?'Åpne portalen':'Open directory',{variant:'outline', onclick:()=>navigate('/')})
            ])
          ])
        ]);
      }
      return el('div', { class:'container section' }, [el('div', { class:'muted' }, [state.lang==='no'?'Laster forhåndsvisning…':'Loading preview…'])]);
    }
    return pagePreviewCook(state.currentListing, (parts[0] === 'admin-view' ? state.preview.token : parts[1]));
  }

  if (parts[0] === 'login') return pageLogin();

  if (parts[0] === 'pay' && parts[1] === 'success') return pagePaySuccess();
  if (parts[0] === 'pay' && parts[1] === 'cancel') return pagePayCancel();

  if (parts[0] === 'for-cooks') return pageForCooks();
  if (parts[0] === 'pricing') return pagePricing();
  if (parts[0] === 'how-it-works') return pageHow();
  if (parts[0] === 'list') return pageList();
  if (parts[0] === 'admin') return pageAdmin();
  if (parts[0] === 'example') return el('div', {}, [pageCook(state.currentListing || findExample())]);

  return pageNotFound();
}

