async function ownerUpdateSettings(token, patch={}){
  // MVP: listing settings (currently currency)
  const r = await fetch(`/api/owner/${encodeURIComponent(token)}/settings`, {
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body: JSON.stringify(patch||{})
  });
  if(!r.ok){
    const j = await r.json().catch(()=>null);
    throw new Error(j?.detail || ('HTTP '+r.status));
  }
  return await r.json();
}

async function ownerSaveDishCrop(token, dishKey, focalX, focalY, zoom){
  // Owner-only: patch a dish image crop (zoom + focal X/Y) without overwriting other unsaved edits.
  const payload = {
    dish_key: String(dishKey||'').trim(),
    image_focal_x: Number(focalX),
    image_focal_y: Number(focalY),
    image_zoom: Number(zoom),
  };
  if(!payload.dish_key) throw new Error('Missing dish_key');
  await apiJson('POST', `/api/owner/${encodeURIComponent(token)}/dish_crop`, payload);
  // Refresh preview listing so thumbnails and modal reflect saved crop.
  if (state.preview && state.preview.active && state.preview.token && String(state.preview.token)===String(token)){
    state.currentListing = await apiGet(`/api/preview/${encodeURIComponent(token)}`);
    render();
  }
}

async function ownerLoadCustomers(token){
  const o = _ensureOwnerState(token);
  // Don't block customer refresh just because we're saving another action.
  // Use a dedicated flag so the list can reload after a successful add.
  if (o.loadingCustomers) return;
  o.loadingCustomers = true;
  o.error = '';
  render();
  try{
    const data = await apiGet(`/api/owner/${encodeURIComponent(token)}/customers`);
    o.items = data.items || [];
    o.loaded = true;
  }catch(e){
    o.error = e?.message || String(e);
    o.loaded = true;
    if (String(o.error || '').toLowerCase().includes('forbidden') || String(o.error || '').includes('403')){
      o.customerForbidden = true;
    }
  }
  o.loadingCustomers = false;
  render();
}

async function ownerAddCustomer(token){
  const o = _ensureOwnerState(token);
  const payload = {
    name: (o.newCustomer.name||'').trim(),
    org_no: (o.newCustomer.org_no||'').trim(),
    phone: (o.newCustomer.phone||'').trim(),
    email: (o.newCustomer.email||'').trim(),
    tags: (o.newCustomer.tags||'').trim(),
    notes: (o.newCustomer.notes||'').trim(),
  };
  if (!payload.name){
    alert(state.lang==='no' ? 'Navn er påkrevd (telefon/e-post er valgfritt).' : 'Name is required (phone/email optional).');
    return;
  }
  o.loading = true;
  o.error = '';
  o.notice = kitchenEditText('saving');
  render();
  try{
    await apiJson('POST', `/api/owner/${encodeURIComponent(token)}/customers`, payload);
    o.newCustomer = { name:'', org_no:'', phone:'', email:'', tags:'', notes:'' };
    // Show the newest item (and avoid confusion if filters were active)
    o.customerSearch = '';
    o.customerTagFilter = '';
    o.customerPage = 1;
    // Release the button state before reloading, otherwise reload was blocked.
    o.loading = false;
    await ownerLoadCustomers(token);
    o.notice = state.lang==='no' ? 'Kunde lagt til ✅' : 'Customer added ✅';
    // Auto-clear the notice
    setTimeout(()=>{
      const oo = _ensureOwnerState(token);
      if (oo.notice && (oo.notice.includes('✅'))){ oo.notice=''; render(); }
    }, 1200);
  }catch(e){
    o.error = e?.message || String(e);
    o.loading = false;
    o.notice = '';
    render();
    // Make sure the user *sees* errors even if they miss the red text.
    try{ alert(o.error); }catch(_){ }
  }
  // Always re-enable Add button.
  o.loading = false;
  render();
}

async function ownerSaveCustomer(token, id, fields){
  const o = _ensureOwnerState(token);
  o.loading = true;
  o.error = '';
  render();
  try{
    await apiJson('PUT', `/api/owner/${encodeURIComponent(token)}/customers/${id}`, fields);
    o.editingId = null;
    await ownerLoadCustomers(token);
  }catch(e){
    o.error = e?.message || String(e);
    o.loading = false;
    render();
  }
}

async function ownerDeleteCustomer(token, id){
  if (!confirm(state.lang==='no' ? 'Slette kunden?' : 'Delete this customer?')) return;
  const o = _ensureOwnerState(token);
  o.loading = true;
  o.error = '';
  render();
  try{
    await apiJson('DELETE', `/api/owner/${encodeURIComponent(token)}/customers/${id}`, {});
    o.editingId = null;
    await ownerLoadCustomers(token);
  }catch(e){
    o.error = e?.message || String(e);
    o.loading = false;
    render();
  }
}



