function ownerRecipeLibraryCard(token, listing){
  const isNO = state.lang==='no';
  const tr = (key, params)=>{
    if (typeof ownerToolsText === 'function') return ownerToolsText(key, params);
    return ownerRecipeLibraryFallbackText(key, params);
  };
  const plan = String(listing?.plan || 'basic').toLowerCase();
  const level = ((['growth','pro'].includes(normalizePlan(plan)))) ? 2 : (normalizePlan(plan)==='business') ? 1 : 0;

  const title = tr('recipeTitle');

  const desc = tr('recipeDesc');

  const note = (level===0)
    ? tr('recipeNoteBasic')
    : (level===1)
      ? tr('recipeNoteBusiness')
      : tr('recipeNoteGrowth');

  const header = el('div', { class:'muted' }, [desc]);
  const info = el('div', { class:'muted small', style:'margin-top:8px' }, [note]);

  const search = el('input', { class:'input', placeholder: tr('searchRecipes'), value: state.recipes.q || '', oninput:(e)=>{ state.recipes.q = e.target.value; render(); } });

  const listWrap = el('div', { style:'margin-top:10px' }, []);

  function paintList(){
    listWrap.innerHTML = '';
    if (!state.recipes.loaded && !state.recipes.loading){
      listWrap.appendChild(button(tr('loadLibrary'), { className:'btn-load-library', onclick: ()=>loadOwnerRecipes(token) }));
      return;
    }
    if (state.recipes.loading){
      listWrap.appendChild(el('div', { class:'muted small' }, [ownerUi('loading')]));
      return;
    }

    if (state.recipes.error){
      listWrap.appendChild(el('div', { class:'errorBox', style:'margin-top:8px' }, [state.recipes.error]));
    }

    let items = _filterRecipes(state.recipes.items || [], state.recipes.q || '');
    items = _filterRecipesByCat(items, state.recipes.cat || 'all');
    const qNow = String(state.recipes.q||'').trim();
    const isAll = (String(state.recipes.cat||'all')==='all');
    const top = items;
    const sectionOrder = ['mains','sides','handhelds','drinks','desserts'];
    const sectionLabel = {
      mains: tr('mains'),
      sides: tr('sides'),
      handhelds: tr('handhelds'),
      drinks: tr('drinks'),
      desserts: tr('desserts')
    };

    const row = (it)=>{
      const locked = !!it.locked;
      const badge = locked ? tr('browseOnly') : (!it.strategy_unlocked && level===1 ? tr('recipeCombos') : tr('fullAccess'));
      return el('div', {
        class:'recipeRow'+(locked?' locked':''),
        title: locked ? tr('basicLockedTip') : '',
        onclick:()=>{
          if(locked) return;
          openRecipeModal(token, it.id);
        }
      }, [
        el('div', { class:'recipeRowMain' }, [
          el('div', { class:'recipeRowTitle' }, [it.title || it.id]),
          it.teaser ? el('div', { class:'muted small' }, [String(it.teaser).slice(0,120)]) : null,
        ].filter(Boolean)),
        el('div', { class:'pill smallPill' }, [badge])
      ]);
    };

    if (!top.length){
      listWrap.appendChild(el('div', { class:'muted small' }, [tr('noMatches')]));
      return;
    }

    
    listWrap.appendChild(el('div', { class:'muted small', style:'margin-bottom:8px' }, [
      tr('showingOf', { shown: top.length, total: items.length })
    ]));

    // If no category filter + no search, present like a restaurant menu (sections)
    if (isAll && !qNow){
      const byCat = {};
      (items||[]).forEach(it=>{
        const c = _recipeCategory(it);
        (byCat[c] = byCat[c] || []).push(it);
      });
      sectionOrder.forEach(cat=>{
        const arr = (byCat[cat]||[]);
        if (!arr.length) return;
        const show = arr.slice(0, 12);
        listWrap.appendChild(el('div', { class:'recipeSection' }, [
          el('div', { class:'recipeSectionHead' }, [
            el('div', { class:'recipeSectionTitle' }, [sectionLabel[cat] || cat]),
            el('div', { class:'muted small' }, [`${arr.length} ${tr('pieces')}`]),
          ]),
          el('div', { class:'recipeList' }, show.map(row)),
        ]));
      });
      return;
    }

    // Otherwise show a simple list (category filtered and/or searched)
    listWrap.appendChild(el('div', { class:'recipeList' }, top.map(row)));

  }

  paintList();

  // Build category pills dynamically to avoid empty tabs.
  const allItems = state.recipes.items || [];
  const catCounts = { mains:0, sides:0, handhelds:0, drinks:0, desserts:0 };
  allItems.forEach(it=>{
    const c = _recipeCategory(it);
    if (catCounts[c] != null) catCounts[c] += 1;
  });

  const cats = [
    { id:'all', label: tr('all'), show:true },
    { id:'mains', label: tr('mains'), show: catCounts.mains>0 },
    { id:'sides', label: tr('sides'), show: catCounts.sides>0 },
    { id:'handhelds', label: tr('handhelds'), show: catCounts.handhelds>0 },
    { id:'drinks', label: tr('drinks'), show: catCounts.drinks>0 },
    { id:'desserts', label: tr('desserts'), show: catCounts.desserts>0 },
  ].filter(x=>x.show);

  // If current selection points to a now-hidden category, reset to all.
  if (!cats.find(c=>c.id===String(state.recipes.cat||'all'))){
    state.recipes.cat = 'all';
  }
  const catBar = el('div', { class:'recipeCats', style:'margin-top:10px' }, [
    ...cats.map(c=>{
      const active = String(state.recipes.cat||'all')===c.id;
      return el('button', { class:'pillBtn'+(active?' active':''), onclick:(e)=>{ e.preventDefault(); state.recipes.cat=c.id; render(); } }, [c.label]);
    })
  ]);

  const content = [header, info, catBar, el('div',{style:'margin-top:10px'},[search]), listWrap];

  // Use toolCard wrapper like other premium tools, but keep visible for all plans
  return toolCard(title, content, 'tool-recipes');
}


