  function notificationsContent(){
    const all = state.admin.notifications || [];
    const status = state.admin.notificationStatus || 'all';
    const type = state.admin.notificationType || 'all';
    const q = String(state.admin.notificationQ || '').toLowerCase().trim();
    const rows = all.filter(n => {
      if (status !== 'all' && String(n.status||'queued') !== status) return false;
      if (type !== 'all' && String(n.notification_type||'') !== type) return false;
      if (q){
        const hay = [n.subject,n.body,n.recipient_email,n.listing_name,n.listing_customer_no,n.notification_type].join(' ').toLowerCase();
        if (!hay.includes(q)) return false;
      }
      return true;
    });
    const counts = all.reduce((acc,n)=>{ const k=String(n.status||'queued'); acc[k]=(acc[k]||0)+1; return acc; },{});
    const types = Array.from(new Set(all.map(n=>String(n.notification_type||'general')).filter(Boolean))).sort();
    function row(n){
      const statusCls = n.status==='sent' ? 'tag-ok' : (n.status==='queued' ? 'tag-warn' : '');
      return el('div',{class:'adminNotificationRow'},[
        el('div',{class:'adminNotificationMain'},[
          el('div',{class:'row',style:'gap:8px; flex-wrap:wrap'},[
            el('strong',{},[n.subject || '(no subject)']),
            el('span',{class:'tag'},[n.notification_type || 'general']),
            el('span',{class:'tag '+statusCls},[n.status || 'queued'])
          ]),
          el('div',{class:'muted small'},[(n.recipient_type || 'admin') + (n.recipient_email ? ' · ' + n.recipient_email : '') + (n.created_at ? ' · ' + n.created_at : '')]),
          n.listing_name ? el('div',{class:'muted small'},[(n.listing_customer_no ? n.listing_customer_no + ' · ' : '') + n.listing_name]) : null,
          (n.details && (n.details.reason || n.details.monthly_theme || n.details.email_kind)) ? el('div',{class:'muted small'},[
            (n.details.reason ? ((state.lang==='no'?'Grunn: ':'Reason: ') + n.details.reason) : ''),
            (n.details.monthly_theme ? (' · ' + (state.lang==='no'?'Tema: ':'Theme: ') + n.details.monthly_theme) : ''),
            (n.details.email_kind ? (' · ' + n.details.email_kind) : '')
          ]) : null,
          n.body ? el('p',{class:'adminNotificationBody'},[n.body]) : null
        ].filter(Boolean)),
        el('div',{class:'adminNotificationActions'},[
          n.ticket_id ? button(state.lang==='no'?'Åpne ticket':'Open ticket',{variant:'outline',onclick:()=>{ state.admin.tab='tickets'; loadTicketDetail(n.ticket_id); }}) : null,
          n.listing_id ? button(state.lang==='no'?'View as':'View as',{variant:'outline',onclick:()=>{ const it=(state.admin.items.all||[]).find(x=>Number(x.id)===Number(n.listing_id)); if(it) viewAsKitchen(it); }}) : null,
          String(n.status||'queued')==='queued' ? button(state.lang==='no'?'Send nå':'Send now',{variant:'primary',onclick:()=>sendNotificationNow(n.id)}) : null,
          button(state.lang==='no'?'Marker sendt':'Mark sent',{variant:'outline',onclick:()=>updateNotificationStatus(n.id,'sent')}),
          button(state.lang==='no'?'Hopp over':'Skip',{variant:'outline',onclick:()=>updateNotificationStatus(n.id,'skipped')})
        ].filter(Boolean))
      ]);
    }
    return el('div',{class:'adminPanel adminNotificationsPanel'},[
      el('div',{class:'adminPanelHead'},[
        el('div',{},[
          el('h2',{},[state.lang==='no'?'Varsler / e-postkø':'Notifications / email queue']),
          el('p',{class:'muted'},[state.lang==='no'
            ? 'Varselkø for support, tilgang og betaling. Manual-modus markerer som sendt; SMTP/SendGrid/Postmark kan sende når server-secrets er satt.'
            : 'Notification queue for support, access and billing. Manual mode marks as sent; SMTP/SendGrid/Postmark can send when server secrets are set.'])
        ]),
        el('div',{class:'adminToolbar',style:'justify-content:flex-end'},[
          button(state.lang==='no'?'Lag trial-utløpsvarsler':'Generate trial-expiry notices',{variant:'outline',onclick:generateTrialExpiryNotifications}),
          button(state.lang==='no'?'Send filtrerte':'Send filtered',{variant:'primary',onclick:()=>sendNotificationsBatch(rows)})
        ])
      ]),
      el('div',{class:'adminNotificationStats'},[
        el('span',{},['Queued: '+(counts.queued||0)]),
        el('span',{},['Sent: '+(counts.sent||0)]),
        el('span',{},['Skipped: '+(counts.skipped||0)]),
        el('span',{},['Error: '+(counts.error||0)])
      ]),
      el('div',{class:'adminToolbar'},[
        el('select',{class:'input',value:status,onchange:e=>{state.admin.notificationStatus=e.target.value; render();}},[
          el('option',{value:'all',selected:status==='all'},['All statuses']),
          el('option',{value:'queued',selected:status==='queued'},['Queued']),
          el('option',{value:'sent',selected:status==='sent'},['Sent']),
          el('option',{value:'skipped',selected:status==='skipped'},['Skipped']),
          el('option',{value:'error',selected:status==='error'},['Error'])
        ]),
        el('select',{class:'input',value:type,onchange:e=>{state.admin.notificationType=e.target.value; render();}},[
          el('option',{value:'all',selected:type==='all'},['All types']),
          ...types.map(t=>el('option',{value:t,selected:type===t},[t]))
        ]),
        el('input',{class:'input adminSearchInput',placeholder:state.lang==='no'?'Søk varsler':'Search notifications',value:state.admin.notificationQ||'',oninput:e=>{state.admin.notificationQ=e.target.value; render();}}),
        button(state.lang==='no'?'Send alle i kø':'Send all queued',{variant:'outline',onclick:()=>sendNotificationsBatch(all)})
      ]),
      !rows.length ? el('div',{class:'adminEmpty'},[state.lang==='no'?'Ingen varsler.':'No notifications.']) : null,
      el('div',{class:'adminNotificationList'},rows.map(row))
    ]);
  }

  function ticketPill(t){
    const cls = t==='closed' ? 'tag' : (t==='pending' ? 'tag tag-warn' : 'tag tag-ok');
    return el('span',{class:cls},[t||'open']);
  }


  function businessBuilderAdminContent(){
    const all = (state.admin.tickets || []).filter(t=>String(t.category||'')==='business_builder');
    const open = all.filter(t=>String(t.status||'open')!=='closed');
    const paid = all.filter(t=>String(t.builder_payment_status||'')==='paid');
    const pendingPayment = all.filter(t=>['offer_sent','payment_pending','payment_plan'].includes(String(t.builder_payment_status||'')));
    const stages = [
      ['new_request', state.lang==='no'?'Ny henvendelse':'New request'],
      ['reviewed', state.lang==='no'?'Vurdert':'Reviewed'],
      ['recommendation_sent', state.lang==='no'?'Anbefaling sendt':'Recommendation sent'],
      ['payment_pending', state.lang==='no'?'Venter på betaling':'Payment pending'],
      ['paid', state.lang==='no'?'Betalt':'Paid'],
      ['session_1_booked', state.lang==='no'?'Første møte booket':'Session 1 booked'],
      ['in_progress', state.lang==='no'?'Pågår':'In progress'],
      ['strategy_delivered', state.lang==='no'?'Strategi levert':'Strategy delivered'],
      ['follow_up_completed', state.lang==='no'?'Oppfølging ferdig':'Follow-up completed'],
      ['closed', state.lang==='no'?'Avsluttet':'Closed']
    ];
    const label = (v)=> (stages.find(x=>x[0]===v)||stages[0])[1];
    const byStage = all.reduce((acc,t)=>{ const k=String(t.builder_stage||'new_request'); acc[k]=(acc[k]||0)+1; return acc; },{});
    const openTicket = (t)=>{ state.admin.tab='tickets'; state.admin.ticketCategory='business_builder'; state.admin.ticketStatus='all'; state.admin.selectedTicketId=t.id; loadTicketDetail(t.id); };
    const stat = (title,value,help)=>el('div',{class:'adminStatCard'},[el('strong',{},[String(value)]),el('span',{},[title]),help?el('small',{},[help]):null].filter(Boolean));
    const row = (t)=>el('button',{type:'button',class:'adminTicketRow',onclick:()=>openTicket(t)},[
      el('div',{},[
        el('strong',{},['#'+t.id+' · '+(t.listing_name || t.subject || 'Business Builder')]),
        el('span',{class:'muted small'},[((t.listing_customer_no||'') ? t.listing_customer_no+' · ' : '')+(t.subject||'Business Builder intake')+' · '+(t.updated_at||'')])
      ]),
      el('div',{class:'adminTicketRowMeta'},[
        el('span',{class:'tag tag-builder'},[label(t.builder_stage||'new_request')]),
        t.builder_recommended_plan ? el('span',{class:'tag'},[String(t.builder_recommended_plan).replaceAll('_',' ')]) : null,
        t.builder_payment_status ? el('span',{class:'tag'},[String(t.builder_payment_status).replaceAll('_',' ')]) : null,
        ticketPill(t.status)
      ].filter(Boolean))
    ]);
    const bbTemplates = state.lang==='no' ? [
      ['BB: mottatt henvendelse', 'Hei! Takk for Business Builder-henvendelsen. Jeg har mottatt skjemaet og går nå gjennom kjøkkensiden, målene, kapasiteten og hvilken retning som virker mest relevant for kjøkkenet ditt. Business Builder er en betalt coachingtjeneste der vi jobber strategisk med home kitchen-businessen din: konsept, synlighet, posisjonering, målgrupper, salg, drift og praktiske vekststeg. Neste steg er at jeg sender en kort anbefaling, riktig plan og betalingsinformasjon før coachingprosessen starter.'],
      ['BB: anbefaler Home Kitchen', 'Hei! Jeg har vurdert henvendelsen og kjøkkensiden din. Basert på det du ønsker å oppnå, anbefaler jeg Home Kitchen Growth Plan. Dette passer best når hovedmålet er å bygge en tydeligere lokal home kitchen-business, få bedre retning, bli mer synlig, styrke konseptet og skape en mer strukturert vei mot flere riktige kunder. Pris: $[amount]. Betaling kan gjøres fullt eller som 3 månedlige betalinger. Når betaling er bekreftet, starter vi coachingprosessen.'],
      ['BB: anbefaler B2B', 'Hei! Jeg har vurdert henvendelsen og kjøkkensiden din. Basert på målene dine anbefaler jeg B2B Growth Plan. Dette passer best når du ønsker å rette kjøkkenet mer profesjonelt mot bedriftsmarkedet, for eksempel kontorer, team, arrangementer eller faste lunsj-/cateringmuligheter. Vi jobber med strategi, posisjonering, salgsretning, målrettet markedsføring og en mer profesjonell plan for å nå relevante bedrifter. Pris: $[amount]. Betaling kan gjøres fullt eller som 3 månedlige betalinger. Når betaling er bekreftet, starter vi coachingprosessen.'],
      ['BB: betalingsinfo', 'Hei! Her er betalingsinformasjonen for Business Builder. Anbefalt plan: [Home Kitchen Growth Plan / B2B Growth Plan]. Pris: $[amount]. Du kan betale hele beløpet nå, eller dele det i 3 månedlige betalinger. Når betalingen er bekreftet, sender jeg forslag til tidspunkt for første coaching-samtale og starter forberedelsen basert på kjøkkensiden din og svarene i skjemaet.'],
      ['BB: betaling registrert', 'Hei! Betalingen er registrert. Neste steg er første coaching-samtale. Jeg sender deg forslag til tidspunkt, og bruker kjøkkensiden din, skjemaet og målene dine som grunnlag for forberedelsen. I første samtale jobber vi med retning, prioriteringer og hva som bør være de viktigste strategiske grepene videre.'],
      ['BB: trenger litt mer info', 'Hei! Takk for henvendelsen. Før jeg anbefaler riktig Business Builder-plan, trenger jeg litt mer informasjon: [skriv hva som mangler]. Når jeg har dette, kan jeg vurdere om Home Kitchen Growth Plan eller B2B Growth Plan passer best.'],
      ['BB: gratisressurser først', 'Hei! Jeg har sett på henvendelsen og kjøkkensiden din. Min vurdering er at det kan være best å starte med ressursene du allerede har i RiceMap24 før du kjøper Business Builder. Bruk først Business Academy, relevante coach-/masterclass-ressurser og de praktiske verktøyene i appen for å styrke grunnlaget. Når kjøkkensiden, menyen og salgsretningen er litt tydeligere, kan Business Builder gi mer verdi.'],
      ['BB: ikke riktig nå', 'Hei! Takk for at du sendte inn Business Builder-skjemaet. Etter å ha sett på henvendelsen vurderer jeg at Business Builder ikke er riktig neste steg akkurat nå. Dette betyr ikke at kjøkkenet ditt ikke har potensial, men at du trolig bør jobbe mer med grunnlaget først. Jeg anbefaler at du starter med [konkret anbefaling], og eventuelt sender inn en ny henvendelse senere.']
    ] : [
      ['BB: request received', 'Hi! Thank you for your Business Builder request. I have received the form and will now review your kitchen page, goals, capacity and which direction seems most relevant for your kitchen. Business Builder is a paid coaching service where we work strategically with your home kitchen business: concept, visibility, positioning, target customers, sales, operations and practical growth steps. The next step is that I send a short recommendation, the right plan and payment information before the coaching process starts.'],
      ['BB: recommend Home Kitchen', 'Hi! I have reviewed your request and kitchen page. Based on what you want to achieve, I recommend the Home Kitchen Growth Plan. This is best when the main goal is to build a clearer local home kitchen business, get stronger direction, become more visible, strengthen the concept and create a more structured path toward the right customers. Price: $[amount]. Payment can be made in full or as 3 monthly payments. Once payment is confirmed, we start the coaching process.'],
      ['BB: recommend B2B', 'Hi! I have reviewed your request and kitchen page. Based on your goals, I recommend the B2B Growth Plan. This is best when you want to position your kitchen more professionally toward the business market, such as offices, teams, events or recurring lunch/catering opportunities. We work with strategy, positioning, sales direction, targeted marketing and a more professional plan for reaching relevant businesses. Price: $[amount]. Payment can be made in full or as 3 monthly payments. Once payment is confirmed, we start the coaching process.'],
      ['BB: payment info', 'Hi! Here is the payment information for Business Builder. Recommended plan: [Home Kitchen Growth Plan / B2B Growth Plan]. Price: $[amount]. You can pay the full amount now, or split it into 3 monthly payments. Once payment is confirmed, I will send suggested times for the first coaching session and start preparing based on your kitchen page and form answers.'],
      ['BB: payment registered', 'Hi! The payment has been registered. The next step is the first coaching session. I will send you suggested times and use your kitchen page, form answers and goals as the basis for preparation. In the first session, we will work on direction, priorities and the most important strategic steps forward.'],
      ['BB: need more info', 'Hi! Thank you for the request. Before I recommend the right Business Builder plan, I need a little more information: [write what is missing]. Once I have this, I can assess whether the Home Kitchen Growth Plan or the B2B Growth Plan is the best fit.'],
      ['BB: free resources first', 'Hi! I have reviewed your request and kitchen page. My assessment is that it may be better to start with the resources you already have in RiceMap24 before buying Business Builder. First use Business Academy, relevant coach/masterclass resources and the practical tools in the app to strengthen the foundation. When the kitchen page, menu and sales direction are clearer, Business Builder can give more value.'],
      ['BB: not a fit now', 'Hi! Thank you for submitting the Business Builder form. After reviewing the request, I do not think Business Builder is the right next step right now. This does not mean that your kitchen lacks potential, but that you should probably strengthen the foundation first. I recommend starting with [specific recommendation], and you can send a new request later.']
    ];
    const templatePreview = el('div',{class:'adminBuilderTemplateBox'},[
      el('div',{class:'adminBuilderTemplateHead'},[
        el('div',{},[
          el('h3',{},[state.lang==='no'?'Business Builder-svarmaler':'Business Builder reply templates']),
          el('p',{class:'muted'},[state.lang==='no'?'Disse kan leses og kopieres også før det finnes en konkret Business Builder-sak. Når du åpner en sak, kan malene settes direkte inn i svarfeltet.':'These can be reviewed and copied even before a Business Builder case exists. When you open a case, the templates can be inserted directly into the reply field.'])
        ])
      ]),
      el('div',{class:'adminBuilderTemplateGrid'},bbTemplates.map(([title,txt])=>el('div',{class:'adminBuilderTemplateCard'},[
        el('div',{class:'adminBuilderTemplateTitle'},[title]),
        el('p',{},[txt]),
        button(state.lang==='no'?'Kopier mal':'Copy template',{variant:'outline',className:'btn-small',onclick:()=>copyToClipboard(txt,state.lang==='no'?'Svarmal kopiert.':'Template copied.')})
      ])))
    ]);
    return el('div',{class:'adminPanel adminBuilderAdminPage'},[
      el('div',{class:'adminPanelHead'},[
        el('div',{},[
          el('h2',{},['RiceMap24 Business Builder']),
          el('p',{class:'muted'},[state.lang==='no'
            ? 'Egen oversikt for betalt coaching. Her ser du Business Builder-henvendelser, status, betaling og neste oppfølging. Åpne en sak for å redigere status, anbefalt plan, betaling, interne notater og svarmaler.'
            : 'Dedicated overview for paid coaching. Track Business Builder requests, stage, payment and follow-up. Open a case to edit stage, recommended plan, payment, internal notes and reply templates.'])
        ]),
        el('div',{class:'adminToolbar',style:'justify-content:flex-end'},[
          button(state.lang==='no'?'Åpne support-filter':'Open support filter',{variant:'outline',onclick:()=>{state.admin.tab='tickets';state.admin.ticketCategory='business_builder';render();}})
        ])
      ]),
      el('div',{class:'adminStatsGrid'},[
        stat(state.lang==='no'?'Åpne Business Builder-saker':'Open Business Builder cases',open.length,state.lang==='no'?'Ikke lukket':'Not closed'),
        stat(state.lang==='no'?'Tilbud/betaling venter':'Offer/payment pending',pendingPayment.length,''),
        stat(state.lang==='no'?'Betalt':'Paid',paid.length,''),
        stat(state.lang==='no'?'Totalt':'Total',all.length,'')
      ]),
      el('div',{class:'adminBuilderWorkflowBox'},[
        el('strong',{},[state.lang==='no'?'Standard arbeidsflyt':'Standard workflow']),
        el('ol',{},[
          el('li',{},[state.lang==='no'?'Les skjema og kjøkkenside. Ikke gi full analyse gratis.':'Review form and kitchen page. Do not give the full analysis for free.']),
          el('li',{},[state.lang==='no'?'Send kort bekreftelse innen 24 timer.':'Send a short confirmation within 24 hours.']),
          el('li',{},[state.lang==='no'?'Vurder Home Kitchen Growth Plan, B2B Growth Plan, gratisressurser først eller avslag.':'Assess Home Kitchen Growth Plan, B2B Growth Plan, free resources first or not a fit.']),
          el('li',{},[state.lang==='no'?'Send anbefaling, pris og betalingsinformasjon.':'Send recommendation, price and payment information.']),
          el('li',{},[state.lang==='no'?'Start coaching først etter bekreftet betaling.':'Start coaching only after confirmed payment.'])
        ])
      ]),
      el('div',{class:'adminBuilderStageStrip'},stages.map(([v,l])=>el('button',{type:'button',class:'adminTicketStat',onclick:()=>{state.admin.tab='tickets';state.admin.ticketCategory='business_builder';state.admin.ticketQ=v;render();}},[
        el('strong',{},[String(byStage[v]||0)]),el('span',{},[l])
      ]))),
      templatePreview,
      el('h3',{},[state.lang==='no'?'Business Builder-saker':'Business Builder cases']),
      !all.length ? el('div',{class:'adminEmpty'},[state.lang==='no'?'Ingen Business Builder-saker ennå. Når en aktør sender skjemaet, dukker saken opp her.':'No Business Builder cases yet. When a kitchen submits the form, the case appears here.']) : el('div',{class:'adminTicketList'},all.map(row))
    ]);
  }

  function ticketsContent(){
    const allTickets = state.admin.tickets || [];
    const status = state.admin.ticketStatus || 'all';
    const priority = state.admin.ticketPriority || 'all';
    const category = state.admin.ticketCategory || 'all';
    const q = String(state.admin.ticketQ || '').trim().toLowerCase();
    const counts = allTickets.reduce((acc,t)=>{ const k=String(t.status||'open'); acc[k]=(acc[k]||0)+1; return acc; },{});
    const highCount = allTickets.filter(t=>String(t.priority||'normal')==='high' && String(t.status||'open')!=='closed').length;
    const categories = Array.from(new Set(allTickets.map(t=>String(t.category||'general')).filter(Boolean))).sort();
    let tickets = allTickets.slice();
    if (status !== 'all') tickets = tickets.filter(t=>String(t.status||'open')===status);
    if (priority !== 'all') tickets = tickets.filter(t=>String(t.priority||'normal')===priority);
    if (category !== 'all') tickets = tickets.filter(t=>String(t.category||'general')===category);
    if (q){
      tickets = tickets.filter(t=>[
        t.id, t.subject, t.body, t.status, t.priority, t.category,
        t.listing_customer_no, t.listing_name, t.listing_slug, t.updated_at
      ].join(' ').toLowerCase().includes(q));
    }
    const selected = state.admin.selectedTicket;
    const selectedListing = selected ? (state.admin.items.all||[]).find(i=>String(i.id)===String(selected.listing_id)) : null;
    const isBuilderTicket = selected && String(selected.category||'') === 'business_builder';
    const builderStages = [
      ['new_request', state.lang==='no'?'Ny henvendelse':'New request'],
      ['reviewed', state.lang==='no'?'Vurdert':'Reviewed'],
      ['recommendation_sent', state.lang==='no'?'Anbefaling sendt':'Recommendation sent'],
      ['payment_pending', state.lang==='no'?'Venter på betaling':'Payment pending'],
      ['paid', state.lang==='no'?'Betalt':'Paid'],
      ['session_1_booked', state.lang==='no'?'Første møte booket':'Session 1 booked'],
      ['in_progress', state.lang==='no'?'Pågår':'In progress'],
      ['strategy_delivered', state.lang==='no'?'Strategi levert':'Strategy delivered'],
      ['follow_up_completed', state.lang==='no'?'Oppfølging ferdig':'Follow-up completed'],
      ['closed', state.lang==='no'?'Avsluttet':'Closed']
    ];
    const builderPayments = [
      ['', state.lang==='no'?'Ikke satt':'Not set'],
      ['not_sent', state.lang==='no'?'Ikke sendt':'Not sent'],
      ['offer_sent', state.lang==='no'?'Tilbud sendt':'Offer sent'],
      ['payment_pending', state.lang==='no'?'Venter på betaling':'Payment pending'],
      ['paid', state.lang==='no'?'Betalt fullt':'Paid in full'],
      ['payment_plan', state.lang==='no'?'3 mnd avbetaling':'3-month payment plan'],
      ['cancelled', state.lang==='no'?'Avbrutt':'Cancelled']
    ];
    const builderStageLabel = (value)=> (builderStages.find(x=>x[0]===value)||builderStages[0])[1];
    const insertTemplate = (txt)=>{ state.admin.ticketReply = (String(state.admin.ticketReply||'').trim() ? (state.admin.ticketReply.trim() + '\n\n') : '') + txt; render(); };
    const templates = state.lang==='no' ? [
      ['Takk – vi sjekker','Hei! Takk for meldingen. Jeg sjekker dette og kommer tilbake så snart jeg har funnet ut av det.'],
      ['Trenger mer info','Hei! Kan du sende litt mer informasjon, gjerne skjermbilde og hva du gjorde rett før dette skjedde?'],
      ['Løst','Hei! Dette skal nå være rettet. Prøv å oppdatere siden og gi beskjed hvis det fortsatt ikke fungerer.']
    ] : [
      ['Thanks – checking','Hi! Thanks for the message. I will check this and get back to you as soon as I have found the cause.'],
      ['Need more info','Hi! Could you send a bit more information, preferably a screenshot and what you did right before this happened?'],
      ['Resolved','Hi! This should now be fixed. Please refresh the page and let me know if it still does not work.']
    ];
    if (isBuilderTicket){
      templates.push(...(state.lang==='no' ? [
        ['BB: mottatt henvendelse', 'Hei! Takk for Business Builder-henvendelsen. Jeg har mottatt skjemaet og går nå gjennom kjøkkensiden, målene, kapasiteten og hvilken retning som virker mest relevant for kjøkkenet ditt. Business Builder er en betalt coachingtjeneste der vi jobber strategisk med home kitchen-businessen din: konsept, synlighet, posisjonering, målgrupper, salg, drift og praktiske vekststeg. Neste steg er at jeg sender en kort anbefaling, riktig plan og betalingsinformasjon før coachingprosessen starter.'],
        ['BB: anbefaler Home Kitchen', 'Hei! Jeg har vurdert henvendelsen og kjøkkensiden din. Basert på det du ønsker å oppnå, anbefaler jeg Home Kitchen Growth Plan. Dette passer best når hovedmålet er å bygge en tydeligere lokal home kitchen-business, få bedre retning, bli mer synlig, styrke konseptet og skape en mer strukturert vei mot flere riktige kunder. Pris: $[amount]. Betaling kan gjøres fullt eller som 3 månedlige betalinger. Når betaling er bekreftet, starter vi coachingprosessen.'],
        ['BB: anbefaler B2B', 'Hei! Jeg har vurdert henvendelsen og kjøkkensiden din. Basert på målene dine anbefaler jeg B2B Growth Plan. Dette passer best når du ønsker å rette kjøkkenet mer profesjonelt mot bedriftsmarkedet, for eksempel kontorer, team, arrangementer eller faste lunsj-/cateringmuligheter. Vi jobber med strategi, posisjonering, salgsretning, målrettet markedsføring og en mer profesjonell plan for å nå relevante bedrifter. Pris: $[amount]. Betaling kan gjøres fullt eller som 3 månedlige betalinger. Når betaling er bekreftet, starter vi coachingprosessen.'],
        ['BB: betalingsinfo', 'Hei! Her er betalingsinformasjonen for Business Builder. Anbefalt plan: [Home Kitchen Growth Plan / B2B Growth Plan]. Pris: $[amount]. Du kan betale hele beløpet nå, eller dele det i 3 månedlige betalinger. Når betalingen er bekreftet, sender jeg forslag til tidspunkt for første coaching-samtale og starter forberedelsen basert på kjøkkensiden din og svarene i skjemaet.'],
        ['BB: betaling registrert', 'Hei! Betalingen er registrert. Neste steg er første coaching-samtale. Jeg sender deg forslag til tidspunkt, og bruker kjøkkensiden din, skjemaet og målene dine som grunnlag for forberedelsen. I første samtale jobber vi med retning, prioriteringer og hva som bør være de viktigste strategiske grepene videre.'],
        ['BB: trenger litt mer info', 'Hei! Takk for henvendelsen. Før jeg anbefaler riktig Business Builder-plan, trenger jeg litt mer informasjon: [skriv hva som mangler]. Når jeg har dette, kan jeg vurdere om Home Kitchen Growth Plan eller B2B Growth Plan passer best.'],
        ['BB: gratisressurser først', 'Hei! Jeg har sett på henvendelsen og kjøkkensiden din. Min vurdering er at det kan være best å starte med ressursene du allerede har i RiceMap24 før du kjøper Business Builder. Bruk først Business Academy, relevante coach-/masterclass-ressurser og de praktiske verktøyene i appen for å styrke grunnlaget. Når kjøkkensiden, menyen og salgsretningen er litt tydeligere, kan Business Builder gi mer verdi.'],
        ['BB: ikke riktig nå', 'Hei! Takk for at du sendte inn Business Builder-skjemaet. Etter å ha sett på henvendelsen vurderer jeg at Business Builder ikke er riktig neste steg akkurat nå. Dette betyr ikke at kjøkkenet ditt ikke har potensial, men at du trolig bør jobbe mer med grunnlaget først. Jeg anbefaler at du starter med [konkret anbefaling], og eventuelt sender inn en ny henvendelse senere.']
      ] : [
        ['BB: request received', 'Hi! Thank you for your Business Builder request. I have received the form and will now review your kitchen page, goals, capacity and which direction seems most relevant for your kitchen. Business Builder is a paid coaching service where we work strategically with your home kitchen business: concept, visibility, positioning, target customers, sales, operations and practical growth steps. The next step is that I send a short recommendation, the right plan and payment information before the coaching process starts.'],
        ['BB: recommend Home Kitchen', 'Hi! I have reviewed your request and kitchen page. Based on what you want to achieve, I recommend the Home Kitchen Growth Plan. This is best when the main goal is to build a clearer local home kitchen business, get stronger direction, become more visible, strengthen the concept and create a more structured path toward the right customers. Price: $[amount]. Payment can be made in full or as 3 monthly payments. Once payment is confirmed, we start the coaching process.'],
        ['BB: recommend B2B', 'Hi! I have reviewed your request and kitchen page. Based on your goals, I recommend the B2B Growth Plan. This is best when you want to position your kitchen more professionally toward the business market, such as offices, teams, events or recurring lunch/catering opportunities. We work with strategy, positioning, sales direction, targeted marketing and a more professional plan for reaching relevant businesses. Price: $[amount]. Payment can be made in full or as 3 monthly payments. Once payment is confirmed, we start the coaching process.'],
        ['BB: payment info', 'Hi! Here is the payment information for Business Builder. Recommended plan: [Home Kitchen Growth Plan / B2B Growth Plan]. Price: $[amount]. You can pay the full amount now, or split it into 3 monthly payments. Once payment is confirmed, I will send suggested times for the first coaching session and start preparing based on your kitchen page and form answers.'],
        ['BB: payment registered', 'Hi! The payment has been registered. The next step is the first coaching session. I will send you suggested times and use your kitchen page, form answers and goals as the basis for preparation. In the first session, we will work on direction, priorities and the most important strategic steps forward.'],
        ['BB: need more info', 'Hi! Thank you for the request. Before I recommend the right Business Builder plan, I need a little more information: [write what is missing]. Once I have this, I can assess whether the Home Kitchen Growth Plan or the B2B Growth Plan is the best fit.'],
        ['BB: free resources first', 'Hi! I have reviewed your request and kitchen page. My assessment is that it may be better to start with the resources you already have in RiceMap24 before buying Business Builder. First use Business Academy, relevant coach/masterclass resources and the practical tools in the app to strengthen the foundation. When the kitchen page, menu and sales direction are clearer, Business Builder can give more value.'],
        ['BB: not a fit now', 'Hi! Thank you for submitting the Business Builder form. After reviewing the request, I do not think Business Builder is the right next step right now. This does not mean that your kitchen lacks potential, but that you should probably strengthen the foundation first. I recommend starting with [specific recommendation], and you can send a new request later.']
      ]));
    }
    const quickStatus = (label, value, count)=>el('button',{type:'button',class:'adminTicketStat '+(status===value?'active':''),onclick:()=>{state.admin.ticketStatus=value; render();}},[
      el('strong',{},[String(count||0)]), el('span',{},[label])
    ]);
    return el('div', { class:'adminSupportGrid' }, [
      el('div', { class:'adminPanel' }, [
        el('div', { class:'adminPanelHead' }, [
          el('div', {}, [
            el('h2', {}, [state.lang==='no'?'Support tickets':'Support tickets']),
            el('p', { class:'muted' }, [state.lang==='no'?'Arbeidsflate for support: filtrer saker, prioriter det som haster, svar aktører og bruk interne notater.':'Support workspace: filter cases, prioritize urgent items, reply to kitchens and use internal notes.'])
          ])
        ]),
        el('div',{class:'adminTicketStats'},[
          quickStatus(state.lang==='no'?'alle':'all','all',allTickets.length),
          quickStatus(state.lang==='no'?'åpne':'open','open',counts.open),
          quickStatus(state.lang==='no'?'venter':'pending','pending',counts.pending),
          quickStatus(state.lang==='no'?'lukket':'closed','closed',counts.closed),
          el('button',{type:'button',class:'adminTicketStat '+(priority==='high'?'active':''),onclick:()=>{state.admin.ticketPriority=priority==='high'?'all':'high'; render();}},[
            el('strong',{},[String(highCount)]), el('span',{},[state.lang==='no'?'høy prioritet':'high priority'])
          ])
        ]),
        el('div',{class:'adminTicketFilters'},[
          el('input',{class:'input',placeholder:state.lang==='no'?'Søk ticket, kjøkken, kunde-ID eller kategori':'Search ticket, kitchen, customer ID or category',value:state.admin.ticketQ||'',oninput:(e)=>{state.admin.ticketQ=e.target.value; render();}}),
          el('select', { class:'input', value:priority, onchange:(e)=>{ state.admin.ticketPriority=e.target.value; render(); } }, [
            el('option',{value:'all',selected:priority==='all'},[state.lang==='no'?'Alle prioriteter':'All priorities']),
            el('option',{value:'high',selected:priority==='high'},['High']),
            el('option',{value:'normal',selected:priority==='normal'},['Normal']),
            el('option',{value:'low',selected:priority==='low'},['Low'])
          ]),
          el('select', { class:'input', value:category, onchange:(e)=>{ state.admin.ticketCategory=e.target.value; render(); } }, [
            el('option',{value:'all',selected:category==='all'},[state.lang==='no'?'Alle kategorier':'All categories']),
            ...categories.map(c=>el('option',{value:c,selected:category===c},[c]))
          ])
        ]),
        (!tickets.length ? el('div',{class:'adminEmpty'},[state.lang==='no'?'Ingen tickets i dette filteret.':'No tickets in this filter.']) : null),
        el('div',{class:'adminTicketList'}, tickets.map(t=>el('button',{type:'button', class:'adminTicketRow' + (state.admin.selectedTicketId===t.id?' active':''), onclick:()=>loadTicketDetail(t.id)},[
          el('div',{},[
            el('strong',{},['#'+t.id+' · '+(t.subject||'Ticket')]),
            el('span',{class:'muted small'},[((t.listing_customer_no||'') ? (t.listing_customer_no+' · ') : '')+(t.listing_name||'Kitchen')+' · '+(t.category||'general')+' · '+(t.updated_at||'')])
          ]),
          el('div',{class:'adminTicketRowMeta'},[String(t.category||'')==='business_builder' ? el('span',{class:'tag tag-builder'},[builderStageLabel(t.builder_stage||'new_request')]) : null, ticketPill(t.status), el('span',{class:'tag '+(String(t.priority||'normal')==='high'?'tag-warn':'')},[t.priority||'normal'])].filter(Boolean))
        ])))
      ]),
      el('div', { class:'adminPanel adminTicketDetail' }, [
        (!selected ? el('div',{class:'adminEmpty'},[state.lang==='no'?'Velg en ticket fra listen.':'Select a ticket from the list.']) : el('div',{},[
          el('div',{class:'adminTicketDetailHead'},[
            el('div',{},[
              el('h2',{},['#'+selected.id+' · '+selected.subject]),
              el('p',{class:'muted'},[((selected.listing_customer_no||'') ? (selected.listing_customer_no+' · ') : '')+(selected.listing_name||'Kitchen')+' · '+(selected.category||'general')+' · '+(selected.created_at||'')])
            ]),
            el('div',{class:'row',style:'gap:8px; flex-wrap:wrap'},[isBuilderTicket ? el('span',{class:'tag tag-builder'},[builderStageLabel(selected.builder_stage||'new_request')]) : null, ticketPill(selected.status), el('span',{class:'tag '+(String(selected.priority||'normal')==='high'?'tag-warn':'')},[selected.priority||'normal'])].filter(Boolean))
          ]),
          selectedListing ? el('div',{class:'adminTicketKitchenCard'},[
            el('div',{},[
              el('strong',{},[selectedListing.name || selected.listing_name || 'Kitchen']),
              el('span',{class:'muted small'},[customerNumber(selectedListing) + (selectedListing.city ? ' · ' + selectedListing.city : '') + ' · ' + normalizePlan(selectedListing.plan||'basic').toUpperCase()])
            ]),
            el('div',{class:'row',style:'gap:8px; flex-wrap:wrap'},[
              button(state.lang==='no'?'View as kitchen':'View as kitchen',{variant:'outline',onclick:()=>viewAsKitchen(selectedListing)}),
              button(state.lang==='no'?'Åpne i Access':'Open in Access',{variant:'outline',onclick:()=>{state.admin.tab='access'; state.admin.accessQ=customerNumber(selectedListing); state.admin.accessExpandedId=selectedListing.id; render();}})
            ])
          ]) : null,
          isBuilderTicket ? el('div',{class:'adminBuilderPanel'},[
            el('div',{class:'adminBuilderPanelHead'},[
              el('div',{},[
                el('strong',{},['RiceMap24 Business Builder']),
                el('p',{class:'muted small'},[state.lang==='no'?'Egen arbeidsflyt for betalt coaching. Bruk denne til å styre vurdering, tilbud, betaling og leveranse.':'Dedicated workflow for paid coaching. Use this to manage review, recommendation, payment and delivery.'])
              ])
            ]),
            el('div',{class:'adminBuilderGrid'},[
              el('div',{class:'field'},[
                el('label',{},[state.lang==='no'?'Business Builder-status':'Business Builder stage']),
                el('select',{class:'input',value:selected.builder_stage||'new_request',onchange:e=>updateTicket(selected.id,{builder_stage:e.target.value})},builderStages.map(([v,l])=>el('option',{value:v,selected:(selected.builder_stage||'new_request')===v},[l])))
              ]),
              el('div',{class:'field'},[
                el('label',{},[state.lang==='no'?'Anbefalt plan':'Recommended plan']),
                el('select',{class:'input',value:selected.builder_recommended_plan||'',onchange:e=>updateTicket(selected.id,{builder_recommended_plan:e.target.value})},[
                  el('option',{value:'',selected:!selected.builder_recommended_plan},[state.lang==='no'?'Ikke vurdert':'Not assessed']),
                  el('option',{value:'home_kitchen_growth',selected:selected.builder_recommended_plan==='home_kitchen_growth'},['Home Kitchen Growth Plan']),
                  el('option',{value:'b2b_growth',selected:selected.builder_recommended_plan==='b2b_growth'},['B2B Growth Plan']),
                  el('option',{value:'free_resources_first',selected:selected.builder_recommended_plan==='free_resources_first'},[state.lang==='no'?'Gratisressurser først':'Free resources first']),
                  el('option',{value:'not_a_fit',selected:selected.builder_recommended_plan==='not_a_fit'},[state.lang==='no'?'Ikke riktig nå':'Not a fit now'])
                ])
              ]),
              el('div',{class:'field'},[
                el('label',{},[state.lang==='no'?'Betaling':'Payment']),
                el('select',{class:'input',value:selected.builder_payment_status||'',onchange:e=>updateTicket(selected.id,{builder_payment_status:e.target.value})},builderPayments.map(([v,l])=>el('option',{value:v,selected:(selected.builder_payment_status||'')===v},[l])))
              ])
            ]),
            el('div',{class:'adminBuilderChecklist'},[
              el('strong',{},[state.lang==='no'?'Anbefalt arbeidsflyt':'Recommended workflow']),
              el('ol',{},[
                el('li',{},[state.lang==='no'?'Les skjema og kjøkkenside. Ikke gi full analyse gratis.':'Review form and kitchen page. Do not give the full analysis for free.']),
                el('li',{},[state.lang==='no'?'Send kort bekreftelse innen 24 timer.':'Send a short confirmation within 24 hours.']),
                el('li',{},[state.lang==='no'?'Vurder Home Kitchen, B2B, gratisressurser først eller ikke riktig nå.':'Assess Home Kitchen, B2B, free resources first or not a fit now.']),
                el('li',{},[state.lang==='no'?'Send anbefaling, pris og betalingsinformasjon.':'Send recommendation, price and payment information.']),
                el('li',{},[state.lang==='no'?'Start coaching først etter bekreftet betaling.':'Start coaching only after confirmed payment.'])
              ])
            ]),
            el('div',{class:'adminBuilderActions'},[
              button(state.lang==='no'?'Marker: vurdert':'Mark reviewed',{variant:'outline',onclick:()=>updateTicket(selected.id,{builder_stage:'reviewed', priority:'high'})}),
              button(state.lang==='no'?'Marker: tilbud sendt':'Mark recommendation sent',{variant:'outline',onclick:()=>updateTicket(selected.id,{builder_stage:'recommendation_sent', builder_payment_status:'offer_sent', status:'pending'})}),
              button(state.lang==='no'?'Marker: betalt':'Mark paid',{variant:'outline',onclick:()=>updateTicket(selected.id,{builder_stage:'paid', builder_payment_status:'paid', status:'open'})}),
              button(state.lang==='no'?'Marker: strategi levert':'Mark strategy delivered',{variant:'outline',onclick:()=>updateTicket(selected.id,{builder_stage:'strategy_delivered'})})
            ])
          ]) : null,
          el('div',{class:'adminTicketControls'},[
            el('select',{class:'input', value:selected.status||'open', onchange:(e)=>updateTicket(selected.id,{status:e.target.value})},[
              el('option',{value:'open',selected:selected.status==='open'},['Open']),
              el('option',{value:'pending',selected:selected.status==='pending'},['Pending']),
              el('option',{value:'closed',selected:selected.status==='closed'},['Closed'])
            ]),
            el('select',{class:'input', value:selected.priority||'normal', onchange:(e)=>updateTicket(selected.id,{priority:e.target.value})},[
              el('option',{value:'low',selected:selected.priority==='low'},['Low']),
              el('option',{value:'normal',selected:selected.priority==='normal'},['Normal']),
              el('option',{value:'high',selected:selected.priority==='high'},['High'])
            ])
          ]),
          el('div',{class:'adminTicketMessages'}, (selected.messages||[]).map(m=>el('div',{class:'adminTicketMsg '+(m.sender==='admin'?'admin':'owner')+(m.is_internal?' internal':'')},[
            el('div',{class:'adminTicketMsgMeta'},[(m.sender||'')+(m.is_internal?' · internal':''), ' · ', m.created_at||'']),
            el('div',{},[m.body||''])
          ]))),
          el('div',{class:'adminTicketTemplates'}, templates.map(([label,txt])=>button(label,{variant:'outline',onclick:()=>insertTemplate(txt)}))),
          el('textarea',{class:'input', style:'width:100%; min-height:82px; margin-top:10px', placeholder:state.lang==='no'?'Skriv svar til aktør…':'Write reply to kitchen…', value:state.admin.ticketReply||'', oninput:(e)=>{state.admin.ticketReply=e.target.value;}},[]),
          el('label',{class:'adminCheckLine'},[el('input',{type:'checkbox', checked:!!state.admin.ticketInternal, onchange:(e)=>{state.admin.ticketInternal=e.target.checked; render();}}), el('span',{},[state.lang==='no'?'Intern note (ikke synlig for aktør)':'Internal note (not visible to kitchen)'])]),
          el('div',{class:'row',style:'gap:8px; flex-wrap:wrap'},[
            button((state.lang==='no'?'Send svar':'Send reply'),{variant:'primary',onclick:()=>replyTicket(selected.id)}),
            button(state.lang==='no'?'Sett som venter':'Set pending',{variant:'outline',onclick:()=>updateTicket(selected.id,{status:'pending'})}),
            button(state.lang==='no'?'Lukk ticket':'Close ticket',{variant:'outline',onclick:()=>updateTicket(selected.id,{status:'closed'})})
          ]),
          el('div',{class:'field',style:'margin-top:14px'},[
            el('div',{class:'muted small',style:'margin-bottom:6px'},[state.lang==='no'?'Admin intern notat':'Admin internal note']),
            el('textarea',{class:'input',style:'width:100%;min-height:76px',value:selected.internal_note||'',oninput:(e)=>{selected.internal_note=e.target.value;}},[]),
            button(state.lang==='no'?'Lagre internt notat':'Save internal note',{variant:'outline',onclick:()=>updateTicket(selected.id,{internal_note:selected.internal_note||''})})
          ])
        ].filter(Boolean)))
      ])
    ]);
  }


  function accessContent(){
    const all = state.admin.items.all || [];
    const q = String(state.admin.accessQ || '').trim().toLowerCase();
    const f = state.admin.accessFilter || 'all';
    const expandedId = state.admin.accessExpandedId || null;
    const today = new Date().toISOString().slice(0,10);
    const soon = new Date(Date.now() + 14*24*60*60*1000).toISOString().slice(0,10);

    function datePlusDays(days){
      return new Date(Date.now() + Number(days||0)*24*60*60*1000).toISOString().slice(0,10);
    }

    function quickAccessPreset(it, kind){
      const name = it.name || it.slug || ('#'+it.id);
      let patch = {};
      if (kind === 'trial14'){
        patch = { access_type:'trial', access_expires_at:datePlusDays(14), access_reason:'14-day manual trial from admin', paid_status:'paid', plan_active:1, account_status:'trial' };
      } else if (kind === 'trial30'){
        patch = { access_type:'trial', access_expires_at:datePlusDays(30), access_reason:'30-day manual trial from admin', paid_status:'paid', plan_active:1, account_status:'trial' };
      } else if (kind === 'free90'){
        patch = { access_type:'free', access_expires_at:datePlusDays(90), access_reason:'90-day free access from admin', paid_status:'paid', plan_active:1, account_status:'active' };
      } else if (kind === 'growthdemo'){
        patch = { access_type:'internal', access_expires_at:datePlusDays(30), access_reason:'30-day Growth demo access from admin', paid_status:'paid', plan_active:1, account_status:'active', plan:'growth', feature_overrides:{} };
      } else if (kind === 'prodpaid'){
        patch = { access_type:'paid', access_expires_at:'', access_reason:'', paid_status:'paid', plan_active:1, account_status:'active', feature_overrides:{} };
      } else if (kind === 'pastdue'){
        patch = { account_status:'past_due', paid_status:'unpaid', plan_active:0, access_type:'paid', access_expires_at:'', access_reason:'Payment marked past due manually from admin' };
      } else if (kind === 'cancel'){
        patch = { account_status:'cancelled', paid_status:'unpaid', plan_active:0, access_type:'paid', access_expires_at:'', access_reason:'Cancelled manually from admin', feature_overrides:{} };
      }
      if (!Object.keys(patch).length) return;
      if (!confirm((state.lang==='no'?'Bruke denne hurtighandlingen på ':'Apply this quick action to ') + name + '?')) return;
      updateMeta(it.id, patch);
    }

    const features = [
      ['britesight','BriteSight Creative Suite'],
      ['print_promo','Print & Promo'],
      ['pro_print_kit','Pro Print Kit'],
      ['business_coach','Business Coach'],
      ['marketing_coach','Marketing Coach'],
      ['masterclass','Masterclass'],
      ['accounting','Accounting & Insights'],
      ['customer_list','Customer List / CRM']
    ];

    function allFeatureSummary(it){
      const raw = it.feature_overrides || {};
      const out = [];
      features.forEach(([key,label])=>{
        const cfg = featureOverrideConfig(it, key);
        if (!cfg) return;
        const active = hasFeatureOverride(it, key);
        const range = [cfg.start || '', cfg.end || ''].filter(Boolean).join('–');
        out.push(label + (active ? ' (active)' : '') + (range ? ' ' + range : ''));
      });
      return out;
    }

    function hasAnyOverride(it){
      return allFeatureSummary(it).length > 0;
    }

    function isExpiringSoon(it){
      const dates = [];
      if (it.access_expires_at) dates.push(String(it.access_expires_at));
      features.forEach(([key])=>{
        const cfg = featureOverrideConfig(it, key);
        if (cfg && cfg.end) dates.push(String(cfg.end));
      });
      return dates.some(d => d >= today && d <= soon);
    }

    let list = all.slice();
    if (f === 'expiring') list = list.filter(isExpiringSoon);
    else if (f === 'overrides') list = list.filter(hasAnyOverride);
    else if (f === 'public_hidden') list = list.filter(it => String(it.billing_visibility || 'hidden') !== 'public');
    else if (f === 'public_visible') list = list.filter(it => String(it.billing_visibility || 'hidden') === 'public');
    else if (f === 'unpaid') list = list.filter(it => String(it.paid_status || 'unpaid') === 'unpaid');
    else if (f.startsWith('acct_')) list = list.filter(it => String(it.account_status || 'active') === f.slice(5));
    else if (f !== 'all') list = list.filter(it => String(it.access_type || 'paid') === f);
    if (q){
      list = list.filter(it => [
        customerNumber(it), it.id, it.name, it.slug, it.city, it.contact_email,
        it.account_status, it.access_reason, it.access_type, allFeatureSummary(it).join(' ')
      ].join(' ').toLowerCase().includes(q));
    }

    const accessCounts = all.reduce((acc,it)=>{ const k=String(it.access_type||'paid'); acc[k]=(acc[k]||0)+1; return acc; },{});
    const expiringCount = all.filter(isExpiringSoon).length;
    const overrideCount = all.filter(hasAnyOverride).length;
    const expiringPreview = all.filter(isExpiringSoon).slice(0,5);

    function normalizeAccessDateInput(raw){
      const value = String(raw || '').trim();
      if (!value) return '';
      // Browser date inputs return YYYY-MM-DD even when the UI displays local formats.
      if (/^\d{4}-\d{2}-\d{2}$/.test(value)) return value;
      // Be defensive for browsers/locales that may expose DD.MM.YYYY or DD/MM/YYYY.
      const m = value.match(/^(\d{1,2})[.\/](\d{1,2})[.\/](\d{4})$/);
      if (m){
        const dd = String(m[1]).padStart(2,'0');
        const mm = String(m[2]).padStart(2,'0');
        return `${m[3]}-${mm}-${dd}`;
      }
      return value.slice(0,10);
    }

    async function saveAccess(it){
      const access_type = document.getElementById('access_type_'+it.id)?.value || 'paid';
      const access_expires_at = normalizeAccessDateInput(document.getElementById('access_expires_'+it.id)?.value || '');
      const access_reason = document.getElementById('access_reason_'+it.id)?.value || '';
      const plan = document.getElementById('access_plan_'+it.id)?.value || normalizePlan(it.plan||'basic');
      const billing = document.getElementById('access_billing_'+it.id)?.value || (it.billing||'monthly');
      const account_status = document.getElementById('access_account_status_'+it.id)?.value || (it.account_status || 'active');
      const feature_overrides = {};
      features.forEach(([key])=>{
        const enabled = !!document.getElementById('access_feat_'+it.id+'_'+key)?.checked;
        const start = document.getElementById('access_feat_start_'+it.id+'_'+key)?.value || '';
        const end = document.getElementById('access_feat_end_'+it.id+'_'+key)?.value || '';
        const reason = document.getElementById('access_feat_reason_'+it.id+'_'+key)?.value || '';
        if (enabled || start || end || reason){
          feature_overrides[key] = { enabled, start, end, reason };
        }
      });
      const paid_status = access_type === 'paid' ? (it.paid_status || 'unpaid') : 'paid';
      const inactive = ['cancelled','paused','archived','deleted_by_request'].includes(account_status);
      const patch = { account_status, access_type, access_expires_at, access_reason, feature_overrides, plan, billing, paid_status, plan_active: inactive ? 0 : (access_type === 'paid' ? (it.plan_active|0) : 1) };
      const ok = await updateMeta(it.id, patch);
      if (ok) {
        state.admin.accessSavedMessage = (state.lang==='no'?'Tilgang lagret.':'Access saved.');
      }
    }

    function clearAccess(it){
      if (!confirm(state.lang==='no'?'Tilbakestille manuell tilgang for dette kjøkkenet?':'Reset manual access for this kitchen?')) return;
      updateMeta(it.id, { access_type:'paid', access_expires_at:'', access_reason:'', feature_overrides:{} });
    }

    async function adminSetOwnerPassword(it){
      const no = state.lang === 'no';
      const name = it.name || it.slug || ('#'+it.id);
      const new_password = document.getElementById('admin_new_password_'+it.id)?.value || '';
      const repeat_password = document.getElementById('admin_repeat_password_'+it.id)?.value || '';
      if (new_password.length < 6){
        alert(no ? 'Nytt passord må være minst 6 tegn.' : 'New password must be at least 6 characters.');
        return;
      }
      if (new_password !== repeat_password){
        alert(no ? 'Passordene er ikke like.' : 'Passwords do not match.');
        return;
      }
      if (!confirm((no ? 'Sette nytt passord for ' : 'Set new password for ') + name + '?')) return;
      try{
        await apiJson('POST', adminUrl(`/api/admin/listings/${it.id}/password`), { new_password, repeat_password }, { timeoutMs:12000 });
        document.getElementById('admin_new_password_'+it.id).value = '';
        document.getElementById('admin_repeat_password_'+it.id).value = '';
        alert(no ? 'Passordet er oppdatert.' : 'Password updated.');
      }catch(e){
        alert((no ? 'Kunne ikke oppdatere passord: ' : 'Could not update password: ') + (e.message || e));
      }
    }

    function compactLine(it){
      const access = String(it.access_type || 'paid');
      const activeNonPaid = access !== 'paid';
      const overrides = featureOverrideSummary(it.feature_overrides);
      const expanded = String(expandedId) === String(it.id);
      return el('div', { class:'adminAccessCompactRow' + (expanded ? ' is-expanded' : '') }, [
        el('div', { class:'adminAccessCompactTop' }, [
          el('div', { class:'adminAccessCompactName' }, [
            el('strong', {}, [it.name || it.slug || ('#'+it.id)]),
            el('span', { class:'muted small' }, [customerNumber(it) + (it.slug ? ' · ' + it.slug : '') + (it.city ? ' · ' + it.city : '')])
          ]),
          el('div', { class:'adminAccessCompactCells' }, [
            el('span', { class:'tag ' + accountStatusTone(it) }, [accountStatusLabel(it)]),
            el('span', { class:'tag ' + ((it.billing_visibility||'hidden')==='public'?'tag-ok':'tag-warn') }, [(it.billing_visibility||'hidden')==='public' ? (state.lang==='no'?'PUBLIC':'PUBLIC') : (state.lang==='no'?'HIDDEN':'HIDDEN')]),
            el('span', { class:'tag ' + (activeNonPaid?'tag-ok':'') }, [access.toUpperCase()]),
            el('span', { class:'tag ' + (String(it.paid_status||'unpaid')==='paid'?'tag-ok':'tag-warn') }, [String(it.paid_status||'unpaid').toUpperCase()]),
            el('span', { class:'tag' }, [normalizePlan(it.plan||'basic').toUpperCase()]),
            it.access_expires_at ? el('span', { class:'tag tag-warn' }, [(state.lang==='no'?'Expires ':'Expires ') + it.access_expires_at]) : el('span', { class:'muted small' }, [state.lang==='no'?'No expiry':'No expiry']),
            overrides.length ? el('span', { class:'tag tag-ok' }, [overrides.length + ' override' + (overrides.length===1?'':'s')]) : el('span', { class:'muted small' }, [state.lang==='no'?'No overrides':'No overrides'])
          ]),
          el('div', { class:'row', style:'gap:8px; justify-content:flex-end; flex-wrap:wrap' }, [
            button(state.lang==='no'?'View as':'View as', { variant:'outline', onclick:()=>viewAsKitchen(it) }),
            button(expanded ? (state.lang==='no'?'Lukk':'Close') : (state.lang==='no'?'Edit':'Edit'), { variant:expanded?'outline':'primary', onclick:()=>{ state.admin.accessExpandedId = expanded ? null : it.id; render(); } })
          ])
        ]),
        expanded ? accessEditor(it) : null
      ].filter(Boolean));
    }

    function accessEditor(it){
      const access = String(it.access_type || 'paid');
      return el('div', { class:'adminAccessControls adminAccessEditor' }, [
        el('div', { class:'adminAccessPresetBox' }, [
          el('div', {}, [
            el('strong', {}, [state.lang==='no'?'Hurtigvalg':'Quick presets']),
            el('p', { class:'muted small' }, [state.lang==='no'
              ? 'Brukes til testbrukere, gratis tilgang, Growth-demo eller manuell betalingsstatus uten å fylle ut alle feltene.'
              : 'Use for test users, free access, Growth demos or manual billing status without filling every field.'])
          ]),
          el('div', { class:'adminPresetActions' }, [
            button(state.lang==='no'?'Trial 14 dager':'Trial 14 days', { variant:'outline', onclick:()=>quickAccessPreset(it,'trial14') }),
            button(state.lang==='no'?'Trial 30 dager':'Trial 30 days', { variant:'outline', onclick:()=>quickAccessPreset(it,'trial30') }),
            button(state.lang==='no'?'Gratis 90 dager':'Free 90 days', { variant:'outline', onclick:()=>quickAccessPreset(it,'free90') }),
            button(state.lang==='no'?'Growth-demo 30 dager':'Growth demo 30 days', { variant:'outline', onclick:()=>quickAccessPreset(it,'growthdemo') }),
            button(state.lang==='no'?'Marker betalt':'Mark paid', { variant:'outline', onclick:()=>quickAccessPreset(it,'prodpaid') }),
            button(state.lang==='no'?'Forfalt':'Past due', { variant:'outline', onclick:()=>quickAccessPreset(it,'pastdue') }),
            button(state.lang==='no'?'Avslutt':'Cancel account', { variant:'outline', onclick:()=>quickAccessPreset(it,'cancel') })
          ])
        ]),
        el('div', { class:'adminPasswordResetBox' }, [
          el('div', {}, [
            el('strong', {}, [state.lang==='no'?'Sett nytt innloggingspassord':'Set new login password']),
            el('p', { class:'muted small' }, [state.lang==='no'
              ? 'Brukes når en testbruker eller aktør har glemt passordet. Du ser ikke gammelt passord; du setter bare et nytt.'
              : 'Use when a test user or kitchen owner has forgotten the password. You cannot see the old password; set a new one.'
            ]),
            el('div', { class:'muted small' }, [(state.lang==='no'?'Login e-post: ':'Login email: ') + ((it.contact && it.contact.email) || it.contact_email || it.owner_email || '—')])
          ]),
          el('div', { class:'adminAccessGrid' }, [
            el('label', {}, [el('span', { class:'muted small' }, [state.lang==='no'?'Nytt passord':'New password']), el('input', { class:'input', id:'admin_new_password_'+it.id, type:'password', autocomplete:'new-password', placeholder:state.lang==='no'?'Minst 6 tegn':'At least 6 characters' })]),
            el('label', {}, [el('span', { class:'muted small' }, [state.lang==='no'?'Gjenta passord':'Repeat password']), el('input', { class:'input', id:'admin_repeat_password_'+it.id, type:'password', autocomplete:'new-password' })])
          ]),
          el('div', { class:'row', style:'gap:8px; flex-wrap:wrap; margin-top:10px' }, [
            button(state.lang==='no'?'Oppdater passord':'Update password', { variant:'outline', onclick:()=>adminSetOwnerPassword(it) })
          ])
        ]),
        el('div', { class:'adminAccessGrid' }, [
          el('label', {}, [el('span', { class:'muted small' }, [state.lang==='no'?'Kundestatus':'Customer status']), el('select', { class:'input', id:'access_account_status_'+it.id }, [
            el('option', { value:'active', selected:(it.account_status||'active')==='active' }, [state.lang==='no'?'Aktiv':'Active']),
            el('option', { value:'trial', selected:(it.account_status||'active')==='trial' }, ['Trial']),
            el('option', { value:'past_due', selected:(it.account_status||'active')==='past_due' }, [state.lang==='no'?'Forfalt':'Past due']),
            el('option', { value:'cancelled', selected:(it.account_status||'active')==='cancelled' }, [state.lang==='no'?'Avsluttet':'Cancelled']),
            el('option', { value:'paused', selected:(it.account_status||'active')==='paused' }, [state.lang==='no'?'Pauset':'Paused']),
            el('option', { value:'archived', selected:(it.account_status||'active')==='archived' }, [state.lang==='no'?'Arkivert':'Archived']),
            el('option', { value:'deleted_by_request', selected:(it.account_status||'active')==='deleted_by_request' }, [state.lang==='no'?'Planlagt sletting':'Scheduled deletion']),
          ])]),
          el('label', {}, [el('span', { class:'muted small' }, [state.lang==='no'?'Tilgangstype':'Access type']), el('select', { class:'input', id:'access_type_'+it.id }, [
            el('option', { value:'paid', selected:access==='paid' }, [state.lang==='no'?'Paid / Stripe':'Paid / Stripe']),
            el('option', { value:'trial', selected:access==='trial' }, [state.lang==='no'?'Trial':'Trial']),
            el('option', { value:'free', selected:access==='free' }, [state.lang==='no'?'Free access':'Free access']),
            el('option', { value:'partner', selected:access==='partner' }, [state.lang==='no'?'Partner access':'Partner access']),
            el('option', { value:'internal', selected:access==='internal' }, [state.lang==='no'?'Internal test':'Internal test'])
          ])]),
          el('label', {}, [el('span', { class:'muted small' }, [state.lang==='no'?'Plan override':'Plan override']), el('select', { class:'input', id:'access_plan_'+it.id }, [
            el('option', { value:'basic', selected:normalizePlan(it.plan)==='basic' }, ['Basic']),
            el('option', { value:'business', selected:normalizePlan(it.plan)==='business' }, ['Business']),
            el('option', { value:'growth', selected:normalizePlan(it.plan)==='growth' }, ['Growth']),
            el('option', { value:'pro', selected:normalizePlan(it.plan)==='pro' }, ['Pro'])
          ])]),
          el('label', {}, [el('span', { class:'muted small' }, [state.lang==='no'?'Billing':'Billing']), el('select', { class:'input', id:'access_billing_'+it.id }, [
            el('option', { value:'monthly', selected:(it.billing||'monthly')==='monthly' }, ['Monthly']),
            el('option', { value:'yearly', selected:(it.billing||'monthly')==='yearly' }, ['Yearly'])
          ])]),
          el('label', {}, [el('span', { class:'muted small' }, [state.lang==='no'?'Utløper':'Expires']), el('input', { class:'input', id:'access_expires_'+it.id, type:'date', value:it.access_expires_at||'' })])
        ]),
        el('details', { class:'adminFeatureDetails', open: hasAnyOverride(it) }, [
          el('summary', {}, [state.lang==='no'?'Advanced access / feature overrides':'Advanced access / feature overrides']),
          el('div', { class:'adminFeatureBox' }, [
            el('div', { class:'muted small' }, [state.lang==='no'?'Gi avgrenset tilgang til enkeltfunksjoner uten å endre hele abonnementet.':'Give limited access to single features without changing the whole plan.']),
            el('div', { class:'adminFeatureTimedGrid' }, features.map(([key,label])=>{
              const cfg = featureOverrideConfig(it, key) || { enabled:false, start:'', end:'', reason:'' };
              const active = hasFeatureOverride(it, key);
              return el('div', { class:'adminFeatureTimedRow' + (active ? ' is-active' : '') }, [
                el('label', { class:'adminFeatureCheck adminFeatureCheckTimed' }, [
                  el('input', { type:'checkbox', id:'access_feat_'+it.id+'_'+key, value:key, checked:cfg.enabled !== false && !!featureOverrideConfig(it,key) }),
                  el('span', {}, [label]),
                  active ? el('span', { class:'tag tag-ok' }, [state.lang==='no'?'Aktiv':'Active']) : null
                ].filter(Boolean)),
                el('div', { class:'adminFeatureDateGrid' }, [
                  el('label', {}, [el('span', { class:'muted small' }, [state.lang==='no'?'Start':'Start']), el('input', { class:'input', type:'date', id:'access_feat_start_'+it.id+'_'+key, value:cfg.start||'' })]),
                  el('label', {}, [el('span', { class:'muted small' }, [state.lang==='no'?'Slutt':'End']), el('input', { class:'input', type:'date', id:'access_feat_end_'+it.id+'_'+key, value:cfg.end||'' })]),
                  el('label', {}, [el('span', { class:'muted small' }, [state.lang==='no'?'Årsak':'Reason']), el('input', { class:'input', id:'access_feat_reason_'+it.id+'_'+key, value:cfg.reason||'', placeholder:state.lang==='no'?'F.eks. 7 dagers test':'E.g. 7-day trial' })])
                ])
              ]);
            }))
          ])
        ]),
        el('textarea', { class:'input', id:'access_reason_'+it.id, style:'width:100%; min-height:58px', placeholder:state.lang==='no'?'Årsak/notat, f.eks. testbruker, samarbeid, kompensasjon…':'Reason/note, e.g. test user, partner, compensation…' }, [it.access_reason||'']),
        el('div', { class:'muted small' }, [state.lang==='no'
          ? 'Endringer i disse feltene lagres først når du trykker Lagre tilgang.'
          : 'Changes in these fields are saved only when you click Save access.']),
        state.admin.accessSavedMessage ? el('div', { class:'small', style:'color:#165c35; font-weight:700' }, [state.admin.accessSavedMessage]) : null,
        el('div', { class:'row', style:'gap:8px; flex-wrap:wrap' }, [
          button(state.lang==='no'?'Lagre tilgang':'Save access', { variant:'primary', onclick:()=>{ state.admin.accessSavedMessage=''; saveAccess(it); } }),
          button(state.lang==='no'?'Tilbakestill til betalt':'Reset to paid', { variant:'outline', onclick:()=>clearAccess(it) })
        ])
      ]);
    }

    return el('div', { class:'adminPanel adminAccessPanel' }, [
      el('div', { class:'adminPanelHead' }, [
        el('div', {}, [
          el('h2', {}, [state.lang==='no'?'Access / Plans':'Access / Plans']),
          el('p', { class:'muted' }, [state.lang==='no'
            ? 'Kompakt oversikt. Bruk søk/filter først, og åpne kun den aktøren du vil endre.'
            : 'Compact overview. Use search/filter first, then open only the kitchen you want to edit.'])
        ]),
        el('div', { class:'adminAccessStats' }, [
          el('span', {}, ['Paid: '+(accessCounts.paid||0)]),
          el('span', {}, ['Trial: '+(accessCounts.trial||0)]),
          el('span', {}, ['Free: '+(accessCounts.free||0)]),
          el('span', {}, ['Partner: '+(accessCounts.partner||0)]),
          el('span', {}, ['Internal: '+(accessCounts.internal||0)]),
          el('span', {}, ['Overrides: '+overrideCount]),
          el('span', {}, ['Expiring: '+expiringCount])
        ]),
        button(state.lang==='no'?'Synk betaling/synlighet':'Sync billing visibility', { variant:'outline', onclick:syncBillingVisibility })
      ]),
      expiringPreview.length ? el('div', { class:'adminExpiringBox' }, [
        el('strong', {}, [state.lang==='no'?'Tilganger som utløper snart':'Access ending soon']),
        el('div', { class:'muted small' }, [expiringPreview.map(it => (it.name||it.slug||customerNumber(it)) + (it.access_expires_at ? ' · ' + it.access_expires_at : '')).join('  |  ')])
      ]) : null,
      el('div', { class:'adminToolbar' }, [
        el('select', { class:'input', style:'max-width:230px', value:f, onchange:(e)=>{ state.admin.accessFilter=e.target.value; render(); } }, [
          el('option', { value:'all', selected:f==='all' }, ['All access types']),
          el('option', { value:'paid', selected:f==='paid' }, ['Paid / Stripe']),
          el('option', { value:'trial', selected:f==='trial' }, ['Trial']),
          el('option', { value:'free', selected:f==='free' }, ['Free access']),
          el('option', { value:'partner', selected:f==='partner' }, ['Partner access']),
          el('option', { value:'internal', selected:f==='internal' }, ['Internal test']),
          el('option', { value:'public_visible', selected:f==='public_visible' }, [state.lang==='no'?'Synlig offentlig':'Public visible']),
          el('option', { value:'public_hidden', selected:f==='public_hidden' }, [state.lang==='no'?'Skjult offentlig':'Public hidden']),
          el('option', { value:'unpaid', selected:f==='unpaid' }, [state.lang==='no'?'Ikke betalt':'Unpaid']),
          el('option', { value:'acct_cancelled', selected:f==='acct_cancelled' }, [state.lang==='no'?'Avsluttede kunder':'Cancelled customers']),
          el('option', { value:'acct_paused', selected:f==='acct_paused' }, [state.lang==='no'?'Pausede kunder':'Paused customers']),
          el('option', { value:'acct_archived', selected:f==='acct_archived' }, [state.lang==='no'?'Arkiverte kunder':'Archived customers']),
          el('option', { value:'overrides', selected:f==='overrides' }, ['Has feature overrides']),
          el('option', { value:'expiring', selected:f==='expiring' }, ['Expiring soon'])
        ]),
        el('input', { class:'input adminSearchInput', placeholder:state.lang==='no'?'Søk kjøkken, kunde-ID, e-post, grunn eller feature':'Search kitchen, customer ID, email, reason or feature', value:state.admin.accessQ||'', oninput:(e)=>{state.admin.accessQ=e.target.value; render();} })
      ]),
      (!list.length ? el('div', { class:'adminEmpty' }, [state.lang==='no'?'Ingen treff.':'No results.']) : null),
      el('div', { class:'adminAccessList adminAccessCompactList' }, list.map(compactLine)),
      el('div', { class:'adminBuildNote' }, [state.lang==='no'
        ? 'Kunde-ID er lagret i databasen. Aktører beholdes i admin/databasen, men siden skjules automatisk fra Explore og offentlig visning når betalt eller manuell tilgang ikke er gyldig.'
        : 'Customer ID is stored in the database. Kitchens stay in admin/database, but the page is hidden automatically from Explore and public view when paid or manual access is not valid.'])
    ].filter(Boolean));
  }


  function adminApi404Hint(e){
    const msg = String((e && e.message) || e || '');
    if (msg.includes('404')){
      return msg + '\n\nThe discount-code API route was not found. Stop the local server and start this Step 7.70 version again, so the backend and frontend are from the same zip.';
    }
    return msg;
  }

  async function saveDiscountCode(payload, id){
    try{
      const key = encodeURIComponent(state.admin.key || '');
      const cleanId = (id === null || id === undefined || id === '' || id === 'new') ? null : id;
      const url = cleanId ? adminUrl(`/api/admin/discount-codes/${encodeURIComponent(cleanId)}`) : adminUrl('/api/admin/discount-codes');
      await apiJson('POST', url, payload || {});
      const dc = await apiGet(adminUrl('/api/admin/discount-codes'));
      state.admin.discountCodes = dc.items || [];
      state.admin.discountEditId = null;
      if (!cleanId) {
        state.admin.discountDraft = { code:'', description:'', discount_type:'percent', percent_off:20, amount_off:'', currency:'', applies_to_plan:'all', billing:'all', max_redemptions:'', active:true, starts_at:'', ends_at:'', internal_note:'' };
      }
      const al = await apiGet(adminUrl('/api/admin/activity?limit=120'));
      state.admin.activity = al.items || [];
      render();
    }catch(e){ alert('Discount code save failed: ' + adminApi404Hint(e)); }
  }

  async function toggleDiscountCode(id, active){
    try{
      if (id === null || id === undefined || id === '') throw new Error('Missing discount code ID');
      const key = encodeURIComponent(state.admin.key || '');
      await apiJson('POST', adminUrl(`/api/admin/discount-codes/${encodeURIComponent(id)}/active`), { active });
      const dc = await apiGet(adminUrl('/api/admin/discount-codes'));
      state.admin.discountCodes = dc.items || [];
      render();
    }catch(e){ alert('Discount code update failed: ' + adminApi404Hint(e)); }
  }

  const DISCOUNT_CURRENCIES = [
    ['NOK','Norwegian krone'],
    ['SEK','Swedish krona'],
    ['DKK','Danish krone'],
    ['EUR','Euro'],
    ['GBP','British pound'],
    ['USD','US dollar'],
    ['CHF','Swiss franc']
  ];

  function readDiscountType(id){
    const elType = document.getElementById(`disc_type_${id}`);
    return elType ? String(elType.value || 'percent') : 'percent';
  }

  function syncDiscountAmountCurrencyControls(id, type){
    const isAmount = String(type || 'percent') === 'amount';
    const percentEl = document.getElementById(`disc_percent_${id}`);
    const amountEl = document.getElementById(`disc_amount_${id}`);
    const currencyEl = document.getElementById(`disc_currency_${id}`);
    // Keep these fields editable in the admin UI. Backend decides which values matter.
    if (percentEl) percentEl.disabled = false;
    if (amountEl) amountEl.disabled = false;
    if (currencyEl) currencyEl.disabled = false;
    if (isAmount && amountEl && !amountEl.value) amountEl.focus();
  }

  function discountCurrencyOptions(current){
    const cur = String(current || '').toUpperCase();
    return [el('option', { value:'', selected:!cur }, ['Select currency'])].concat(
      DISCOUNT_CURRENCIES.map(([code, name]) => el('option', { value:code, selected:cur===code }, [`${code} — ${name}`]))
    );
  }

  function discountLabel(c){
    if ((c.discount_type||'percent') === 'amount'){
      return `${Number(c.amount_off||0).toFixed(0)} ${c.currency||''}`.trim();
    }
    return `${Number(c.percent_off||0).toFixed(0)}%`;
  }

  function discountStatus(c){
    if (!c.active) return state.lang==='no'?'Inactive':'Inactive';
    if (!c.usable_now) return state.lang==='no'?'Not usable now':'Not usable now';
    return state.lang==='no'?'Active':'Active';
  }


  function billingContent(){
    const items = (state.admin.items.all || []).slice().sort((a,b)=> String(a.name||'').localeCompare(String(b.name||'')));
    if (!state.admin.checkoutPreview){
      const first = items[0] || {};
      state.admin.checkoutPreview = { listing_id: first.id || '', plan: normalizePlan(first.plan || 'basic'), billing: first.billing || 'monthly', discount_code: '', referral_credit: true };
    }
    const paid = items.filter(x => String(x.paid_status||'').toLowerCase()==='paid').length;
    const pastDue = items.filter(x => String(x.account_status||'').toLowerCase()==='past_due').length;
    const cancelled = items.filter(x => String(x.account_status||'').toLowerCase()==='cancelled').length;
    const missingStripe = items.filter(x => !String(x.stripe_subscription_id||'').trim()).length;
    const no = state.lang === 'no';
    const q = String(state.admin.billingQ || '').trim().toLowerCase();
    const mode = state.admin.billingStatus || 'all';
    let rows = items;
    if (mode === 'paid') rows = rows.filter(x => String(x.paid_status||'').toLowerCase()==='paid');
    if (mode === 'past_due') rows = rows.filter(x => String(x.account_status||'').toLowerCase()==='past_due');
    if (mode === 'cancelled') rows = rows.filter(x => String(x.account_status||'').toLowerCase()==='cancelled');
    if (mode === 'missing_stripe') rows = rows.filter(x => !String(x.stripe_subscription_id||'').trim());
    if (q) rows = rows.filter(x => [x.name,x.slug,x.plan,x.billing,x.paid_status,x.account_status,x.stripe_status,x.stripe_subscription_id].join(' ').toLowerCase().includes(q));
    const stat = (label, value, help, tone) => el('button', { type:'button', class:'adminStatCard '+(tone||''), onclick:()=>{ state.admin.billingStatus = help || 'all'; render(); } }, [
      el('span', {}, [label]), el('strong', {}, [String(value)])
    ]);

    function checkoutPreviewBox(){
      const draft = state.admin.checkoutPreview || {};
      const selected = items.find(x => String(x.id) === String(draft.listing_id)) || items[0] || {};
      if (!draft.listing_id && selected.id) draft.listing_id = selected.id;
      const country = normalizeMarketCountry(selected.country || 'NO');
      const market = marketForCountry(country);
      const plan = normalizePlan(draft.plan || selected.plan || 'basic');
      const billing = String(draft.billing || selected.billing || 'monthly') === 'yearly' ? 'yearly' : 'monthly';
      const months = billing === 'yearly' ? 10 : 1;
      const base = Number((market.prices && market.prices[plan]) || 0) * months;
      const codeRaw = String(draft.discount_code || '').trim().toUpperCase();
      const code = (state.admin.discountCodes || []).find(c => String(c.code || '').toUpperCase() === codeRaw);
      const codePlanOk = !code || !code.applies_to_plan || code.applies_to_plan === 'all' || normalizePlan(code.applies_to_plan) === plan;
      const codeBillingOk = !code || !code.billing || code.billing === 'all' || code.billing === billing;
      const codeCurrencyOk = !code || (code.discount_type || 'percent') !== 'amount' || String(code.currency || '').toUpperCase() === String(market.currency || '').toUpperCase();
      const codeUsable = !!code && code.usable_now && codePlanOk && codeBillingOk && codeCurrencyOk;
      let discount = 0;
      if (codeUsable){
        if ((code.discount_type || 'percent') === 'amount') discount = Math.min(base, Number(code.amount_off || 0));
        else discount = Math.min(base, base * (Number(code.percent_off || 0) / 100));
      }
      const availableCredit = Math.max(0, Number(selected.referral_credit_balance || 0));
      const credit = draft.referral_credit ? Math.min(Math.max(0, base - discount), availableCredit) : 0;
      const total = Math.max(0, base - discount - credit);
      const fmt = v => moneyAmount(v, market.currency) + ' ' + market.currency;
      const warning = codeRaw && !code ? (no ? 'Koden finnes ikke i Discount codes.' : 'Code not found in Discount codes.')
        : code && !code.usable_now ? (no ? 'Koden er ikke aktiv/brukbar nå.' : 'Code is not active/usable now.')
        : code && !codePlanOk ? (no ? 'Koden gjelder ikke valgt plan.' : 'Code does not apply to the selected plan.')
        : code && !codeBillingOk ? (no ? 'Koden gjelder ikke valgt billing.' : 'Code does not apply to the selected billing.')
        : code && !codeCurrencyOk ? (no ? 'Fast rabattbeløp har feil valuta for dette landet.' : 'Fixed amount discount has the wrong currency for this country.')
        : '';
      return el('div', { class:'adminCheckoutBox' }, [
        el('div', { class:'adminCheckoutHead' }, [
          el('div', {}, [
            el('h3', {}, [no?'Checkout / invoice preview':'Checkout / invoice preview']),
            el('p', { class:'muted small' }, [no
              ? 'Tester hvordan planpris, rabattkode og opptjent referral-credit skal treffe Stripe Checkout/invoice senere.'
              : 'Test how plan price, discount code and earned referral credit should affect Stripe Checkout/invoices later.'])
          ]),
          el('span', { class:'tag' }, [no?'MVP-kobling':'MVP wiring'])
        ]),
        el('div', { class:'adminCheckoutGrid' }, [
          el('label', {}, [el('span', { class:'muted small' }, [no?'Kjøkken':'Kitchen']), el('select', { class:'input', value:String(selected.id || ''), onchange:e=>{ state.admin.checkoutPreview.listing_id=e.target.value; const next=items.find(x=>String(x.id)===String(e.target.value)); if(next){ state.admin.checkoutPreview.plan=normalizePlan(next.plan||'basic'); state.admin.checkoutPreview.billing=next.billing||'monthly'; } render(); } }, items.map(x=>el('option', { value:String(x.id), selected:String(x.id)===String(selected.id) }, [x.name || x.slug || ('#'+x.id)]))) ]),
          el('label', {}, [el('span', { class:'muted small' }, [no?'Plan':'Plan']), el('select', { class:'input', value:plan, onchange:e=>{ state.admin.checkoutPreview.plan=e.target.value; render(); } }, ['basic','business','growth','pro'].map(x=>el('option', { value:x, selected:x===plan }, [planDisplayName(x)]))) ]),
          el('label', {}, [el('span', { class:'muted small' }, ['Billing']), el('select', { class:'input', value:billing, onchange:e=>{ state.admin.checkoutPreview.billing=e.target.value; render(); } }, [el('option',{value:'monthly',selected:billing==='monthly'},['Monthly']), el('option',{value:'yearly',selected:billing==='yearly'},['Yearly'])]) ]),
          el('label', {}, [el('span', { class:'muted small' }, [no?'Rabattkode':'Discount code']), el('input', { class:'input', value:draft.discount_code||'', placeholder:'WELCOME30', oninput:e=>{ state.admin.checkoutPreview.discount_code=e.target.value; render(); } })]),
          el('label', { class:'adminCheckLine' }, [el('input', { type:'checkbox', checked:!!draft.referral_credit, onchange:e=>{ state.admin.checkoutPreview.referral_credit=!!e.target.checked; render(); } }), el('span', {}, [no?'Bruk referral-credit hvis tilgjengelig':'Use referral credit if available'])])
        ]),
        warning ? el('div', { class:'adminInlineWarn' }, [warning]) : null,
        el('div', { class:'adminCheckoutTotals' }, [
          el('div', {}, [el('span', {}, [no?'Grunnpris':'Base price']), el('strong', {}, [fmt(base)])]),
          el('div', {}, [el('span', {}, [no?'Rabattkode':'Discount code']), el('strong', {}, ['− ' + fmt(discount)])]),
          el('div', {}, [el('span', {}, [no?'Referral-credit':'Referral credit']), el('strong', {}, ['− ' + fmt(credit)])]),
          el('div', { class:'adminCheckoutTotal' }, [el('span', {}, [no?'Estimert betaling':'Estimated charge']), el('strong', {}, [fmt(total)])])
        ]),
        el('div', { class:'muted small' }, [no
          ? 'Dette trekker ikke penger og endrer ikke Stripe. Det gir en tydelig lokal regel før rabattkoder/referral-credit kobles til ekte Stripe-kuponger, promotion codes eller invoice credits.'
          : 'This does not charge money or change Stripe. It defines the local rule before discount codes/referral credit are connected to real Stripe coupons, promotion codes or invoice credits.'])
      ].filter(Boolean));
    }


    function stripeEventsBox(){
      const allEvents = state.admin.stripeEvents || [];
      const st = state.admin.stripeEventStatus || 'all';
      const typ = state.admin.stripeEventType || 'all';
      const qq = String(state.admin.stripeEventQ || '').trim().toLowerCase();
      const types = Array.from(new Set(allEvents.map(e=>e.event_type).filter(Boolean))).sort();
      let evs = allEvents.slice();
      if (st !== 'all') evs = evs.filter(e=>String(e.status||'')===st);
      if (typ !== 'all') evs = evs.filter(e=>String(e.event_type||'')===typ);
      if (qq) evs = evs.filter(e=>[e.event_id,e.event_type,e.status,e.source,e.message,e.subscription_id,e.customer_id,e.listing_name,e.listing_customer_no].join(' ').toLowerCase().includes(qq));
      const badgeTone = e => String(e.status||'') === 'processed' ? 'tag-ok' : (String(e.status||'') === 'error' ? 'tag-warn' : '');
      return el('div', { class:'adminStripeEventsBox' }, [
        el('div', { class:'adminPanelHead' }, [
          el('div', {}, [
            el('h3', {}, [no?'Webhook-eventer / testlogg':'Webhook events / test log']),
            el('p', { class:'muted small' }, [no
              ? 'Viser ekte Stripe-webhook-eventer når webhook er koblet, og lokale admin-simuleringer mens du tester.'
              : 'Shows real Stripe webhook events when connected, and local admin simulations while testing.'])
          ]),
          button(no?'Oppdater':'Refresh', { variant:'outline', onclick: refresh })
        ]),
        el('div', { class:'row', style:'gap:8px; flex-wrap:wrap; margin:8px 0 12px' }, [
          el('select', { class:'input', style:'max-width:190px', value:st, onchange:e=>{state.admin.stripeEventStatus=e.target.value; render();} }, [
            el('option',{value:'all',selected:st==='all'},[no?'Alle statuser':'All statuses']),
            el('option',{value:'processed',selected:st==='processed'},['processed']),
            el('option',{value:'simulated',selected:st==='simulated'},['simulated']),
            el('option',{value:'ignored',selected:st==='ignored'},['ignored']),
            el('option',{value:'error',selected:st==='error'},['error'])
          ]),
          el('select', { class:'input', style:'max-width:260px', value:typ, onchange:e=>{state.admin.stripeEventType=e.target.value; render();} }, [
            el('option',{value:'all',selected:typ==='all'},[no?'Alle eventer':'All events'])
          ].concat(types.map(t=>el('option',{value:t,selected:typ===t},[t])))),
          el('input', { class:'input', style:'max-width:360px', placeholder:no?'Søk event, Stripe-ID eller kjøkken':'Search event, Stripe ID or kitchen', value:state.admin.stripeEventQ||'', oninput:e=>{state.admin.stripeEventQ=e.target.value; render();} })
        ]),
        !evs.length ? el('div', { class:'adminEmpty' }, [no?'Ingen Stripe-eventer ennå. Bruk simuleringsknappene under, eller koble ekte webhook senere.':'No Stripe events yet. Use the simulation buttons below, or connect the real webhook later.']) :
          el('div', { class:'adminStripeEventRows' }, evs.slice(0,40).map(e=>el('div',{class:'adminStripeEventRow'},[
            el('div',{},[
              el('strong',{},[e.event_type || 'event']),
              el('div',{class:'muted small'},[(e.listing_name || (no?'Ukjent kjøkken':'Unknown kitchen')) + (e.listing_customer_no ? ' · ' + e.listing_customer_no : '')]),
              el('div',{class:'muted small',style:'word-break:break-all'},[(e.subscription_id || e.event_id || '')])
            ]),
            el('div',{class:'adminStripeEventMeta'},[
              el('span',{class:'tag '+badgeTone(e)},[e.status || '']),
              el('span',{class:'tag'},[e.source || '']),
              el('span',{class:'muted small'},[e.created_at || ''])
            ]),
            el('div',{class:'muted small'},[e.message || ''])
          ])))
      ]);
    }

    return el('div', { class:'adminPanel adminBillingPanel' }, [
      el('div', { class:'adminPanelHead' }, [
        el('div', {}, [
          el('h2', {}, [no?'Stripe / betaling':'Stripe / Billing']),
          el('p', { class:'muted' }, [no
            ? 'Arbeidsflate for å teste og følge Stripe-status før ekte webhooks kobles i produksjon.'
            : 'Workspace for testing and reviewing Stripe status before real production webhooks are connected.'])
        ]),
        el('div', { class:'row', style:'gap:8px; flex-wrap:wrap' }, [
          button(no?'Synk synlighet':'Sync visibility', { variant:'outline', onclick: syncBillingVisibility }),
          button(no?'Oppdater':'Refresh', { variant:'outline', onclick: refresh })
        ])
      ]),
      el('div', { class:'adminStatsRow' }, [
        stat(no?'Betalt':'Paid', paid, 'paid', 'green'),
        stat(no?'Forfalt':'Past due', pastDue, 'past_due', 'amber'),
        stat(no?'Kansellert':'Cancelled', cancelled, 'cancelled', ''),
        stat(no?'Mangler Stripe-ID':'Missing Stripe ID', missingStripe, 'missing_stripe', 'amber')
      ]),
      el('div', { class:'adminBuildNote' }, [no
        ? 'Dette er fortsatt lokal/dev-simulering. Når Stripe-webhook-secret og ekte Checkout er koblet, skal de samme feltene oppdateres automatisk av /api/billing/webhook.'
        : 'This is still local/dev simulation. Once Stripe webhook secret and real Checkout are connected, the same fields will be updated automatically by /api/billing/webhook.']),
      checkoutPreviewBox(),
      stripeEventsBox(),
      el('div', { class:'row', style:'gap:10px; margin:12px 0; flex-wrap:wrap' }, [
        el('select', { class:'input', style:'max-width:220px', value:mode, onchange:(e)=>{ state.admin.billingStatus=e.target.value; render(); } }, [
          el('option', { value:'all', selected:mode==='all' }, [no?'Alle':'All']),
          el('option', { value:'paid', selected:mode==='paid' }, [no?'Betalt':'Paid']),
          el('option', { value:'past_due', selected:mode==='past_due' }, [no?'Forfalt':'Past due']),
          el('option', { value:'cancelled', selected:mode==='cancelled' }, [no?'Kansellert':'Cancelled']),
          el('option', { value:'missing_stripe', selected:mode==='missing_stripe' }, [no?'Mangler Stripe-ID':'Missing Stripe ID'])
        ]),
        el('input', { class:'input', style:'max-width:360px', placeholder:no?'Søk kjøkken, plan, status eller Stripe-ID':'Search kitchen, plan, status or Stripe ID', value:state.admin.billingQ||'', oninput:(e)=>{ state.admin.billingQ=e.target.value; render(); } })
      ]),
      el('div', { class:'adminStripeRows' }, rows.map(it => {
        const stripeLine = String(it.stripe_subscription_id||'').trim() || (no?'Ingen Stripe subscription ID ennå':'No Stripe subscription ID yet');
        return el('div', { class:'adminStripeRow' }, [
          el('div', { class:'adminStripeMain' }, [
            el('strong', {}, [it.name || it.slug || ('#'+it.id)]),
            el('div', { class:'muted small' }, [planDisplayName(normalizePlan(it.plan||'basic')) + ' · ' + (it.billing || 'monthly') + ' · ' + (it.country || 'NO')]),
            el('div', { class:'muted small', style:'word-break:break-all' }, ['Stripe: ', stripeLine])
          ]),
          el('div', { class:'adminStripeBadges' }, [
            el('span', { class:'tag ' + (String(it.paid_status||'')==='paid'?'tag-ok':'') }, [it.paid_status || 'unpaid']),
            el('span', { class:'tag' }, [it.account_status || 'active']),
            el('span', { class:'tag' }, [it.stripe_status || 'no stripe status']),
            el('span', { class:'tag ' + (String(it.billing_visibility||'')==='public'?'tag-ok':'') }, [it.billing_visibility || 'hidden'])
          ]),
          el('div', { class:'adminStripeActions' }, [
            button(no?'Simuler paid':'Simulate paid', { variant:'outline', onclick:()=>simulateStripeEvent(it.id, 'invoice.paid') }),
            button(no?'Simuler past_due':'Simulate past_due', { variant:'outline', onclick:()=>simulateStripeEvent(it.id, 'invoice.payment_failed') }),
            button(no?'Simuler cancelled':'Simulate cancelled', { variant:'outline', onclick:()=>simulateStripeEvent(it.id, 'customer.subscription.deleted') })
          ])
        ]);
      }))
    ]);
  }

  function discountContent(){
    const all = state.admin.discountCodes || [];
    const q = String(state.admin.discountQ || '').trim().toLowerCase();
    const f = state.admin.discountFilter || 'all';
    const todayIso = new Date().toISOString().slice(0,10);
    const nextMonthIso = (()=>{ const d=new Date(); d.setMonth(d.getMonth()+1); return d.toISOString().slice(0,10); })();
    let rows = all.slice();
    if (f === 'active') rows = rows.filter(c=>c.active && c.usable_now);
    if (f === 'inactive') rows = rows.filter(c=>!c.active);
    if (f === 'expired') rows = rows.filter(c=>c.active && !c.usable_now);
    if (f === 'percent') rows = rows.filter(c=>(c.discount_type||'percent')==='percent');
    if (f === 'amount') rows = rows.filter(c=>(c.discount_type||'percent')==='amount');
    if (f === 'limited') rows = rows.filter(c=>!!c.max_redemptions);
    if (q) rows = rows.filter(c=>[c.code,c.description,c.internal_note,c.applies_to_plan,c.billing,c.discount_type,c.currency].join(' ').toLowerCase().includes(q));
    const editing = state.admin.discountEditId;
    const stats = {
      total: all.length,
      active: all.filter(c=>c.active && c.usable_now).length,
      inactive: all.filter(c=>!c.active).length,
      notNow: all.filter(c=>c.active && !c.usable_now).length,
      limited: all.filter(c=>!!c.max_redemptions).length
    };
    function baseDiscountDraft(){
      return { code:'', description:'', discount_type:'percent', percent_off:20, amount_off:'', currency:'', applies_to_plan:'all', billing:'all', max_redemptions:'', active:true, starts_at:'', ends_at:'', internal_note:'' };
    }
    if (!state.admin.discountDraft) state.admin.discountDraft = baseDiscountDraft();
    const emptyDraft = state.admin.discountDraft;

    function applyDiscountPreset(kind){
      const p = baseDiscountDraft();
      if (kind === 'launch20') Object.assign(p, { code:'LAUNCH20', description:'Launch offer', percent_off:20, max_redemptions:100, starts_at:todayIso, internal_note:'General launch discount.' });
      if (kind === 'welcome30') Object.assign(p, { code:'WELCOME30', description:'First month welcome offer', percent_off:30, billing:'monthly', max_redemptions:50, starts_at:todayIso, ends_at:nextMonthIso, internal_note:'Short welcome campaign.' });
      if (kind === 'annual10') Object.assign(p, { code:'YEAR10', description:'Annual plan discount', percent_off:10, billing:'yearly', starts_at:todayIso, internal_note:'Encourage yearly subscriptions.' });
      if (kind === 'growth15') Object.assign(p, { code:'GROWTH15', description:'Growth plan upgrade offer', percent_off:15, applies_to_plan:'growth', starts_at:todayIso, ends_at:nextMonthIso, internal_note:'Upgrade campaign from Basic/Business to Growth.' });
      state.admin.discountDraft = p;
      render();
    }

    function duplicateDiscount(c){
      state.admin.discountDraft = {
        code: String((c.code||'CODE') + '_COPY').replace(/[^A-Z0-9_-]/gi,'').toUpperCase(),
        description: c.description || '',
        discount_type: c.discount_type || 'percent',
        percent_off: c.percent_off || '',
        amount_off: c.amount_off || '',
        currency: c.currency || '',
        applies_to_plan: c.applies_to_plan || 'all',
        billing: c.billing || 'all',
        max_redemptions: c.max_redemptions || '',
        active: false,
        starts_at: c.starts_at || '',
        ends_at: c.ends_at || '',
        internal_note: ((c.internal_note||'') + ' Duplicated from ' + (c.code||'')).trim()
      };
      state.admin.discountEditId = null;
      render();
      setTimeout(()=>document.querySelector('.adminDiscountCreate')?.scrollIntoView({behavior:'smooth', block:'start'}), 40);
    }

    function form(c, isNew){
      const id = isNew ? 'new' : c.id;
      const typeId = `disc_type_${id}`;
      const currentType = String(c.discount_type || 'percent');
      return el('div', { class:'adminDiscountForm' }, [
        el('div', { class:'adminDiscountGrid' }, [
          el('label', { class:'field' }, [el('span', {}, ['Code']), el('input', { class:'input', id:`disc_code_${id}`, value:c.code||'', placeholder:'WELCOME20', oninput:(e)=>{ c.code=e.target.value; } })]),
          el('label', { class:'field' }, [el('span', {}, ['Description']), el('input', { class:'input', id:`disc_desc_${id}`, value:c.description||'', placeholder:'Launch offer', oninput:(e)=>{ c.description=e.target.value; } })]),
          el('label', { class:'field' }, [el('span', {}, ['Type']), el('select', { class:'input', id:typeId, value:currentType, onchange:(e)=>{
            c.discount_type = e.target.value;
            if (c.discount_type === 'amount' && !c.currency) c.currency = 'NOK';
            render();
          } }, [
            el('option', { value:'percent', selected:currentType==='percent' }, ['Percent']),
            el('option', { value:'amount', selected:currentType==='amount' }, ['Fixed amount'])
          ])]),
          el('label', { class:'field' }, [el('span', {}, ['Percent off']), el('input', { class:'input', id:`disc_percent_${id}`, type:'number', min:'0', max:'100', value:String(c.percent_off ?? ''), oninput:(e)=>{ c.percent_off=e.target.value; } })]),
          el('label', { class:'field' }, [el('span', {}, ['Amount off']), el('input', { class:'input', id:`disc_amount_${id}`, type:'number', min:'0', step:'0.01', value:String(c.amount_off ?? ''), placeholder:'10.00', oninput:(e)=>{ c.amount_off=e.target.value; } })]),
          el('label', { class:'field' }, [el('span', {}, ['Currency']), el('select', { class:'input', id:`disc_currency_${id}`, value:((c.currency||'') || (currentType==='amount'?'NOK':'')).toUpperCase(), onchange:(e)=>{ c.currency=e.target.value; }, oninput:(e)=>{ c.currency=e.target.value; } }, discountCurrencyOptions((c.currency||'') || (currentType==='amount'?'NOK':'')))]) ,
          el('label', { class:'field' }, [el('span', {}, ['Plan']), el('select', { class:'input', id:`disc_plan_${id}`, value:c.applies_to_plan||'all', onchange:(e)=>{ c.applies_to_plan=e.target.value; } }, ['all','basic','business','growth','pro'].map(v=>el('option',{value:v,selected:(c.applies_to_plan||'all')===v},[v])))]),
          el('label', { class:'field' }, [el('span', {}, ['Billing']), el('select', { class:'input', id:`disc_billing_${id}`, value:c.billing||'all', onchange:(e)=>{ c.billing=e.target.value; } }, ['all','monthly','yearly'].map(v=>el('option',{value:v,selected:(c.billing||'all')===v},[v])))]),
          el('label', { class:'field' }, [el('span', {}, ['Max redemptions']), el('input', { class:'input', id:`disc_max_${id}`, type:'number', min:'0', value:String(c.max_redemptions ?? ''), oninput:(e)=>{ c.max_redemptions=e.target.value; } })]),
          el('label', { class:'field' }, [el('span', {}, ['Starts']), el('input', { class:'input', id:`disc_start_${id}`, type:'date', value:c.starts_at||'', onchange:(e)=>{ c.starts_at=e.target.value; } })]),
          el('label', { class:'field' }, [el('span', {}, ['Ends']), el('input', { class:'input', id:`disc_end_${id}`, type:'date', value:c.ends_at||'', onchange:(e)=>{ c.ends_at=e.target.value; } })]),
          el('label', { class:'field adminCheckLine' }, [el('input', { type:'checkbox', id:`disc_active_${id}`, checked:c.active!==false, onchange:(e)=>{ c.active=!!e.target.checked; } }), el('span', {}, ['Active'])])
        ]),
        el('label', { class:'field' }, [el('span', {}, ['Internal note']), el('textarea', { class:'input', id:`disc_note_${id}`, style:'width:100%;min-height:64px', value:c.internal_note||'', oninput:(e)=>{ c.internal_note=e.target.value; } }, [])]),
        el('div', { class:'row', style:'gap:8px; flex-wrap:wrap' }, [
          button(isNew ? (state.lang==='no'?'Opprett kode':'Create code') : (state.lang==='no'?'Lagre kode':'Save code'), { variant:'primary', onclick:()=>{
            const chosenType = document.getElementById(`disc_type_${id}`)?.value || 'percent';
            const chosenCurrency = chosenType === 'amount' ? (document.getElementById(`disc_currency_${id}`)?.value || '') : '';
            if (chosenType === 'amount' && !chosenCurrency){
              alert(state.lang==='no' ? 'Velg valuta for fast beløp-rabatt.' : 'Choose a currency for fixed amount discounts.');
              return;
            }
            const payload = {
              code: document.getElementById(`disc_code_${id}`)?.value || '',
              description: document.getElementById(`disc_desc_${id}`)?.value || '',
              discount_type: chosenType,
              percent_off: Number(document.getElementById(`disc_percent_${id}`)?.value || 0),
              amount_off: Number(document.getElementById(`disc_amount_${id}`)?.value || 0),
              currency: chosenCurrency,
              applies_to_plan: document.getElementById(`disc_plan_${id}`)?.value || 'all',
              billing: document.getElementById(`disc_billing_${id}`)?.value || 'all',
              max_redemptions: document.getElementById(`disc_max_${id}`)?.value || '',
              active: !!document.getElementById(`disc_active_${id}`)?.checked,
              starts_at: document.getElementById(`disc_start_${id}`)?.value || '',
              ends_at: document.getElementById(`disc_end_${id}`)?.value || '',
              internal_note: document.getElementById(`disc_note_${id}`)?.value || ''
            };
            saveDiscountCode(payload, isNew ? null : c.id);
          }}),
          (!isNew ? button(state.lang==='no'?'Avbryt':'Cancel', { variant:'outline', onclick:()=>{state.admin.discountEditId=null; render();} }) : null)
        ].filter(Boolean))
      ]);
    }

    function row(c){
      if (editing === c.id) return el('div', { class:'adminDiscountCard' }, [form(c, false)]);
      return el('div', { class:'adminDiscountCard' }, [
        el('div', { class:'adminDiscountTop' }, [
          el('div', {}, [
            el('strong', { class:'adminDiscountCode' }, [c.code]),
            el('div', { class:'muted small' }, [[discountLabel(c), c.description, c.applies_to_plan && c.applies_to_plan!=='all' ? c.applies_to_plan : '', c.billing && c.billing!=='all' ? c.billing : ''].filter(Boolean).join(' · ')])
          ]),
          el('div', { class:'row', style:'gap:6px; flex-wrap:wrap; justify-content:flex-end' }, [
            el('span', { class:'tag ' + (c.usable_now ? 'tag-ok' : 'tag-warn') }, [discountStatus(c)]),
            el('span', { class:'tag' }, [`${c.redemption_count||0}/${c.max_redemptions||'∞'}`])
          ])
        ]),
        el('div', { class:'adminDiscountMeta' }, [
          el('span', {}, ['Valid: ' + [c.starts_at||'now', c.ends_at||'no end'].join(' → ')]),
          c.internal_note ? el('span', {}, ['Note: ' + c.internal_note]) : null
        ].filter(Boolean)),
        el('div', { class:'row', style:'gap:8px; flex-wrap:wrap; margin-top:10px' }, [
          button(state.lang==='no'?'Rediger':'Edit', { variant:'outline', onclick:()=>{state.admin.discountEditId=c.id; render();} }),
          button(state.lang==='no'?'Kopier':'Duplicate', { variant:'outline', onclick:()=>duplicateDiscount(c) }),
          button(c.active ? (state.lang==='no'?'Deaktiver':'Deactivate') : (state.lang==='no'?'Aktiver':'Activate'), { variant:'outline', onclick:()=>toggleDiscountCode(c.id, !c.active) })
        ])
      ]);
    }

    return el('div', { class:'adminPanel adminDiscountPanel' }, [
      el('div', { class:'adminPanelHead' }, [
        el('div', {}, [
          el('h2', {}, [state.lang==='no'?'Rabattkoder':'Discount codes']),
          el('p', { class:'muted' }, [state.lang==='no'
            ? 'MVP for rabattkoder: opprett, tidsstyr, avgrens mot plan/billing og deaktiver koder. Stripe/checkout-kobling kan bygges i neste betalingsrunde.'
            : 'MVP for discount codes: create, time-limit, restrict to plan/billing and deactivate codes. Percent discounts are currency-independent; fixed amount discounts require a valid currency. Stripe/checkout integration can be added in a later billing step. Select Fixed amount to enable Amount off and Currency.'])
        ]),
        el('div', { class:'adminToolbar' }, [
          el('select', { class:'input', value:f, onchange:(e)=>{state.admin.discountFilter=e.target.value; render();} }, [
            el('option', { value:'all', selected:f==='all' }, ['All']),
            el('option', { value:'active', selected:f==='active' }, ['Active now']),
            el('option', { value:'inactive', selected:f==='inactive' }, ['Inactive']),
            el('option', { value:'expired', selected:f==='expired' }, ['Not usable now']),
            el('option', { value:'percent', selected:f==='percent' }, ['Percent']),
            el('option', { value:'amount', selected:f==='amount' }, ['Fixed amount']),
            el('option', { value:'limited', selected:f==='limited' }, ['Limited redemptions'])
          ]),
          el('input', { class:'input adminSearchInput', placeholder:state.lang==='no'?'Søk kode/notat':'Search code/note', value:state.admin.discountQ||'', oninput:(e)=>{state.admin.discountQ=e.target.value; render();} })
        ])
      ]),
      el('div', { class:'adminMiniStats adminDiscountStats' }, [
        el('button', { class:'adminMiniStat', onclick:()=>{state.admin.discountFilter='all'; render();} }, [el('strong', {}, [String(stats.total)]), el('span', {}, ['All codes'])]),
        el('button', { class:'adminMiniStat', onclick:()=>{state.admin.discountFilter='active'; render();} }, [el('strong', {}, [String(stats.active)]), el('span', {}, ['Active now'])]),
        el('button', { class:'adminMiniStat', onclick:()=>{state.admin.discountFilter='expired'; render();} }, [el('strong', {}, [String(stats.notNow)]), el('span', {}, ['Not usable now'])]),
        el('button', { class:'adminMiniStat', onclick:()=>{state.admin.discountFilter='limited'; render();} }, [el('strong', {}, [String(stats.limited)]), el('span', {}, ['Limited'])])
      ]),
      el('div', { class:'adminDiscountPresets' }, [
        el('span', { class:'muted small' }, [state.lang==='no'?'Hurtigmaler:':'Quick presets:']),
        button('LAUNCH20', { variant:'outline', onclick:()=>applyDiscountPreset('launch20') }),
        button('WELCOME30', { variant:'outline', onclick:()=>applyDiscountPreset('welcome30') }),
        button('YEAR10', { variant:'outline', onclick:()=>applyDiscountPreset('annual10') }),
        button('GROWTH15', { variant:'outline', onclick:()=>applyDiscountPreset('growth15') })
      ]),
      el('div', { class:'adminDiscountCreate' }, [
        el('h3', {}, [state.lang==='no'?'Ny rabattkode':'New discount code']),
        form(emptyDraft, true)
      ]),
      (!rows.length ? el('div', { class:'adminEmpty' }, [state.lang==='no'?'Ingen rabattkoder ennå.':'No discount codes yet.']) : null),
      el('div', { class:'adminDiscountList' }, rows.map(row)),
      el('div', { class:'adminBuildNote' }, [state.lang==='no'
        ? 'Rabattkodene lagres nå i databasen og loggføres i Activity log. De trekkes ikke automatisk fra betaling i Stripe ennå.'
        : 'Discount codes are now stored in the database and logged in Activity log. They do not automatically reduce Stripe payment yet.'])
    ]);
  }


  function activityLabel(action){
    const no = state.lang === 'no';
    const mapNo = {
      listing_update:'Aktør oppdatert', listing_activate:'Aktør aktivert', listing_deactivate:'Aktør deaktivert',
      ticket_reply:'Ticketsvar', ticket_update:'Ticket oppdatert', settings_update:'Settings endret',
      billing_visibility_sync:'Betalingssynlighet synkronisert', view_as_kitchen:'View as kitchen', discount_code_create:'Rabattkode opprettet', discount_code_update:'Rabattkode oppdatert', discount_code_toggle:'Rabattkode aktivert/deaktivert', production_review:'Produksjonsgjennomgang'
    };
    const mapEn = {
      listing_update:'Listing updated', listing_activate:'Listing activated', listing_deactivate:'Listing deactivated',
      ticket_reply:'Ticket reply', ticket_update:'Ticket updated', settings_update:'Settings changed',
      billing_visibility_sync:'Billing visibility synced', view_as_kitchen:'View as kitchen', discount_code_create:'Discount code created', discount_code_update:'Discount code updated', discount_code_toggle:'Discount code toggled', production_review:'Production review', announcement_create:'Popup message created', announcement_status:'Popup message status'
    };
    return (no ? mapNo[action] : mapEn[action]) || action || '—';
  }

  function activityContent(){
    let rows = Array.isArray(state.admin.activity) ? state.admin.activity : [];
    const q = String(state.admin.activityQ || '').trim().toLowerCase();
    const action = state.admin.activityAction || 'all';
    if (action !== 'all') rows = rows.filter(r => String(r.action||'') === action);
    if (q) rows = rows.filter(r => [r.customer_no,r.listing_name,r.title,r.action,JSON.stringify(r.details||{})].join(' ').toLowerCase().includes(q));
    const activitySource = Array.isArray(state.admin.activity) ? state.admin.activity : [];
    const actions = Array.from(new Set(activitySource.map(r=>r && r.action).filter(Boolean))).sort();
    const detailText = (r)=>{
      let d = (r && r.details) || {};
      if (typeof d === 'string') { try{ d = JSON.parse(d); }catch(_){ d = { text:d }; } }
      if (!d || typeof d !== 'object') d = {};
      if (r.action === 'listing_update'){
        const keys = Object.keys(d.changed || {});
        return keys.length ? keys.join(', ') : (d.patch_keys || []).join(', ');
      }
      if (r.action === 'ticket_update') return ['status:'+ (d.status||'—'), 'priority:'+(d.priority||'—')].join(' · ');
      if (r.action === 'settings_update') return Object.keys(d.patch || {}).join(', ');
      if (r.action === 'billing_visibility_sync') return 'changed: ' + (d.changed ?? 0);
      if (r.action === 'ticket_reply') return d.is_internal ? (state.lang==='no'?'Intern note':'Internal note') : (state.lang==='no'?'Svar til aktør':'Reply to kitchen');
      return r.title || '';
    };
    return el('div', { class:'adminPanel adminActivityPanel' }, [
      el('div', { class:'adminPanelHead' }, [
        el('div', {}, [
          el('h2', {}, [state.lang==='no'?'Aktivitetslogg':'Activity log']),
          el('p', { class:'muted' }, [state.lang==='no'
            ? 'MVP-logg for viktige adminhandlinger: tilgang, status, support, settings, billing sync og View as kitchen.'
            : 'MVP log for important admin actions: access, status, support, settings, billing sync and View as kitchen.'])
        ]),
        el('div', { class:'adminToolbar' }, [
          el('select', { class:'input', value: action, onchange:(e)=>{ state.admin.activityAction = e.target.value; render(); } }, [
            el('option', { value:'all', selected: action==='all' }, [(state.lang==='no'?'Alle handlinger':'All actions')]),
            ...actions.map(a=>el('option', { value:a, selected: action===a }, [activityLabel(a)]))
          ]),
          el('input', { class:'input adminSearchInput', placeholder: state.lang==='no'?'Søk ID, aktør, handling':'Search ID, kitchen, action', value: state.admin.activityQ || '', oninput:(e)=>{ state.admin.activityQ = e.target.value; render(); } })
        ])
      ]),
      (!rows.length ? el('div', { class:'adminEmpty' }, [state.lang==='no'?'Ingen loggførte handlinger ennå.':'No logged actions yet.']) : null),
      el('div', { class:'adminActivityRows' }, rows.map(r=> el('div', { class:'adminActivityRow' }, [
        el('div', { class:'adminActivityMain' }, [
          el('strong', {}, [activityLabel(r.action)]),
          el('span', { class:'muted small' }, [
            [r.customer_no, r.listing_name || r.title].filter(Boolean).join(' · ') || 'System'
          ]),
          detailText(r) ? el('span', { class:'muted tiny' }, [detailText(r)]) : null
        ].filter(Boolean)),
        el('div', { class:'adminActivityMeta' }, [
          el('span', { class:'tag' }, [r.actor || 'admin']),
          el('span', { class:'muted tiny' }, [String(r.created_at || '').replace('T',' ').slice(0,19)])
        ])
      ])))
    ]);
  }


  async function saveAdminUser(userId){
    const prefix = userId ? ('adminUser_'+userId+'_') : 'adminUser_new_';
    const payload = {
      name: document.getElementById(prefix+'name')?.value || '',
      email: document.getElementById(prefix+'email')?.value || '',
      role: document.getElementById(prefix+'role')?.value || 'viewer',
      active: !!document.getElementById(prefix+'active')?.checked,
      internal_note: document.getElementById(prefix+'note')?.value || ''
    };
    try{
      const key = encodeURIComponent(state.admin.key || '');
      const url = userId ? adminUrl(`/api/admin/users/${userId}`) : adminUrl('/api/admin/users');
      await apiJson('POST', url, payload);
      const au = await apiGet(adminUrl('/api/admin/users'));
      state.admin.adminUsers = au.items || [];
      state.admin.adminUserEditId = null;
      try{
        const al = await apiGet(adminUrl('/api/admin/activity?limit=120'));
        state.admin.activity = al.items || [];
      }catch(e){}
      render();
    }catch(e){ alert('Admin user update failed: ' + (e.message||e)); }
  }

  async function markAdminSeen(userId){
    try{
      const key = encodeURIComponent(state.admin.key || '');
      await apiJson('POST', adminUrl(`/api/admin/users/${userId}/seen`), {});
      const au = await apiGet(adminUrl('/api/admin/users'));
      state.admin.adminUsers = au.items || [];
      const al = await apiGet(adminUrl('/api/admin/activity?limit=120'));
      state.admin.activity = al.items || [];
      render();
    }catch(e){ alert('Could not mark admin as seen: ' + (e.message||e)); }
  }

  function adminUsersContent(){
    const users = state.admin.adminUsers || [];
    const roles = ['owner','admin','support','billing','viewer'];
    const roleText = {
      owner: state.lang==='no'?'Owner / full tilgang':'Owner / full access',
      admin: state.lang==='no'?'Admin / drift':'Admin / operations',
      support: state.lang==='no'?'Support / tickets':'Support / tickets',
      billing: state.lang==='no'?'Billing / betaling':'Billing / payments',
      viewer: state.lang==='no'?'Viewer / kun lese':'Viewer / read-only'
    };
    const permissionRows = [
      { key:'kitchens', label: state.lang==='no'?'Kjøkken / aktivering':'Kitchens / activation', owner:1, admin:1, support:0, billing:0, viewer:1 },
      { key:'tickets', label: state.lang==='no'?'Support tickets':'Support tickets', owner:1, admin:1, support:1, billing:0, viewer:1 },
      { key:'billing', label: state.lang==='no'?'Betaling / Stripe':'Billing / Stripe', owner:1, admin:1, support:0, billing:1, viewer:1 },
      { key:'discounts', label: state.lang==='no'?'Rabattkoder / credits':'Discounts / credits', owner:1, admin:1, support:0, billing:1, viewer:1 },
      { key:'notifications', label: state.lang==='no'?'Varsler / e-post':'Notifications / email', owner:1, admin:1, support:1, billing:0, viewer:1 },
      { key:'communications', label: state.lang==='no'?'E-post til aktører':'Owner email communications', owner:1, admin:1, support:1, billing:0, viewer:0 },
      { key:'settings', label: state.lang==='no'?'Systeminnstillinger':'System settings', owner:1, admin:1, support:0, billing:0, viewer:0 },
      { key:'admin_users', label: state.lang==='no'?'Admin-brukere / roller':'Admin users / roles', owner:1, admin:0, support:0, billing:0, viewer:0 }
    ];
    const selectedRole = state.admin.testRole || localStorage.getItem('rm_admin_test_role') || 'owner';
    state.admin.testRole = selectedRole;
    const canForRole = (row, role)=>!!row[role];
    function mark(v){ return el('span', { class:'adminPermMark ' + (v ? 'ok' : 'no') }, [v ? '✓' : '–']); }
    const permissionMatrix = el('div', { class:'adminPermissionPanel' }, [
      el('div', { class:'adminPanelHead compact' }, [
        el('div', {}, [
          el('h3', {}, [state.lang==='no'?'Rolle- og tilgangsmatrise':'Role and permission matrix']),
          el('p', { class:'muted small' }, [state.lang==='no'
            ? 'Brukes til å se hva hver rolle bør kunne gjøre når ekte innlogging/2FA kobles. Foreløpig er dette en test-/planleggingsflate.'
            : 'Used to see what each role should be able to do when real login/2FA is connected. For now this is a test/planning surface.'])
        ]),
        el('label', { class:'adminRoleTestSelect' }, [
          el('span', { class:'muted small' }, [state.lang==='no'?'Test som rolle':'Test as role']),
          el('select', { class:'input', value:selectedRole, onchange:(e)=>{ state.admin.testRole=e.target.value; localStorage.setItem('rm_admin_test_role', e.target.value); render(); } }, roles.map(r=>el('option', { value:r, selected:selectedRole===r }, [roleText[r]])))
        ])
      ]),
      el('div', { class:'adminPermTableWrap' }, [
        el('table', { class:'adminPermTable' }, [
          el('thead', {}, [el('tr', {}, [el('th', {}, [state.lang==='no'?'Område':'Area'])].concat(roles.map(r=>el('th', {}, [r]))))]),
          el('tbody', {}, permissionRows.map(row=>el('tr', { class: canForRole(row, selectedRole) ? 'activeRoleAllowed' : '' }, [
            el('td', {}, [row.label])
          ].concat(roles.map(r=>el('td', {}, [mark(canForRole(row,r))]))))))
        ])
      ]),
      el('div', { class:'adminBuildNote' }, [state.lang==='no'
        ? `Valgt testrolle: ${roleText[selectedRole]}. Rader markeres der denne rollen bør ha tilgang. Neste produksjonssteg er ekte session-login, passordhash og 2FA.`
        : `Selected test role: ${roleText[selectedRole]}. Rows are highlighted where this role should have access. Next production step is real session login, password hashing and 2FA.`])
    ]);
    function formRow(u, isNew=false){
      const id = isNew ? null : u.id;
      const prefix = id ? ('adminUser_'+id+'_') : 'adminUser_new_';
      return el('div', { class:'adminUserCard' }, [
        el('div', { class:'adminUserGrid' }, [
          el('label', {}, [el('span', {}, [state.lang==='no'?'Navn':'Name']), el('input', { class:'input', id:prefix+'name', value:u.name||'', placeholder:'Marius / Support' })]),
          el('label', {}, [el('span', {}, ['Email']), el('input', { class:'input', id:prefix+'email', value:u.email||'', placeholder:'admin@ricemap24.com' })]),
          el('label', {}, [el('span', {}, ['Role']), el('select', { class:'input', id:prefix+'role' }, roles.map(r=>el('option', { value:r, selected:(u.role||'viewer')===r }, [roleText[r]])))]),
          el('label', { class:'adminCheckLine' }, [el('input', { type:'checkbox', id:prefix+'active', checked: u.active!==0 }), el('span', {}, [state.lang==='no'?'Aktiv':'Active'])])
        ]),
        el('textarea', { class:'input', id:prefix+'note', style:'width:100%; min-height:58px; margin-top:10px', placeholder: state.lang==='no'?'Internt notat':'Internal note' }, [u.internal_note||'']),
        el('div', { class:'row', style:'gap:8px; flex-wrap:wrap; margin-top:10px' }, [
          button(isNew ? (state.lang==='no'?'Opprett admin-bruker':'Create admin user') : (state.lang==='no'?'Lagre':'Save'), { variant:'primary', onclick:()=>saveAdminUser(id) }),
          (!isNew ? button(state.lang==='no'?'Marker innlogging/test':'Mark login/test', { variant:'outline', onclick:()=>markAdminSeen(id) }) : null),
          (!isNew ? el('span', { class:'tag '+(u.active!==0?'tag-ok':'tag-warn') }, [u.active!==0 ? 'active' : 'inactive']) : null),
          (!isNew && u.last_seen_at ? el('span', { class:'muted small' }, [(state.lang==='no'?'Sist sett: ':'Last seen: ') + u.last_seen_at]) : null)
        ].filter(Boolean))
      ]);
    }
    return el('div', { class:'adminPanel adminUsersPanel' }, [
      el('div', { class:'adminPanelHead' }, [
        el('div', {}, [
          el('h2', {}, [state.lang==='no'?'Admin-tilgang og roller':'Admin access and roles']),
          el('p', { class:'muted' }, [state.lang==='no'
            ? 'MVP-struktur for ekte admin-login senere. Her kan du definere hvem som skal ha owner/admin/support/billing/viewer-rolle, og handlinger logges i aktivitetsloggen.'
            : 'MVP structure for real admin login later. Define owner/admin/support/billing/viewer roles here; changes are written to the activity log.'])
        ]),
        el('span', { class:'tag' }, [(users.filter(u=>u.active!==0).length) + ' active'])
      ]),
      el('div', { class:'adminBuildNote' }, [state.lang==='no'
        ? 'Dette erstatter ikke ekte passord/2FA ennå. Admin key brukes fortsatt lokalt, men rollemodellen, tilgangsmatrisen og loggingen er nå klargjort for produksjonsinnlogging.'
        : 'Session login is now the normal admin path. The legacy admin key remains only as a manual development fallback until production auth is fully hardened.']),
      permissionMatrix,
      el('div', { class:'adminUsersList' }, users.map(u=>formRow(u))),
      el('h3', { style:'margin-top:18px' }, [state.lang==='no'?'Legg til admin-bruker':'Add admin user']),
      formRow({ role:'viewer', active:1 }, true)
    ]);
  }


  function productionSummaryText(){
    const pr = state.admin.productionReadiness || { checks:[], ready_count:0, total_count:0, mode:'local-mvp' };
    const checks = Array.isArray(pr.checks) ? pr.checks.filter(Boolean) : [];
    const missing = checks.filter(c=>!c.ready).map(c=>c.label || c.id || 'unknown');
    const stripeEvents = Array.isArray(state.admin.stripeEvents) ? state.admin.stripeEvents : [];
    const errorCount = stripeEvents.filter(e => String(e.status||'').toLowerCase()==='error').length;
    const lines = [
      'RiceMap24 production review',
      'Status: ' + (pr.ready_count || 0) + '/' + (pr.total_count || checks.length || 0) + ' checks ready',
      'Mode: ' + (pr.mode || 'local-mvp'),
      'Missing: ' + (missing.length ? missing.join(', ') : 'none'),
      'Stripe webhook events: ' + stripeEvents.length,
      'Stripe error events: ' + errorCount,
      'Reviewed: ' + new Date().toISOString()
    ];
    if (state.admin.productionNote) lines.push('Note: ' + state.admin.productionNote);
    return lines.join('\n');
  }

  async function logProductionReview(){
    try{
      const key = encodeURIComponent(state.admin.key || '');
      const pr = state.admin.productionReadiness || {};
      const stripeEvents = Array.isArray(state.admin.stripeEvents) ? state.admin.stripeEvents : [];
      const payload = {
        ready_count: pr.ready_count || 0,
        total_count: pr.total_count || ((pr.checks||[]).length || 0),
        mode: pr.mode || 'local-mvp',
        missing: (Array.isArray(pr.checks) ? pr.checks.filter(Boolean) : []).filter(c=>!c.ready).map(c=>c.id || c.label || 'unknown'),
        stripe_event_count: stripeEvents.length,
        stripe_error_count: stripeEvents.filter(e => e && String(e.status||'').toLowerCase()==='error').length,
        note: state.admin.productionNote || ''
      };
      await apiJson('POST', adminUrl('/api/admin/production-review'), payload);
      const al = await apiGet(adminUrl('/api/admin/activity?limit=120'));
      state.admin.activity = al.items || [];
      state.admin.productionNote = '';
      alert(state.lang==='no'?'Produksjonsgjennomgang loggført.':'Production review logged.');
      render();
    }catch(e){
      alert('Production review failed: ' + (e.message||e));
    }
  }


  function productionContent(){
    const no = state.lang === 'no';
    const pr = state.admin.productionReadiness && typeof state.admin.productionReadiness === 'object' ? state.admin.productionReadiness : {};
    const checks = Array.isArray(pr.checks) ? pr.checks.filter(Boolean) : [];
    const readyCount = Number(pr.ready_count || checks.filter(c=>c && c.ready).length || 0);
    const totalCount = Number(pr.total_count || checks.length || 0);
    const score = readyCount + '/' + totalCount;
    const stripeEvents = Array.isArray(state.admin.stripeEvents) ? state.admin.stripeEvents.filter(Boolean) : [];
    const recentErrors = stripeEvents.filter(e => String(e.status||'').toLowerCase()==='error').length;
    const missingChecks = checks.filter(c => c && !c.ready);
    const priceIds = (pr.price_ids && typeof pr.price_ids === 'object' && !Array.isArray(pr.price_ids)) ? pr.price_ids : {};
    const pilot = state.admin.pilotReadiness && typeof state.admin.pilotReadiness === 'object' ? state.admin.pilotReadiness : {};
    const pilotChecks = Array.isArray(pilot.checks) ? pilot.checks.filter(Boolean) : [];
    const pilotReadyCount = Number(pilot.ready_count || pilotChecks.filter(c=>c && c.ready).length || 0);
    const pilotTotalCount = Number(pilot.total_count || pilotChecks.length || 0);
    const pilotListings = pilot.listings && typeof pilot.listings === 'object' ? pilot.listings : {};
    const envTemplate = [
      '# RiceMap24 production env checklist',
      'RICEMAP_ENV=production',
      'RICEMAP_ADMIN_KEY=change-this-to-a-long-random-value',
      'RICEMAP_SESSION_SECRET=change-this-to-a-long-random-value',
      'DATABASE_URL=postgresql://...',
      'STRIPE_SECRET_KEY=sk_live_...',
      'STRIPE_WEBHOOK_SECRET=whsec_...',
      'RICEMAP_APP_URL=https://your-domain.example',
      ''
    ].join('\n');
    function copyText(txt, ok, manual){
      try{
        if (navigator.clipboard && navigator.clipboard.writeText){ navigator.clipboard.writeText(txt).then(()=>alert(ok)).catch(()=>prompt(manual, txt)); }
        else prompt(manual, txt);
      }catch(e){ prompt(manual, txt); }
    }
    const checkRow = (c)=>{
      c = c || {};
      const ready = !!c.ready;
      let detail = '';
      if (Array.isArray(c.missing) && c.missing.length) detail = (no?'Mangler: ':'Missing: ') + c.missing.join(', ');
      if (c.provider) detail = (detail ? detail + ' · ' : '') + 'Provider: ' + c.provider;
      if (typeof c.public_count !== 'undefined') detail = (detail ? detail + ' · ' : '') + (no?'Synlige: ':'Visible: ') + String(c.public_count);
      if (c.mode) detail = (detail ? detail + ' · ' : '') + 'Mode: ' + String(c.mode);
      return el('div', { class:'adminProdCheckRow ' + (ready ? 'is-ready' : 'is-missing') }, [
        el('div', {}, [el('strong', {}, [String(c.label || c.id || 'Check')]), detail ? el('div', { class:'muted small' }, [detail]) : null].filter(Boolean)),
        el('span', { class:'tag ' + (ready ? 'tag-ok' : 'tag-warn') }, [ready ? (no?'Klar':'Ready') : (no?'Mangler':'Missing')])
      ]);
    };
    const actionItems = [];
    if (missingChecks.some(c=>String(c.id||'')==='admin_session_auth' && !c.ready)) actionItems.push([no?'Stram inn admin-auth':'Harden admin auth', no?'Hold legacy-key deaktivert utenfor development og bruk session-login før lansering.':'Keep legacy key disabled outside development and use session login before launch.', 'settings']);
    if (missingChecks.some(c=>String(c.id||'').includes('https') || String(c.id||'').includes('session_secret') || String(c.id||'').includes('cors'))) actionItems.push([no?'Fullfør sikkerhetsoppsett':'Complete security setup', no?'Sett HTTPS public URL, session secret og eksakte CORS-domener før staging/production.':'Set HTTPS public URL, session secret and exact CORS domains before staging/production.', 'settings']);
    if (missingChecks.some(c=>String(c.id||'').includes('backup'))) actionItems.push([no?'Klargjør backup':'Prepare backup', no?'Aktiver database-/upload-backup og test restore før ekte brukere.':'Enable database/upload backup and test restore before real users.', 'settings']);
    if (missingChecks.some(c=>String(c.id||'').includes('monitoring'))) actionItems.push([no?'Koble feilmonitorering':'Connect error monitoring', no?'Sett opp enkel serverfeil-/webhook-/login-feilmonitorering før pilot.':'Set up basic server, webhook and login error monitoring before pilot.', 'settings']);
    if (missingChecks.some(c=>String(c.id||'').includes('stripe'))) actionItems.push([no?'Fullfør Stripe-oppsett':'Complete Stripe setup', no?'Koble produkter, pris-ID-er og webhook før betaling slås på.':'Connect products, price IDs and webhook before enabling payment.', 'billing']);
    if (missingChecks.some(c=>String(c.id||'').includes('email'))) actionItems.push([no?'Koble ekte e-post':'Connect real email', no?'Legg inn e-postleverandør og test varselkøen.':'Add email provider and test the notification queue.', 'notifications']);
    if (recentErrors) actionItems.push([no?'Sjekk webhook-feil':'Review webhook errors', String(recentErrors) + (no?' Stripe-event(s) har feilstatus.':' Stripe event(s) have error status.'), 'billing']);
    if (!actionItems.length) actionItems.push([no?'Kjør siste manuelle test':'Run final manual test', no?'Gjør én komplett test: registrering, betaling, webhook, tilgang og e-postvarsel.':'Run one full test: signup, payment, webhook, access and email notice.', 'billing']);
    const report = [
      'RiceMap24 production review',
      'Status: ' + score + ' checks ready',
      'Mode: ' + String(pr.mode || 'local-mvp'),
      'Missing: ' + (missingChecks.length ? missingChecks.map(c=>c.label || c.id || 'unknown').join(', ') : 'none'),
      'Stripe webhook events: ' + stripeEvents.length,
      'Stripe error events: ' + recentErrors,
      'Reviewed: ' + new Date().toISOString()
    ].join('\n');
    return el('div', { class:'adminPanel adminProductionPanel' }, [
      el('div', { class:'adminPanelHead' }, [
        el('div', {}, [
          el('h2', {}, [no?'Produksjonssjekk':'Production readiness']),
          el('p', { class:'muted' }, [no?'Stabil sjekk av miljø, secrets, Stripe og e-post før lansering.':'Stable check of environment, secrets, Stripe and email before launch.'])
        ]),
        el('div', { class:'adminProdScore' }, [el('strong', {}, [score]), el('span', {}, [String(pr.mode || 'MVP/local')])])
      ]),
      el('section', { class:'adminProdCard adminProdPilotCard' }, [
        el('div', { class:'adminProdLaunchHead' }, [
          el('div', {}, [
            el('h3', {}, [no?'Pilot readiness':'Pilot readiness']),
            el('p', { class:'muted small' }, [no?'Dette er den praktiske sjekken for lukket test med få aktører. Den er mindre streng enn full produksjon.':'This is the practical check for a closed test with a few kitchens. It is less strict than full production.'])
          ]),
          el('div', { class:'adminProdScore' }, [el('strong', {}, [pilotReadyCount + '/' + pilotTotalCount]), el('span', {}, [String(pilot.mode || 'pilot')])])
        ]),
        el('div', { class:'adminProdMiniList', style:'margin-bottom:10px' }, [
          el('div', { class:'adminProdMiniRow' }, [el('span', {}, [no?'Aktører totalt':'Total kitchens']), el('span', { class:'tag' }, [String(pilotListings.total || 0)])]),
          el('div', { class:'adminProdMiniRow' }, [el('span', {}, [no?'Synlige på Explore':'Visible on Explore']), el('span', { class:'tag ' + ((pilotListings.public||0) ? 'tag-ok' : 'tag-warn') }, [String(pilotListings.public || 0)])])
        ]),
        el('div', { class:'adminProdChecks' }, pilotChecks.length ? pilotChecks.map(checkRow) : [el('div', { class:'muted' }, [no?'Ingen pilotdata lastet ennå.':'No pilot data loaded yet.'])])
      ]),
      el('div', { class:'adminProdGrid' }, [
        el('section', { class:'adminProdCard' }, [
          el('h3', {}, [no?'Miljø og secrets':'Environment and secrets']),
          el('div', { class:'adminProdChecks' }, checks.length ? checks.map(checkRow) : [el('div', { class:'muted' }, [no?'Ingen sjekkdata lastet ennå.':'No check data loaded yet.'])])
        ]),
        el('section', { class:'adminProdCard' }, [
          el('h3', {}, ['Stripe Price IDs']),
          el('div', { class:'adminProdMiniList' }, Object.keys(priceIds).length ? Object.keys(priceIds).sort().map(k=>el('div', { class:'adminProdMiniRow' }, [el('span', {}, [k.replaceAll('_',' ')]), el('span', { class:'tag ' + (priceIds[k] ? 'tag-ok' : 'tag-warn') }, [priceIds[k] ? 'set' : 'missing'])])) : [el('div', { class:'muted' }, ['—'])])
        ]),
        el('section', { class:'adminProdCard' }, [
          el('h3', {}, [no?'Webhook-test':'Webhook test']),
          el('div', { class:'adminProdMiniList' }, [
            el('div', { class:'adminProdMiniRow' }, [el('span', {}, [no?'Webhook events i logg':'Webhook events in log']), el('span', { class:'tag' }, [String(stripeEvents.length)])]),
            el('div', { class:'adminProdMiniRow' }, [el('span', {}, [no?'Feil-events':'Error events']), el('span', { class:'tag ' + (recentErrors ? 'tag-warn' : 'tag-ok') }, [String(recentErrors)])])
          ]),
          button(no?'Åpne Billing / Stripe':'Open Billing / Stripe', { variant:'outline', onclick:()=>{ state.admin.tab='billing'; render(); } })
        ]),
        el('section', { class:'adminProdCard' }, [
          el('h3', {}, [no?'E-posttest':'Email test']),
          el('p', { class:'muted small' }, [no?'Sett provider i Innstillinger og test varselkøen.':'Set provider in Settings and test the notification queue.']),
          el('div', { class:'row', style:'gap:8px; flex-wrap:wrap' }, [
            button(no?'Åpne varsler':'Open notifications', { variant:'primary', onclick:()=>{ state.admin.tab='notifications'; render(); } }),
            button(no?'Åpne innstillinger':'Open settings', { variant:'outline', onclick:()=>{ state.admin.tab='settings'; render(); } })
          ])
        ])
      ]),
      el('section', { class:'adminProdCard adminProdActionCard' }, [
        el('h3', {}, [no?'Neste tiltak':'Next actions']),
        el('div', { class:'adminProdActionList' }, actionItems.map((a,idx)=>el('div', { class:'adminProdActionItem' }, [
          el('strong', {}, [String(idx+1) + '. ' + a[0]]),
          el('p', {}, [a[1]]),
          button(no?'Åpne relevant fane':'Open relevant tab', { variant:'outline', onclick:()=>{ state.admin.tab=a[2]; render(); } })
        ])))
      ]),
      el('section', { class:'adminProdCard adminProdReviewCard' }, [
        el('div', { class:'adminProdLaunchHead' }, [
          el('div', {}, [el('h3', {}, [no?'Produksjonsrapport':'Production report']), el('p', { class:'muted small' }, [no?'Kopier status eller env-mal for manuell kontroll.':'Copy status or env template for manual control.'])]),
          el('div', { class:'row', style:'gap:8px; flex-wrap:wrap' }, [
            button(no?'Kopier status':'Copy status', { variant:'outline', onclick:()=>copyText(report, no?'Status kopiert.':'Status copied.', no?'Kopier status manuelt:':'Copy status manually:') }),
            button(no?'Kopier env-mal':'Copy env template', { variant:'outline', onclick:()=>copyText(envTemplate, no?'Env-mal kopiert.':'Env template copied.', no?'Kopier env-mal manuelt:':'Copy env template manually:') })
          ])
        ]),
        el('textarea', { class:'input adminProdNoteInput', rows:'3', placeholder:no?'Notat':'Note', value: state.admin.productionNote || '', oninput:(e)=>{ state.admin.productionNote = e.target.value; } })
      ]),
      el('section', { class:'adminProdCard adminProdActivityCard' }, [
        el('h3', {}, [no?'Siste produksjonsrelaterte hendelser':'Recent production-related events']),
        el('div', { class:'adminProdActivityList' }, (state.admin.activity || []).filter(r=>r && ['production_review','settings_update','billing_visibility_sync','discount_code_create','discount_code_update','discount_code_toggle'].includes(String(r.action||''))).slice(0,6).map(r=>el('div', { class:'adminProdActivityItem' }, [
          el('strong', {}, [String(r.action || '')]),
          el('span', { class:'muted tiny' }, [String(r.created_at || '').replace('T',' ').slice(0,19)]),
          el('span', { class:'muted small' }, [r.title || r.listing_name || r.customer_no || 'System'])
        ])))
      ]),
      el('div', { class:'adminProdNote' }, [no?'Ikke legg secrets i kode eller zip. Bruk miljøvariabler/server-secrets.':'Do not put secrets in code or zip. Use environment variables/server secrets.'])
    ]);
  }

