  async function createAdminAnnouncement(){
    const f = state.admin.announcementForm || {};
    if (!String(f.title||'').trim() || !String(f.body||'').trim()){
      alert(state.lang==='no'?'Tittel og meldingstekst må fylles ut.':'Title and message text are required.');
      return;
    }
    try{
      const key = encodeURIComponent(state.admin.key || '');
      await apiJson('POST', adminUrl('/api/admin/announcements'), f);
      state.admin.announcementForm = { title:'', body:'', cta:'', target_tab:'dashboard', target_plan:'all', target_listing_id:'', priority:'normal', status:'active', active_from:'', active_until:'', max_views:1 };
      await refresh();
    }catch(e){
      alert('Announcement failed: ' + (e.message||e));
    }
  }

  async function setAdminAnnouncementStatus(id, status){
    try{
      const key = encodeURIComponent(state.admin.key || '');
      await apiJson('POST', adminUrl(`/api/admin/announcements/${id}/status`), { status });
      await refresh();
    }catch(e){
      alert('Announcement update failed: ' + (e.message||e));
    }
  }

