// --- Map view (Leaflet) ---
function _hash32(str){
  // Simple deterministic hash (good enough for stable jitter)
  let h = 2166136261;
  for (let i=0; i<str.length; i++){
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return (h >>> 0);
}

function approxLatLng(item){
  const lat = (item && item.lat!=null) ? Number(item.lat) : null;
  const lng = (item && item.lng!=null) ? Number(item.lng) : null;
  if (lat==null || lng==null || Number.isNaN(lat) || Number.isNaN(lng)) return null;

  // Coordinates from API are already rounded (privacy-friendly). Add a tiny deterministic jitter
  // so multiple cooks in the same postcode don't stack perfectly.
  const slug = String(item.slug||'');
  const h = _hash32(slug);
  const j1 = ((h % 1000) / 1000) - 0.5;           // [-0.5..0.5)
  const j2 = (((h/1000|0) % 1000) / 1000) - 0.5;  // [-0.5..0.5)
  const jitter = 0.004; // ~ up to ~400m
  return [lat + j1*jitter, lng + j2*jitter];
}

function destroyLeaflet(){
  try{
    const m = state.ui._leaflet?.map;
    if (m){
      m.remove();
    }
  }catch(e){}
  state.ui._leaflet = { map:null, layer:null, cluster:false };
}

function initLeafletPortal(){
  // Inline portal map (List/Map toggle)
  const elMap = document.getElementById('leafletPortalMap');
  if (!elMap) return;

  // Leaflet loaded?
  if (!window.L){
    return; // UI already shows fallback text.
  }

  // (Re)create map every render while map view is active (render rebuilds DOM).
  destroyLeaflet();

  // Airbnb-ish behavior:
  // - If the user searched a location, zoom in there.
  // - Otherwise, start at a sensible Scandinavia-ish zoom (not fit-to-all).
  let center = [59.9139, 10.7522]; // Oslo
  let zoom = 5;
  if (state.ui.near && state.ui.near.active && state.ui.near.lat!=null && state.ui.near.lng!=null){
    center = [Number(state.ui.near.lat), Number(state.ui.near.lng)];
    zoom = 11;
  }

  const map = window.L.map(elMap, { zoomControl:true }).setView(center, zoom);
  window.L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    maxZoom: 19,
    attribution: '&copy; OpenStreetMap'
  }).addTo(map);

  // Airbnb-style map clusters with counts (if MarkerCluster plugin is available).
  let layer = null;
  try{
    if (window.L && typeof window.L.markerClusterGroup === 'function'){
      layer = window.L.markerClusterGroup({
        showCoverageOnHover: false,
        spiderfyOnMaxZoom: true,
        maxClusterRadius: 46,
      }).addTo(map);
      state.ui._leaflet.cluster = true;
    }
  }catch(e){}
  if (!layer){
    layer = window.L.layerGroup().addTo(map);
    state.ui._leaflet.cluster = false;
  }
  state.ui._leaflet.map = map;
  state.ui._leaflet.layer = layer;

  updateLeafletMarkers();

  // Make sure Leaflet sizes correctly inside the layout.
  setTimeout(()=>{ try{ map.invalidateSize(); }catch(e){} }, 60);
}

function updateLeafletMarkers(){
  const map = state.ui._leaflet?.map;
  const layer = state.ui._leaflet?.layer;
  if (!map || !layer || !window.L) return;

  layer.clearLayers();

  // Airbnb-style map: show all live kitchens (mapListings) by default.
  // Fallback to current results if map listings aren't loaded.
  const src = (state.mapListings && state.mapListings.length) ? state.mapListings : (state.listings||[]);
  const items = src.filter(x => x && x.lat!=null && x.lng!=null);
  if (!items.length){
    return;
  }

  const bounds = [];

  for (const it of items){
    const pos = approxLatLng(it);
    if (!pos) continue;
    bounds.push(pos);
    const marker = window.L.marker(pos).addTo(layer);
    const title = (it.name||'');
    const sub = `${it.area||''}${it.city?(' · '+it.city):''}`.trim();
    marker.bindPopup(`<div style="font-family:Inter,system-ui; max-width:220px">
      <div style="font-weight:700; margin-bottom:4px">${escapeHtml(title)}</div>
      <div style="color:#6b7280; font-size:13px; margin-bottom:10px">${escapeHtml(sub)}</div>
      <button data-slug="${escapeHtml(String(it.slug||''))}" class="btn btn-view-menu small">${state.lang==='no'?'Se meny':'View menu'}</button>
    </div>`);
    marker.on('popupopen', (e)=>{
      const btn = e.popup && e.popup._contentNode ? e.popup._contentNode.querySelector('button[data-slug]') : null;
      if (btn){
        btn.onclick = ()=>{ destroyLeaflet(); navigate(`/c/${it.slug}`); };
      }
    });
  }

  // If the user searched a location (near-mode), fit to the *current results* bounds
  // (not all map pins), which is closer to Airbnb behavior.
  if (state.ui.near && state.ui.near.active){
    const nearItems = (state.listings||[]).filter(x => x && x.lat!=null && x.lng!=null);
    const nearBounds = [];
    for (const it of nearItems){
      const p = approxLatLng(it);
      if (p) nearBounds.push(p);
    }
    if (nearBounds.length>=2){
      try{ map.fitBounds(nearBounds, { padding:[18,18] }); }catch(e){}
    } else if (nearBounds.length===1){
      try{ map.setView(nearBounds[0], 12); }catch(e){}
    }
  }
}

function mapFab(){
  // Show only on portal route
  if (!location.pathname.endsWith('/') && location.pathname !== '/' && !location.pathname.startsWith('/index')) {
    // SPA routes are handled by hash-less paths; only show on portal root
  }
  const path = location.pathname;
  const isPortal = path === '/' || path === '' || path.endsWith('/index.html');
  if (!isPortal) return null;

  return el('div', { class:'fab' }, [
    el('button', { type:'button', onclick: ()=>{ state.ui.mapOpen=true; render(); } }, [
      el('span', {}, ['🗺️']),
      t('ui.map')
    ])
  ]);
}

function mapOverlay(){
  if (!state.ui.mapOpen) return null;
  return el('div', { class:'overlay', onclick:(e)=>{ if(e.target.classList.contains('overlay')){ state.ui.mapOpen=false; destroyLeaflet(); render(); } } }, [
    el('div', { class:'modal' }, [
      el('div', { class:'modal-head' }, [
        el('div', { class:'title' }, [state.lang==='no' ? 'Kartvisning' : 'Map view']),
        el('button', { class:'btn small', type:'button', onclick: ()=>{ state.ui.mapOpen=false; destroyLeaflet(); render(); } }, [state.lang==='no' ? 'Lukk' : 'Close'])
      ]),
      el('div', { class:'modal-body' }, [
        (!window.L
          ? el('div', { class:'card' }, [
              el('p', { class:'muted' }, [state.lang==='no'
                ? 'Kart krever internett (Leaflet lastes fra CDN). Bruk listen inntil videre.'
                : 'Map requires internet (Leaflet loads from a CDN). Use the list for now.'
              ])
            ])
          : el('div', { class:'mapBox' }, [
              el('div', { id:'leafletMap' }, []),
            ])
        ),
        el('div', { class:'mapNote' }, [state.lang==='no'
          ? 'Pins viser omtrentlig plassering basert på postnummer/område (ikke nøyaktig adresse).'
          : 'Pins show approximate locations based on postcode/area (not exact address).'
        ])
      ]),
      el('div', { class:'modal-actions' }, [
        el('button', { class:'btn btn-outline', type:'button', onclick: ()=>{ destroyLeaflet(); initLeafletOverlay(); } }, [state.lang==='no' ? 'Oppdater kart' : 'Refresh map']),
        el('button', { class:'btn primary', type:'button', onclick: ()=>{ state.ui.mapOpen=false; destroyLeaflet(); render(); } }, [state.lang==='no' ? 'Lukk' : 'Close'])
      ])
    ])
  ]);
}

function render(){
  const root = document.getElementById('app');
  if (!root) return;

  try{
    // Build the full route in memory first, then replace the root in one operation.
    // This prevents stacked/duplicated page sections if a deploy/browser briefly runs
    // overlapping renders while scrolling or switching owner tabs.
    const _parts = location.pathname.split('/').filter(Boolean);
    const showOrderUi = (_parts[0] === 'c');

    const main = el('div', { class:'main' }, [
      topBar(),
      el('div', { class:'content' }, [routeView()]),
      footer(),
      (showOrderUi && state.currentListing ? orderBar(state.currentListing) : null),
      (showOrderUi && state.currentListing ? orderDrawer(state.currentListing) : null),
    ].filter(Boolean));

    const topBtn = el('button', { class:'toTopBtn' + (state.ui.showTop ? '' : ' is-hidden'), type:'button', title:(state.lang==='no'?'Til toppen':'Top'), 'aria-hidden': state.ui.showTop ? 'false' : 'true', onclick: ()=>scrollToTop() }, ['↑']);
    root.replaceChildren(main, topBtn);

    // After DOM is in place, initialize the portal map if the user is on Map view.
    const path = location.pathname;
    const isPortal = (path === '/' || path === '' || path.endsWith('/index.html'));
    if (isPortal && state.ui.portalView === 'map'){
      setTimeout(()=>{ try{ initLeafletPortal(); }catch(e){ console.error('Map init error', e); } }, 0);
    } else {
      if (state.ui._leaflet && state.ui._leaflet.map){
        destroyLeaflet();
      }
    }
  }catch(err){
    console.error('Render error:', err);

    root.innerHTML = '';
    const msg = (state.lang==='no')
      ? 'Noe gikk galt i appen. Prøv å laste siden på nytt.'
      : 'Something went wrong in the app. Try reloading the page.';

    const card = el('div', { class:'container section' }, [
      el('div', { class:'card' }, [
        el('h2', { class:'h3' }, [state.lang==='no'?'Feil i appen':'App error']),
        el('p', { class:'muted' }, [msg]),
        button(state.lang==='no'?'Last på nytt':'Reload', { variant:'primary', onclick: ()=>location.reload() }),
        el('pre', { class:'pre', style:'margin-top:12px; white-space:pre-wrap; word-break:break-word;' }, [
          String((err && (err.stack || err.message)) || err)
        ]),
      ])
    ]);

    root.appendChild(card);
  }
}

async function boot(){
  if (window.__rm_boot_started){
    return;
  }
  window.__rm_boot_started = true;

  if (!window.__rm_err_handlers){
    window.__rm_err_handlers = true;
    window.addEventListener('error', (e)=>{ console.error('Global error:', e.error || e.message || e); });
    window.addEventListener('unhandledrejection', (e)=>{ console.error('Unhandled rejection:', e.reason || e); });
  }

  if (!window.__rm_pop_listener){
    window.__rm_pop_listener = true;
    window.addEventListener('popstate', onRoute);
  }

  // Render immediately. Do not wait for API calls or map/CDN resources before
  // showing the app shell. This prevents a blank page when SQLite is locked or
  // one endpoint is slow during local testing.
  onRoute();

  refreshAuth().then(()=>{ render(); }).catch(()=>{});

  if (!window.__rm_scroll_listener){
    window.__rm_scroll_listener = true;
    let ticking = false;
    window.addEventListener('scroll', ()=>{
      if (ticking) return;
      ticking = true;
      requestAnimationFrame(()=>{
        ticking = false;
        const show = (window.scrollY || 0) > 500;
        if (!!state.ui.showTop !== show){
          state.ui.showTop = show;
          try{
            const btn = document.querySelector('.toTopBtn');
            if (btn){
              btn.classList.toggle('is-hidden', !show);
              btn.setAttribute('aria-hidden', show ? 'false' : 'true');
            } else {
              render();
            }
          }catch(_){ }
        }
      });
    }, { passive:true });
  }

  try{
    await loadCuisines();
  }catch(e){
    console.error('loadCuisines failed', e);
    state.cuisines = state.cuisines || [];
  }

  try{
    const data = await apiGet('/api/listings', { timeoutMs: 8000 });
    state.listings = data.items || [];
  }catch(e){
    console.error('Initial listings load failed', e);
    state.ui.emptyNote = state.lang==='no'
      ? 'Kunne ikke laste kjøkken akkurat nå. API-et kan være opptatt. Prøv å laste siden på nytt.'
      : 'Could not load kitchens right now. The API may be busy. Try reloading.';
  }

  loadMapListings();

  // A default listing is only needed by the isolated /example route.
  // Do NOT load one for admin-view, owner dashboard, public kitchen, admin, login,
  // or portal routes: this asynchronous request can otherwise arrive after the
  // route-specific request and overwrite the kitchen that was explicitly selected.
  const path = location.pathname;
  const parts = path.split('/').filter(Boolean);
  const isExampleRoute = (parts[0] === 'example');
  if (isExampleRoute && state.listings.length > 0 && !state.currentListing){
    const exampleSlug = String(state.listings[0]?.slug || '').trim();
    if (exampleSlug){
      apiGet(`/api/listings/${encodeURIComponent(exampleSlug)}`, { timeoutMs: 8000 })
        .then(x=>{
          // Keep this response bound to /example in case the user navigated away.
          if (location.pathname !== '/example') return;
          state.currentListing = x;
          render();
        })
        .catch(e=>{ console.error('example listing load failed', e); });
    }
  }

  render();
}

boot().catch(err=>{
  console.error(err);
  document.getElementById('app').innerHTML = '<div style="padding:24px;font-family:Inter,system-ui">Failed to start. Check API is running.</div>';
});
